/* AUTO-GENERATED — Utah Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["UT"] = {"code":"UT","name":"Utah","agency":"Utah DLD","agencyShort":"DLD","handbook":"https://dld.utah.gov/cdl-info/","links":{},"en":[{"q":"What is the maximum legal width of a commercial vehicle and its load on Utah highways without a permit?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"answer":0,"explanation":"Utah limits vehicle width to 8 feet 6 inches (102 inches), measured outside-to-outside at the widest points, with or without a load. Source: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length page.","handbook":"","hbref":""},{"q":"What is the maximum legal height for a vehicle and load on Utah highways without an oversize permit?","options":["14 feet","13 feet 6 inches","15 feet","13 feet"],"answer":0,"explanation":"Utah's maximum legal height is 14 feet, measured from the level road surface to the top of the load or vehicle. Source: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length page.","handbook":"","hbref":""},{"q":"What is the maximum legal gross vehicle weight on Utah highways without an overweight permit?","options":["80,000 pounds","78,000 pounds","84,000 pounds","76,000 pounds"],"answer":0,"explanation":"Utah caps legal gross vehicle weight at 80,000 pounds, consistent with the federal limit, subject to axle and bridge-formula limits. Source: Utah Code 72-7-404; UDOT size/weight permitting.","handbook":"","hbref":""},{"q":"On Utah highways, what is the maximum legal load on a single axle without a permit?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"answer":0,"explanation":"Utah limits a single axle to 20,000 pounds. Source: Utah Code 72-7-404(1); Utah Admin. Code R909-2.","handbook":"","hbref":""},{"q":"On Utah highways, what is the maximum legal load on a tandem axle group without a permit?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"answer":0,"explanation":"Utah limits a tandem axle to 34,000 pounds. Source: Utah Code 72-7-404(1); UDOT size/weight permitting.","handbook":"","hbref":""},{"q":"What is the maximum legal length of a single (straight) motor vehicle on Utah highways?","options":["45 feet","40 feet","53 feet","48 feet"],"answer":0,"explanation":"A single motor vehicle in Utah may not exceed 45 feet in length, excluding overhangs. Source: Utah Admin. Code R909-2-4.","handbook":"","hbref":""},{"q":"What is the maximum legal length of a semitrailer operated in a tractor-semitrailer combination on Utah highways?","options":["53 feet","48 feet","57 feet","45 feet"],"answer":0,"explanation":"Utah allows a semitrailer up to 53 feet in length in a tractor-semitrailer combination. Source: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length.","handbook":"","hbref":""},{"q":"Under Utah law, how far may a load extend beyond the FRONT of the power unit before an oversize permit is required?","options":["3 feet","4 feet","5 feet","2 feet"],"answer":0,"explanation":"A vehicle may not carry a load extending more than 3 feet beyond the front of the power unit without a permit. Source: Utah Admin. Code R909-2-4 overhang provision.","handbook":"","hbref":""},{"q":"Under Utah law, how far may a load extend beyond the REAR of the bed or body before an oversize permit is required?","options":["6 feet","4 feet","8 feet","3 feet"],"answer":0,"explanation":"A load may not extend more than 6 feet beyond the rear of the bed or body without a permit. Source: Utah Admin. Code R909-2-4 overhang provision.","handbook":"","hbref":""},{"q":"What is the maximum combined trailer length for a double-trailer (twin-trailer) combination on Utah highways?","options":["61 feet","65 feet","53 feet","68 feet"],"answer":0,"explanation":"Utah allows a maximum of 61 feet of combined trailer length for double-trailer combinations. Source: Utah Admin. Code R909-2-4.","handbook":"","hbref":""},{"q":"Under Utah Code 72-7-404, what is the maximum allowable weight on any single WHEEL of a vehicle?","options":["10,500 pounds","8,000 pounds","12,000 pounds","9,000 pounds"],"answer":0,"explanation":"Utah prohibits operating a vehicle with a gross weight exceeding 10,500 pounds on one wheel. Source: Utah Code 72-7-404(1).","handbook":"","hbref":""},{"q":"Which formula does Utah use to determine the allowable gross weight on a group of consecutive axles?","options":["The federal bridge formula: W = 500[LN/(N-1) + 12N + 36]","Gross weight divided by the number of tires","20,000 pounds multiplied by the number of axles","The sum of axle ratings minus 10 percent"],"answer":0,"explanation":"Utah adopts the federal bridge formula W = 500[LN/(N-1) + 12N + 36], where W is gross weight, L is axle-group distance, and N is the number of axles. Source: Utah Code 72-7-404; UDOT online bridge calculator.","handbook":"","hbref":""},{"q":"In the Utah bridge formula W = 500[LN/(N-1) + 12N + 36], what does the variable 'L' represent?","options":["The distance in feet between the extremes of the axle group","The legal load limit per axle","The length of the trailer in feet","The number of loaded axles"],"answer":0,"explanation":"In the bridge formula, L is the distance in feet between the extreme axles of the group, N is the number of axles, and W is the resulting gross weight to the nearest 500 pounds. Source: Utah Code 72-7-404.","handbook":"","hbref":""},{"q":"Under Utah Code 72-7-404, two consecutive sets of tandem axles may each carry 34,000 pounds provided the distance between the first and last axles of the sets is at least how many feet?","options":["36 feet","30 feet","40 feet","44 feet"],"answer":0,"explanation":"Two consecutive sets of tandem axles may each carry 34,000 pounds if the overall distance between the first and last axles of the two sets is 36 feet or more. Source: Utah Code 72-7-404.","handbook":"","hbref":""},{"q":"When is an oversize/overweight permit required from UDOT in Utah?","options":["When the vehicle or load exceeds the legal size or weight limits in Utah Code 72-7-402 and 72-7-404","Only when crossing a state line into Utah","Only for loads over 200,000 pounds","Only when traveling on Interstate highways"],"answer":0,"explanation":"A UDOT permit is required whenever a vehicle or load exceeds the legal size and/or weight limits set in Utah Code 72-7-402 (size) and 72-7-404 (weight). Source: UDOT Oversize & Overweight Provisions; Utah Code 72-7-406.","handbook":"","hbref":""},{"q":"How are Utah oversize/overweight permits typically issued by UDOT?","options":["On a single-trip, semi-annual, or annual basis","Only as lifetime permits","Only as single-trip permits","Only as monthly permits"],"answer":0,"explanation":"UDOT issues oversize/overweight permits on a single-trip, semi-annual, or annual basis, obtained through the UDOT online permitting (MCS) system. Source: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2-8.","handbook":"","hbref":""},{"q":"An overweight DIVISIBLE load permit in Utah is generally available for a vehicle or combination registered for what gross weight range?","options":["78,001 to 80,000 pounds","60,000 to 70,000 pounds","80,001 to 90,000 pounds","70,000 to 78,000 pounds"],"answer":0,"explanation":"Utah's overweight divisible load permit applies to vehicles or combinations properly registered for 78,001 to 80,000 pounds and must still meet the bridge formula and legal axle limits. Source: Utah Admin. Code R909-2-21; UDOT Overweight Divisible Load Provisions.","handbook":"","hbref":""},{"q":"For Utah hay-truck operations, two rolls or bales of hay may be hauled side by side under a non-divisible oversize permit only if their combined width does not exceed what?","options":["10 feet","8 feet 6 inches","12 feet","14 feet"],"answer":0,"explanation":"Utah allows hay-truck combinations to carry two rolls or bales side by side when their combined width is 10 feet or less and a valid non-divisible oversize permit is held. Source: UDOT/Utah Admin. Code R909-2 agricultural (hay truck) provisions.","handbook":"","hbref":""},{"q":"On a typical Utah highway that is NOT a divided/Interstate route, at what width does an oversize load generally require a pilot/escort vehicle?","options":["More than 12 feet","More than 8 feet 6 inches","More than 14 feet","More than 16 feet"],"answer":0,"explanation":"On two-lane (non-divided) Utah highways an escort is generally required when load width exceeds 12 feet; on divided/Interstate highways the threshold is greater than 14 feet. Source: UDOT/Utah Admin. Code R909-2 escort provisions.","handbook":"","hbref":""},{"q":"Under Utah's non-divisible overweight permit provisions, up to what maximum single-axle weight may UDOT authorize for a non-divisible load?","options":["29,000 pounds","24,000 pounds","34,000 pounds","20,000 pounds"],"answer":0,"explanation":"UDOT may issue overweight permits for non-divisible loads up to 29,000 pounds on a single axle, 50,000 pounds on a tandem, and a permitted GVW up to 125,000 pounds. Source: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2.","handbook":"","hbref":""},{"q":"In Utah, which CDL class is required to operate a combination vehicle with a Gross Combination Weight Rating of 26,001 pounds or more, where the unit being towed is rated over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Utah issues a Class A CDL for combination vehicles with a GCWR of 26,001 lbs or more when the towed unit exceeds 10,000 lbs GVWR (e.g., a tractor-trailer). Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info) and Utah CDL Handbook.","handbook":"","hbref":""},{"q":"A Utah driver operates a single vehicle (such as a large dump truck or bus) with a Gross Vehicle Weight Rating of 26,001 pounds or more and no towed unit. Which CDL class does this require?","options":["Class C","Class B","Class A","Class E"],"answer":1,"explanation":"A Utah Class B CDL covers a single vehicle with a GVWR of 26,001 lbs or more that has no towed unit (or tows a unit 10,000 lbs or less). Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Under Utah rules, a Class C CDL applies to a vehicle with a GVWR below 26,001 pounds when it is designed to transport at least how many passengers, including the driver?","options":["10 passengers","12 passengers","16 passengers","24 passengers"],"answer":2,"explanation":"Utah defines Class C as a vehicle under 26,001 lbs GVWR that carries 16 or more passengers including the driver, or that is placarded for hazardous materials. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Utah CDL for intrastate operation (driving only within Utah)?","options":["16 years old","18 years old","19 years old","21 years old"],"answer":1,"explanation":"Utah allows a CDL at 18 for intrastate driving only. Drivers under 21 are restricted to operation within Utah. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"What is the minimum age required to hold a Utah CDL valid for interstate operation (driving across state lines)?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Federal rules adopted by Utah require a driver to be at least 21 to operate a commercial motor vehicle in interstate commerce. Drivers 18-20 are limited to intrastate operation. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"A 19-year-old Utah CDL holder carries a K-restriction. Which of the following endorsements is this driver ELIGIBLE to obtain?","options":["Hazardous Materials (H)","Passenger (P)","School Bus (S)","Tanker (N)"],"answer":3,"explanation":"Drivers under 21 in Utah are restricted to intrastate operation and are NOT eligible for the H (hazmat), P (passenger), or S (school bus) endorsements. The N (tanker) endorsement is not on that prohibited list. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Which endorsement does a Utah driver need to haul hazardous materials in quantities that require placards?","options":["N endorsement","T endorsement","H endorsement","X endorsement"],"answer":2,"explanation":"The H (Hazardous Materials) endorsement is required to transport hazmat in placardable amounts. It also requires a TSA security threat assessment background check. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Before Utah will issue a Hazardous Materials (H) endorsement, the applicant must clear which additional screening?","options":["A federal TSA security threat assessment background check","A state-administered polygraph examination","A vision test by an ophthalmologist","An employer-sponsored drug rehabilitation course"],"answer":0,"explanation":"The H endorsement requires passing a TSA (Transportation Security Administration) security threat assessment / background check under federal law, in addition to the hazmat knowledge test. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info); 49 CFR 1572.","handbook":"","hbref":""},{"q":"A Utah driver wants to pull double and triple trailers. Which endorsement is required, and on which CDL class can it be carried?","options":["T endorsement, available only on a Class A CDL","N endorsement, available on Class A or B","T endorsement, available only on a Class B CDL","P endorsement, available on any class"],"answer":0,"explanation":"The T (Doubles/Triples) endorsement allows pulling more than one trailer and can only be added to a Class A CDL. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info) and Utah CDL Handbook.","handbook":"","hbref":""},{"q":"Which endorsement does a Utah driver need to operate a tank vehicle used to haul liquids or gases?","options":["P endorsement","N endorsement","H endorsement","T endorsement"],"answer":1,"explanation":"The N (Tanker) endorsement is required for vehicles transporting liquids/gases in a tank with an individual rated capacity of 119 gallons or more and an aggregate rated capacity over 1,000 gallons. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Which endorsement is required before a Utah driver can obtain the School Bus (S) endorsement?","options":["Hazmat (H) endorsement","Tanker (N) endorsement","Passenger (P) endorsement","Doubles/Triples (T) endorsement"],"answer":2,"explanation":"In Utah the School Bus (S) endorsement is added on top of the Passenger (P) endorsement; an applicant must qualify for P (knowledge and skills) and then pass the additional S knowledge and skills tests. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Which two endorsements require a Utah applicant to pass a driving SKILLS test in addition to a written knowledge test?","options":["H (Hazmat) and N (Tanker)","P (Passenger) and S (School Bus)","T (Doubles/Triples) and N (Tanker)","H (Hazmat) and T (Doubles/Triples)"],"answer":1,"explanation":"In Utah the P (Passenger) and S (School Bus) endorsements each require a driving skills test in the appropriate vehicle, while H, N, and T require only a knowledge test. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Under federal rules adopted by Utah, how long must a driver hold a Commercial Learner Permit (CLP) before being allowed to take the CDL driving skills test?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"An applicant must hold the CLP for at least 14 days before taking the CDL skills test. This is an FMCSA requirement applied by the Utah DLD. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is a Utah Commercial Learner Permit (CLP) valid from its date of issuance?","options":["90 days","180 days","1 year","2 years"],"answer":1,"explanation":"A Utah CLP is valid for 180 days (about 6 months). It may be renewed once within a two-year period. Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test).","handbook":"","hbref":""},{"q":"What minimum score must an applicant achieve to pass a Utah CDL written knowledge test (general knowledge or an endorsement test)?","options":["70%","75%","80%","90%"],"answer":2,"explanation":"Utah requires a score of 80% to pass any CDL written knowledge test. Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test).","handbook":"","hbref":""},{"q":"Which knowledge test must a Utah applicant pass FIRST in order to be issued a Commercial Learner Permit?","options":["The 50-question general knowledge test","The 25-question air brakes test","The 20-question combination vehicles test","The 30-question hazmat test"],"answer":0,"explanation":"Passing the 50-question general knowledge test (at 80%) results in issuance of a CLP, which is valid for 180 days. Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test).","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) required for first-time Utah Class A or Class B applicants must be completed through a provider that is:","options":["Approved by the local school district","Listed on the FMCSA Training Provider Registry","Certified by the Utah State Tax Commission","Accredited by the U.S. Department of Education"],"answer":1,"explanation":"ELDT must be completed through a provider listed on the FMCSA Training Provider Registry (TPR) before the skills test. ELDT applies to first-time Class A/B applicants, Class B-to-A upgrades, and first-time H, P, and S endorsements. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info); 49 CFR Part 380.","handbook":"","hbref":""},{"q":"For which of the following does Utah NOT require Entry-Level Driver Training (ELDT)?","options":["A first-time Class A CDL applicant","A first-time Hazmat (H) endorsement applicant","Adding a Tanker (N) endorsement","A first-time School Bus (S) endorsement applicant"],"answer":2,"explanation":"Federal ELDT applies to first-time Class A/B CDLs, Class B-to-A upgrades, and first-time H, P, and S endorsements. The N (tanker) and T (doubles/triples) endorsements are not subject to ELDT. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info); 49 CFR Part 380.","handbook":"","hbref":""},{"q":"When applying for a Utah CDL, which combination of documents must an applicant provide to the Driver License Division?","options":["Proof of identity and lawful presence, full Social Security number, and two documents proving Utah residence","A passport only","A high school diploma and one utility bill","A vehicle registration and proof of insurance only"],"answer":0,"explanation":"Utah DLD requires proof of identity/lawful presence, the applicant's full Social Security number, and two documents proving Utah residence (plus a valid medical certificate where required). Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"A Utah CDL applicant who drives only within Utah and hauls non-exempt cargo, and who holds a valid DOT medical card, should self-certify under which category?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"answer":2,"explanation":"Utah uses four self-certification categories. A driver operating only within Utah in non-excepted commerce certifies as Non-Excepted Intrastate. Interstate categories apply to across-state-line driving; excepted categories apply to specific federally exempt operations. Source: Utah DLD CDL Self-Certification page (dld.utah.gov/cdl-self-certification).","handbook":"","hbref":""},{"q":"In Utah, what is the blood/breath alcohol concentration (BAC) at or above which a person is prohibited from operating a commercial motor vehicle (CMV)?","options":["0.04","0.08","0.02","0.05"],"answer":0,"explanation":"Utah Code 53-3-414(1)(a)(ii) makes it a major offense to drive a CMV with an alcohol concentration of 0.04 grams or more. The 0.08 limit applies only to non-commercial driving. Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"A Utah CDL driver is convicted of a FIRST major offense (such as driving a CMV with a BAC of 0.04 or more) and was NOT hauling placarded hazardous materials. What is the minimum CDL disqualification period?","options":["1 year","60 days","3 years","6 months"],"answer":0,"explanation":"Under Utah Code 53-3-414(1)(a), a first major offense results in disqualification for not less than one year. Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"If a Utah CDL driver commits a first major offense (such as a DUI) WHILE transporting a hazardous material that must be placarded, the minimum disqualification increases to what period?","options":["3 years","1 year","2 years","Lifetime"],"answer":0,"explanation":"Utah Code 53-3-414(2) raises the minimum disqualification for a first major offense to not less than three years when the offense occurs while transporting placarded hazardous materials. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"What happens to a Utah CDL holder who is convicted of a SECOND major offense arising from a separate incident?","options":["Disqualified for life from driving a CMV","Disqualified for 3 years","Disqualified for 1 year","Disqualified for 120 days"],"answer":0,"explanation":"Utah Code 53-3-414(3)(a) provides that two or more major offenses from separate incidents result in lifetime disqualification from driving a CMV. Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"Under Utah's implied-consent rules, what is the consequence for a CDL driver who refuses to submit to a chemical test for alcohol or drug concentration?","options":["It is treated as a major offense, disqualifying the CDL for at least 1 year","A warning only on the first refusal","A 60-day disqualification","A $500 fine with no disqualification"],"answer":0,"explanation":"Utah Code 53-3-414(1)(a)(vi) lists refusal to submit to a chemical test as a major offense, carrying the same minimum 1-year disqualification (3 years if placarded hazmat). Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"How many SERIOUS traffic violations within a three-year period trigger a 60-day CDL disqualification in Utah?","options":["2","3","1","4"],"answer":0,"explanation":"Utah Code 53-3-414(6)(a)(i) requires a disqualification of not less than 60 days for two serious traffic violations occurring within three years. Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"In Utah, a CDL driver convicted of THREE or more serious traffic violations within a three-year period is disqualified for at least how long?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Utah Code 53-3-414(6)(a)(ii) imposes a disqualification of not less than 120 days for three or more serious traffic violations within three years. Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Utah CDL driver?","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A parking violation","Driving 3 mph below the limit"],"answer":0,"explanation":"Per the Utah CDL Manual and Utah's violation (ACD) code list, speeding 15 mph or more over the limit is a serious traffic violation. Lesser speeding and parking are not serious. Source: Utah CDL Manual; 49 CFR 383.51 applied in Utah.","handbook":"","hbref":""},{"q":"Which act counts as a serious traffic violation that can contribute to a Utah CDL disqualification?","options":["Texting or using a hand-held phone while driving a CMV","Using a hands-free phone while driving a CMV","Eating while driving a CMV","Listening to the radio while driving a CMV"],"answer":0,"explanation":"Utah follows the federal serious-violation list (49 CFR 383.51): texting or using a hand-held mobile phone while operating a CMV is a serious traffic violation. Hands-free use is not. Source: Utah CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Utah CDL driver is convicted of a FIRST violation of an out-of-service (OOS) order while driving a CMV (no hazmat, not a large bus). What is the minimum disqualification under Utah law?","options":["180 days","90 days","60 days","1 year"],"answer":0,"explanation":"Utah Code 53-3-414(7)(a)(i) sets the minimum disqualification for a first out-of-service order violation at 180 days, which exceeds the federal 90-day floor. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"Besides disqualification, what minimum CIVIL PENALTY does Utah law impose on a CDL driver convicted of a FIRST out-of-service order violation?","options":["$2,500","$1,000","$5,000","$500"],"answer":0,"explanation":"Utah Code 53-3-414(7)(b) requires a civil penalty of not less than $2,500 for a first out-of-service order violation. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"Under Utah law, the minimum civil penalty for a CDL driver's SECOND or subsequent out-of-service order violation is at least:","options":["$5,000","$2,500","$3,500","$10,000"],"answer":0,"explanation":"Utah Code 53-3-414(7)(c) sets the civil penalty at not less than $5,000 for a second or subsequent out-of-service order violation. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"A Utah CDL driver is convicted of a SECOND out-of-service order violation, in a separate incident, within a 10-year period. What is the minimum disqualification?","options":["2 years","1 year","180 days","3 years"],"answer":0,"explanation":"Utah Code 53-3-414(7)(a)(ii) requires a disqualification of not less than two years for a second OOS-order violation in separate incidents within any 10-year period. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"Under Utah law, a THIRD or more out-of-service order violation in separate incidents within a 10-year period results in a disqualification of:","options":["3 to 5 years","1 to 2 years","180 days to 1 year","10 years"],"answer":0,"explanation":"Utah Code 53-3-414(7)(a)(iii) requires a disqualification of not less than three years but not more than five years for three or more OOS-order violations within any 10-year period. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"A Utah CDL driver is convicted of a FIRST railroad-highway grade crossing violation while driving a CMV. What is the minimum disqualification?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Utah Code 53-3-414(9)(a) imposes a disqualification of not less than 60 days for a first railroad-highway grade crossing violation. Source: Utah Code 53-3-414; Utah CDL Manual.","handbook":"","hbref":""},{"q":"For a SECOND railroad-highway grade crossing violation within a three-year period (separate incidents), a Utah CDL driver is disqualified for at least:","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Utah Code 53-3-414(9)(b) requires a disqualification of not less than 120 days for a second grade-crossing violation within any three-year period. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"A Utah CDL driver convicted of a THIRD or more railroad-highway grade crossing violation within a three-year period (separate incidents) is disqualified for at least:","options":["1 year","120 days","60 days","3 years"],"answer":0,"explanation":"Utah Code 53-3-414(9)(c) requires a disqualification of not less than one year for three or more grade-crossing violations within any three-year period. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"If a CMV driver who is required to hold a CDL tests positive for ANY detectable amount of alcohol below 0.04, what action is taken?","options":["Placed out of service for 24 hours","Immediate 1-year CDL disqualification","60-day CDL disqualification","No action since it is under 0.04"],"answer":0,"explanation":"Utah follows the federal rule (49 CFR 392.5): a CMV driver with any detectable alcohol under 0.04 must be placed out of service for 24 hours. A reading of 0.04 or higher is a major offense. Source: Utah CDL Manual; 49 CFR 392.5.","handbook":"","hbref":""},{"q":"In Utah, what is the minimum CDL disqualification for using a CMV in the commission of a felony involving manufacturing, distributing, or dispensing a controlled substance?","options":["Lifetime, with no reinstatement available","1 year","3 years","10 years"],"answer":0,"explanation":"Utah Code 53-3-414(5) and 414(3)(b) impose lifetime disqualification with NO eligibility for reinstatement when a CMV is used in a felony involving controlled-substance manufacturing, distribution, or dispensing. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"A Utah CDL holder receives a lifetime disqualification that is eligible for reinstatement. What is the minimum disqualification period that must be served before applying to reinstate the CDL?","options":["10 years","5 years","3 years","15 years"],"answer":0,"explanation":"Utah Code 53-3-414(4)(a) allows a driver to apply for reinstatement only after serving a minimum disqualification of 10 years and completing an approved rehabilitation program meeting 49 CFR 383.51. Source: Utah Code 53-3-414.","handbook":"","hbref":""},{"q":"Under Utah's Move Over law, when a commercial driver approaches a stationary tow truck or highway maintenance vehicle displaying flashing amber lights on a multi-lane highway, what must the driver do?","options":["Reduce speed and, if practical and safe, change into a lane not adjacent to the stopped vehicle","Maintain speed but sound the horn to warn the workers","Come to a complete stop until the stopped vehicle leaves the shoulder","Nothing, because the law only applies to police and ambulances"],"answer":0,"explanation":"Utah Code 41-6a-904 (the Move Over law) requires a driver approaching a stationary authorized emergency vehicle, tow/wrecker truck, or roadway maintenance vehicle with flashing lights to reduce speed and, if traveling in an adjacent lane and it is practical with due regard to safety, move into a lane not next to the stopped vehicle. Source: Utah Code 41-6a-904.","handbook":"","hbref":""},{"q":"Utah's Move Over law (41-6a-904) specifies which numeric speed a driver must slow to when passing a stationary emergency or maintenance vehicle?","options":["No fixed number is set; the law requires the driver to 'reduce speed'","Exactly 20 mph below the posted limit","A flat 25 mph regardless of the posted limit","Exactly 10 mph in all cases"],"answer":0,"explanation":"Utah Code 41-6a-904 does not name a fixed mph figure. It requires the driver to reduce speed, provide as much space as practical, and change lanes away from the stopped vehicle when practical. Source: Utah Code 41-6a-904.","handbook":"","hbref":""},{"q":"On a Utah highway with more than one lane in the same direction, a CMV traveling in the left general-purpose lane is overtaken by a faster vehicle behind it. What does Utah law require?","options":["Move safely to a lane on the right and not impede the free flow of traffic in the left lane","Hold the lane because the truck is already at the posted speed limit","Speed up to at least 5 mph over the limit to clear the lane","Move left onto the median shoulder to let the vehicle pass"],"answer":0,"explanation":"Utah Code 41-6a-704 provides that a driver in the left general-purpose lane who is overtaken by another vehicle must yield by moving safely to a lane on the right and may not impede the movement or free flow of traffic in the left lane; violation is an infraction. Source: Utah Code 41-6a-704.","handbook":"","hbref":""},{"q":"What is the maximum posted speed limit a commercial driver may legally encounter on a rural Utah interstate?","options":["80 mph where posted","65 mph statewide cap for all trucks","70 mph maximum for any vehicle","85 mph where posted"],"answer":0,"explanation":"Utah posts 80 mph on designated rural interstate segments (75 mph is the common default), the highest in the state. Source: Utah Code 41-6a-601/604 and Utah DOT posted limits.","handbook":"","hbref":""},{"q":"How does Utah treat truck speed limits compared with passenger-car limits on the interstate?","options":["Trucks follow the same posted limit; Utah sets no separate lower statewide truck speed limit","Trucks are capped at 55 mph statewide regardless of the posted limit","Trucks must always drive 15 mph below the posted car limit","Trucks are limited to 60 mph on all interstates"],"answer":0,"explanation":"Unlike split-limit states such as California, Utah does not impose a separate lower statewide speed limit for trucks; CMVs obey the same posted limit (up to 80 mph). Only localized signed truck-speed reductions on certain grades apply. Source: Utah Code Title 41 Chapter 6a Part 6 and Utah DOT.","handbook":"","hbref":""},{"q":"At a railroad grade crossing in Utah, a driver of a bus carrying passengers or a placarded HazMat vehicle must stop the vehicle within what distance of the nearest rail?","options":["Within 50 feet but not less than 15 feet from the nearest rail","Within 25 feet but not less than 5 feet from the nearest rail","Within 100 feet but not less than 50 feet from the nearest rail","Within 75 feet but not less than 25 feet from the nearest rail"],"answer":0,"explanation":"Buses with passengers and placarded HazMat vehicles must stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen before crossing. Source: Utah CDL Handbook (DLD) and 49 CFR 392.10 as applied in Utah.","handbook":"","hbref":""},{"q":"Which of these Utah commercial vehicles is required to STOP at every railroad crossing (where not exempt)?","options":["A bus carrying passengers and a vehicle displaying HazMat placards","Any tractor-trailer hauling general freight","Only vehicles weighing over 26,001 pounds","Only triple-trailer combinations"],"answer":0,"explanation":"Utah follows the federal rule: only buses carrying passengers and placarded HazMat vehicles must stop at railroad crossings; most other CMVs are not required to stop. Source: Utah CDL Handbook (DLD); 49 CFR 392.10.","handbook":"","hbref":""},{"q":"When stopping for a railroad crossing in a placarded HazMat vehicle in Utah, before any part of the vehicle is on the tracks the driver should NOT do which of the following?","options":["Change gears while any part of the vehicle is crossing the tracks","Look and listen in both directions for an approaching train","Activate the four-way flashers on approach","Choose a crossing point where the vehicle can clear the tracks without stopping"],"answer":0,"explanation":"A CMV driver must never change gears while any part of the vehicle is on the tracks, since a missed shift could stall the vehicle on the crossing. Source: Utah CDL Handbook (DLD), railroad crossings section.","handbook":"","hbref":""},{"q":"On an undivided two-lane Utah road, a school bus stops and displays alternating flashing red lights. What must a driver approaching from the OPPOSITE direction do?","options":["Stop before reaching the bus and remain stopped until the red lights stop flashing","Slow to 20 mph and pass with caution on the left","Proceed normally because oncoming traffic is never required to stop","Stop only if children are visibly in the roadway"],"answer":0,"explanation":"Utah Code 41-6a-1302 requires traffic from both directions to stop for a school bus showing flashing red lights and not proceed until the red lights cease. Source: Utah Code 41-6a-1302.","handbook":"","hbref":""},{"q":"A school bus is stopped with flashing red lights on the far side of a raised, landscaped median dividing the highway. A CMV driver moving in the opposite direction on the other side of that median is required to do what under Utah law?","options":["Continue, because the median-divided highway exception applies to opposite-direction traffic","Stop, because all traffic must always stop for flashing red lights","Stop only if the bus is within 100 feet","Reduce to 15 mph but need not stop"],"answer":0,"explanation":"Because the highway is divided by a clearly indicated dividing section (the raised median), Utah Code 41-6a-1302 allows opposite-direction traffic to proceed without stopping. Source: Utah Code 41-6a-1302.","handbook":"","hbref":""},{"q":"What color of flashing school-bus lights signals that the bus is preparing to stop and that drivers should slow and prepare to stop in Utah?","options":["Alternating flashing amber (yellow) lights","Alternating flashing red lights","Steady blue lights","Alternating flashing green lights"],"answer":0,"explanation":"In Utah, amber (yellow) flashing lights warn that the bus is about to stop; red flashing lights with the extended stop arm require traffic to stop. Source: Utah Code 41-6a-1302; Utah CDL Handbook school bus section.","handbook":"","hbref":""},{"q":"When a CMV is stopped on the shoulder of a divided or one-way Utah highway, where must the driver place the three emergency warning triangles?","options":["About 10, 100, and 200 feet behind the vehicle toward approaching traffic","About 10, 50, and 150 feet behind the vehicle toward approaching traffic","About 25, 75, and 125 feet behind the vehicle toward approaching traffic","About 50, 100, and 250 feet behind the vehicle toward approaching traffic"],"answer":0,"explanation":"On a divided or one-way highway, triangles go about 10 ft, 100 ft, and 200 ft toward approaching traffic. Source: Utah CDL Handbook (DLD); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"After stopping a CMV on a Utah roadway, within how many minutes must the driver have the emergency warning devices (triangles) placed?","options":["Within 10 minutes","Within 2 minutes","Within 5 minutes","Within 30 minutes"],"answer":0,"explanation":"Warning devices must be set out within 10 minutes of stopping. Source: Utah CDL Handbook (DLD); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a straight, level, undivided two-way Utah road, where are the three warning triangles placed for a stopped CMV?","options":["10 feet to the rear, 100 feet to the rear, and 100 feet to the front of the vehicle","10 feet, 200 feet, and 300 feet, all to the rear","25 feet to the rear, 50 feet to the rear, and 75 feet to the front","100 feet to the rear, 100 feet to the front, and one at the bumper"],"answer":0,"explanation":"On a two-way road, place one triangle about 10 ft to the rear, one about 100 ft to the rear, and one about 100 ft to the front (toward traffic in both directions). Source: Utah CDL Handbook (DLD); 49 CFR 392.22.","handbook":"","hbref":""},{"q":"What is the maximum vehicle WIDTH that may travel on Utah highways without an oversize permit?","options":["8 feet 6 inches","8 feet 0 inches","10 feet 0 inches","9 feet 6 inches"],"answer":0,"explanation":"Utah's legal maximum width without a permit is 8 feet 6 inches (102 inches); anything wider requires a UDOT oversize permit. Source: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2.","handbook":"","hbref":""},{"q":"What is the maximum vehicle HEIGHT allowed on Utah highways before an oversize permit is required?","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"answer":0,"explanation":"Utah allows up to 14 feet in height without a permit, measured from the road surface to the top of the load, which is higher than the 13'6\" limit common in many states. Source: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2.","handbook":"","hbref":""},{"q":"A combination vehicle in Utah grosses 86,000 pounds and is 9 feet wide. What is required before it may operate on Utah highways?","options":["A UDOT oversize/overweight special transportation permit","Nothing, because it is under the federal interstate cap","Only a wide-load banner, no permit","Only a HazMat endorsement on the driver's license"],"answer":0,"explanation":"Loads exceeding 80,000 lb gross or wider than 8'6\" exceed Utah legal limits and require a UDOT oversize/overweight permit (single-trip, semiannual, or annual). Source: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2.","handbook":"","hbref":""},{"q":"On steep Utah mountain grades such as I-80 through Parleys Canyon, what feature is provided specifically to stop a heavy truck whose brakes have failed?","options":["A runaway truck escape ramp","A mandatory weigh-in-motion scale","A reversible HOV lane","A truck-only toll booth"],"answer":0,"explanation":"Utah grades such as I-80 in Parleys Canyon have a runaway truck escape ramp, plus signed brake-check areas approaching the descent, so drivers should descend in a low gear and use proper brake technique. Source: Utah DOT; Utah CDL Handbook (mountain driving).","handbook":"","hbref":""},{"q":"Before a long downgrade in the Utah mountains, what is the safest practice for a commercial driver to control speed?","options":["Select a low gear and rely on engine/auxiliary braking before starting down","Stay in high gear and ride the service brakes continuously to the bottom","Shift to neutral to coast and save fuel down the grade","Build extra speed at the top to make it over the next rise"],"answer":0,"explanation":"Utah's mountain-driving guidance is to choose a low gear and use engine/auxiliary braking before the descent so the service brakes do not overheat; brake-check areas on grades like Parleys Canyon support this. Source: Utah CDL Handbook (DLD), mountain driving and downgrade braking.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in Utah?","options":["The Utah Driver License Division (DLD)","The Utah Department of Motor Vehicles (DMV)","The Utah Department of Transportation (UDOT)","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"In Utah, CDLs are issued by the Utah Driver License Division (DLD), part of the Department of Public Safety. The DMV handles vehicle registration, UDOT handles roads and oversize/overweight permits, and FMCSA is the federal regulator. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"How many questions are on Utah's CDL general knowledge written test?","options":["50 questions","30 questions","40 questions","100 questions"],"answer":0,"explanation":"Utah's general knowledge written test consists of 50 multiple-choice questions, all based on the CDL Handbook. Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test) and 2025 CDL Manual.","handbook":"","hbref":""},{"q":"What minimum score must you achieve to pass a Utah CDL knowledge test?","options":["80%","70%","75%","90%"],"answer":0,"explanation":"Utah requires 80% to pass each CDL knowledge test (40 of 50 on the general knowledge test). This matches the federal standard in 49 CFR 383.135. Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test).","handbook":"","hbref":""},{"q":"In what language are Utah CDL knowledge tests administered?","options":["English only; translation materials are prohibited","English or Spanish, at the applicant's choice","Any language with an approved interpreter present","English, with translation dictionaries permitted"],"answer":0,"explanation":"Utah administers all CDL knowledge tests in English only, and the use of translation materials is strictly prohibited. The tests are also closed-book. Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test).","handbook":"","hbref":""},{"q":"Before taking any CDL written knowledge tests in Utah, what must an applicant already have?","options":["A current DOT medical examiner's certificate","A completed road skills test","One year of out-of-state CDL experience","A hazardous materials background check"],"answer":0,"explanation":"Utah requires applicants to have a current medical examiner's certificate (MEC) before taking the written knowledge tests. The skills test comes later, and the hazmat background check applies only to that endorsement. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"How long is a DOT medical examiner's certificate valid at most for a Utah CDL holder?","options":["Up to 24 months","Up to 12 months","Up to 36 months","Up to 6 months"],"answer":0,"explanation":"A DOT physical (medical examiner's certificate) is valid for up to 24 months in Utah, though an examiner may issue it for a shorter period when monitoring a medical condition. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"Who is authorized to perform the DOT physical for a Utah CDL applicant?","options":["A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed physician chosen by the applicant","A DLD employee at the testing office","Only a UDOT-employed physician"],"answer":0,"explanation":"The DOT physical must be performed by a certified medical examiner listed on the FMCSA National Registry of Certified Medical Examiners. Not just any physician qualifies. Source: Utah DLD CDL Information page and FMCSA National Registry.","handbook":"","hbref":""},{"q":"How many self-certification categories must a Utah CDL applicant choose from?","options":["Four categories, choosing exactly one","Two categories, choosing exactly one","Three categories, choosing exactly one","Five categories, choosing exactly one"],"answer":0,"explanation":"Utah uses four self-certification categories, and a driver may certify to only one. They are Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. Source: Utah DLD CDL Self-Certification page (dld.utah.gov/cdl-self-certification).","handbook":"","hbref":""},{"q":"A Utah driver who operates only within Utah and must meet state qualification requirements would self-certify under which category?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Exempt Federal"],"answer":0,"explanation":"Non-Excepted Intrastate covers drivers operating only within Utah who must meet state medical qualification standards (UCA 53-3-303.5); it carries a Utah-only restriction. Interstate categories apply to nationwide commerce. Source: Utah DLD CDL Self-Certification page (dld.utah.gov/cdl-self-certification).","handbook":"","hbref":""},{"q":"At which of these times must a Utah CDL driver submit a self-certification (and current medical certificate) to the DLD?","options":["Upon issuance of any CDL, when the driving condition changes, and at each renewal","Only once, the first time a CDL is ever issued","Only when changing employers","Only when adding a new endorsement"],"answer":0,"explanation":"For the medical certification process to stay complete, the self-certification form must be submitted to the DLD upon issuance of any CDL, if the status of the driving condition changes, and at each CDL renewal. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"What training must first-time Class A or Class B CDL applicants complete in Utah before obtaining the license?","options":["Entry-Level Driver Training (ELDT) from a registered provider","A 160-hour state apprenticeship","A defensive driving course approved by UDOT","Six months of supervised employer training"],"answer":0,"explanation":"Federal and Utah rules require first-time Class A/B applicants (and first-time school bus, passenger, or hazmat endorsement applicants) to complete Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry before obtaining the CDL. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"ELDT consists of two parts. What must an applicant obtain before the behind-the-wheel portion can be administered?","options":["A commercial learner permit (CLP)","A passing score on the skills test","A hazmat endorsement","A full unrestricted CDL"],"answer":0,"explanation":"ELDT has a theory part and a behind-the-wheel part. Theory may be completed before applying, but a commercial learner permit (CLP) must be obtained before any behind-the-wheel training can be administered. Source: Utah DLD CDL Information page (dld.utah.gov/cdl-info).","handbook":"","hbref":""},{"q":"After passing the written knowledge test in Utah, how long is the commercial learner permit (CLP) valid?","options":["180 days","90 days","1 year","60 days"],"answer":0,"explanation":"Once the general knowledge test is passed, Utah issues a commercial learner permit (CLP) valid for 180 days (about 6 months). Source: Utah DLD CDL Written Knowledge Test page (dld.utah.gov/cdl-written-test) and 2025 CDL Manual.","handbook":"","hbref":""},{"q":"How long must a Utah applicant hold the CLP before being allowed to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Utah requires the applicant to hold the CLP for at least 14 days (and complete ELDT) before taking the skills test, matching the federal CLP rule. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test).","handbook":"","hbref":""},{"q":"The Utah CDL skills test is made up of which three parts, in order?","options":["Pre-trip vehicle inspection, basic control skills, and on-road driving","Written exam, basic control skills, and on-road driving","Pre-trip inspection, air brake exam, and on-road driving","Basic control skills, on-road driving, and a final written exam"],"answer":0,"explanation":"Utah's CDL skills test has three parts: the pre-trip vehicle inspection, the basic control skills test, and the on-road driving test. The written tests are separate from the skills test. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test).","handbook":"","hbref":""},{"q":"What does the pre-trip inspection portion of the Utah skills test primarily evaluate?","options":["Your knowledge of whether the vehicle is safe to drive","Your ability to back the vehicle into a dock","Your reaction time in heavy traffic","Your written knowledge of traffic laws"],"answer":0,"explanation":"The pre-trip inspection tests the applicant's knowledge of whether the vehicle is safe to drive, covering items such as the engine, tractor, trailer, lights, gauges, safety equipment, and air brakes if equipped. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test).","handbook":"","hbref":""},{"q":"To pass the basic control skills portion of the Utah CDL skills test, how many error points may you accrue?","options":["Eight or fewer error points","Twelve or fewer error points","Thirty or fewer error points","Zero error points"],"answer":0,"explanation":"Utah's basic control skills test (forward stop, straight-line backing, forward offset tracking, reverse offset backing) requires eight or fewer error points to pass. The on-road test allows up to 30. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test).","handbook":"","hbref":""},{"q":"To pass the on-road driving portion of the Utah CDL skills test, how many error points may you accrue?","options":["Thirty or fewer error points","Eight or fewer error points","Fifteen or fewer error points","Fifty or fewer error points"],"answer":0,"explanation":"Utah's on-road driving test, which checks whether you have the minimum skills to drive in most traffic situations, requires 30 or fewer error points to pass. The basic control skills test allows only eight. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test).","handbook":"","hbref":""},{"q":"What does Utah require an applicant to provide in order to take the CDL skills (driving) test?","options":["Your own registered, road-ready vehicle of the proper class","A vehicle supplied by the Driver License Division","A vehicle borrowed from a UDOT motor pool","Only a valid CLP, since the state provides the vehicle"],"answer":0,"explanation":"Utah requires the applicant to bring their own registered and road-ready vehicle that is representative of the class of CDL being sought. The DLD does not furnish test vehicles. Source: Utah DLD CDL Driving Skills Test page (dld.utah.gov/cdl-driving-test).","handbook":"","hbref":""},{"q":"How often must a Utah CDL holder renew the license under the standard renewal cycle?","options":["Every five years","Every four years","Every eight years","Every two years"],"answer":0,"explanation":"Utah CDLs follow a five-year renewal cycle, and each renewal requires an updated application plus current self-certification and medical documentation. Source: Utah DLD CDL renewal information (dld.utah.gov) and Utah Uniform Commercial Driver License Act, UCA 53-3-400 et seq.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимально допустимая ширина коммерческого транспортного средства с грузом на дорогах штата Юта без специального разрешения?","options":["8 футов 6 дюймов","8 футов 0 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Юта ограничивает ширину транспортного средства до 8 футов 6 дюймов (102 inches), измеряемую от наружного края до наружного края в самых широких точках, с грузом или без него. Источник: Utah Admin. Code R909-2-4; страница UDOT Legal Height, Width & Length."},"1":{"q":"Какова максимально допустимая высота транспортного средства с грузом на дорогах штата Юта без разрешения на негабаритный груз?","options":["14 футов","13 футов 6 дюймов","15 футов","13 футов"],"explanation":"Максимально допустимая высота в Юте составляет 14 футов, измеряемая от ровной поверхности дороги до верха груза или транспортного средства. Источник: Utah Admin. Code R909-2-4; страница UDOT Legal Height, Width & Length."},"2":{"q":"Какова максимально допустимая полная масса транспортного средства на дорогах штата Юта без разрешения на перевес?","options":["80,000 pounds","78,000 pounds","84,000 pounds","76,000 pounds"],"explanation":"Юта ограничивает допустимую полную массу транспортного средства до 80,000 pounds, что соответствует федеральному лимиту, с учетом ограничений по осям и формуле моста (bridge formula). Источник: Utah Code 72-7-404; оформление разрешений UDOT по габаритам/массе."},"3":{"q":"Какова максимально допустимая нагрузка на одиночную ось на дорогах штата Юта без разрешения?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Юта ограничивает нагрузку на одиночную ось до 20,000 pounds. Источник: Utah Code 72-7-404(1); Utah Admin. Code R909-2."},"4":{"q":"Какова максимально допустимая нагрузка на группу сдвоенных осей (тандем) на дорогах штата Юта без разрешения?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Юта ограничивает нагрузку на сдвоенную ось (тандем) до 34,000 pounds. Источник: Utah Code 72-7-404(1); оформление разрешений UDOT по габаритам/массе."},"5":{"q":"Какова максимально допустимая длина одиночного (цельного) автотранспортного средства на дорогах штата Юта?","options":["45 футов","40 футов","53 фута","48 футов"],"explanation":"Одиночное автотранспортное средство в Юте не может превышать 45 футов в длину, без учета свесов. Источник: Utah Admin. Code R909-2-4."},"6":{"q":"Какова максимально допустимая длина полуприцепа, эксплуатируемого в составе автопоезда «тягач-полуприцеп», на дорогах штата Юта?","options":["53 фута","48 футов","57 футов","45 футов"],"explanation":"Юта разрешает полуприцеп длиной до 53 футов в составе автопоезда «тягач-полуприцеп». Источник: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length."},"7":{"q":"Согласно законодательству Юты, насколько груз может выступать за ПЕРЕДНЮЮ часть тягача, прежде чем потребуется разрешение на негабаритный груз?","options":["3 фута","4 фута","5 футов","2 фута"],"explanation":"Транспортное средство не может перевозить груз, выступающий более чем на 3 фута за переднюю часть тягача, без разрешения. Источник: положение о свесах Utah Admin. Code R909-2-4."},"8":{"q":"Согласно законодательству Юты, насколько груз может выступать за ЗАДНЮЮ часть кузова или платформы, прежде чем потребуется разрешение на негабаритный груз?","options":["6 футов","4 фута","8 футов","3 фута"],"explanation":"Груз не может выступать более чем на 6 футов за заднюю часть кузова или платформы без разрешения. Источник: положение о свесах Utah Admin. Code R909-2-4."},"9":{"q":"Какова максимальная суммарная длина прицепов для сочленения с двумя прицепами (сдвоенный прицеп) на дорогах штата Юта?","options":["61 фут","65 футов","53 фута","68 футов"],"explanation":"Юта допускает максимальную суммарную длину прицепов 61 фут для сцепок с двумя прицепами. Источник: Utah Admin. Code R909-2-4."},"10":{"q":"Согласно Utah Code 72-7-404, какова максимально допустимая нагрузка на одно КОЛЕСО транспортного средства?","options":["10,500 pounds","8,000 pounds","12,000 pounds","9,000 pounds"],"explanation":"Юта запрещает эксплуатацию транспортного средства с полной нагрузкой, превышающей 10,500 pounds на одно колесо. Источник: Utah Code 72-7-404(1)."},"11":{"q":"Какую формулу использует Юта для определения допустимой полной массы на группу последовательных осей?","options":["Федеральную формулу моста: W = 500[LN/(N-1) + 12N + 36]","Полную массу, разделенную на количество шин","20,000 pounds, умноженные на количество осей","Сумму паспортных нагрузок осей минус 10 процентов"],"explanation":"Юта применяет федеральную формулу моста W = 500[LN/(N-1) + 12N + 36], где W — полная масса, L — расстояние группы осей, а N — количество осей. Источник: Utah Code 72-7-404; онлайн-калькулятор моста UDOT."},"12":{"q":"В формуле моста Юты W = 500[LN/(N-1) + 12N + 36] что обозначает переменная «L»?","options":["Расстояние в футах между крайними осями группы","Допустимый предел нагрузки на ось","Длину прицепа в футах","Количество нагруженных осей"],"explanation":"В формуле моста L — это расстояние в футах между крайними осями группы, N — количество осей, а W — итоговая полная масса, округленная до ближайших 500 pounds. Источник: Utah Code 72-7-404."},"13":{"q":"Согласно Utah Code 72-7-404, два последовательных комплекта сдвоенных осей могут каждый нести по 34,000 pounds при условии, что расстояние между первой и последней осями этих комплектов составляет не менее скольких футов?","options":["36 футов","30 футов","40 футов","44 фута"],"explanation":"Два последовательных комплекта сдвоенных осей могут каждый нести по 34,000 pounds, если общее расстояние между первой и последней осями этих двух комплектов составляет 36 футов или более. Источник: Utah Code 72-7-404."},"14":{"q":"Когда требуется разрешение от UDOT на негабаритный/перевесной груз в Юте?","options":["Когда транспортное средство или груз превышает допустимые ограничения по габаритам или массе, установленные в Utah Code 72-7-402 и 72-7-404","Только при пересечении границы штата при въезде в Юту","Только для грузов свыше 200,000 pounds","Только при движении по межштатным автомагистралям (Interstate)"],"explanation":"Разрешение UDOT требуется всякий раз, когда транспортное средство или груз превышает допустимые ограничения по габаритам и/или массе, установленные в Utah Code 72-7-402 (габариты) и 72-7-404 (масса). Источник: UDOT Oversize & Overweight Provisions; Utah Code 72-7-406."},"15":{"q":"Как обычно выдаются разрешения UDOT на негабаритный/перевесной груз в Юте?","options":["На разовую поездку, на полугодовой или годовой основе","Только как пожизненные разрешения","Только как разрешения на разовую поездку","Только как месячные разрешения"],"explanation":"UDOT выдает разрешения на негабаритный/перевесной груз на основе разовой поездки, на полугодовой или годовой основе, оформляемые через онлайн-систему UDOT по выдаче разрешений (MCS). Источник: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2-8."},"16":{"q":"Разрешение на перевесной ДЕЛИМЫЙ груз в Юте, как правило, доступно для транспортного средства или сцепки, зарегистрированных для какого диапазона полной массы?","options":["от 78,001 до 80,000 pounds","от 60,000 до 70,000 pounds","от 80,001 до 90,000 pounds","от 70,000 до 78,000 pounds"],"explanation":"Разрешение Юты на перевесной делимый груз применяется к транспортным средствам или сцепкам, надлежащим образом зарегистрированным на массу от 78,001 до 80,000 pounds, и при этом должно соответствовать формуле моста и допустимым ограничениям по осям. Источник: Utah Admin. Code R909-2-21; UDOT Overweight Divisible Load Provisions."},"17":{"q":"При перевозке сена в Юте два рулона или тюка сена могут перевозиться бок о бок по разрешению на неделимый негабаритный груз только в том случае, если их суммарная ширина не превышает чего?","options":["10 футов","8 футов 6 дюймов","12 футов","14 футов"],"explanation":"Юта разрешает сцепкам для перевозки сена везти два рулона или тюка бок о бок, когда их суммарная ширина составляет 10 футов или менее и имеется действующее разрешение на неделимый негабаритный груз. Источник: положения UDOT/Utah Admin. Code R909-2 для сельхозперевозок (перевозка сена)."},"18":{"q":"На обычной дороге Юты, которая НЕ является разделенной/межштатной (Interstate) трассой, при какой ширине для негабаритного груза, как правило, требуется сопровождающий автомобиль (pilot/escort)?","options":["Более 12 футов","Более 8 футов 6 дюймов","Более 14 футов","Более 16 футов"],"explanation":"На двухполосных (неразделенных) дорогах Юты сопровождение, как правило, требуется, когда ширина груза превышает 12 футов; на разделенных/межштатных (Interstate) дорогах порог составляет более 14 футов. Источник: положения UDOT/Utah Admin. Code R909-2 о сопровождении."},"19":{"q":"Согласно положениям Юты о разрешениях на перевес для неделимых грузов, до какой максимальной нагрузки на одиночную ось UDOT может разрешить для неделимого груза?","options":["29,000 pounds","24,000 pounds","34,000 pounds","20,000 pounds"],"explanation":"UDOT может выдавать разрешения на перевес для неделимых грузов до 29,000 pounds на одиночную ось, 50,000 pounds на тандем и разрешенную полную массу до 125,000 pounds. Источник: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2."},"20":{"q":"В Юте какой класс CDL требуется для управления составным транспортным средством с полной разрешенной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемый прицеп рассчитан более чем на 10,000 pounds?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Юта выдает CDL класса A для составных транспортных средств с GCWR 26,001 lbs или более, когда буксируемый прицеп превышает 10,000 lbs GVWR (например, автопоезд «тягач-прицеп»). Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info) и Utah CDL Handbook."},"21":{"q":"Водитель в Юте управляет одиночным транспортным средством (например, большим самосвалом или автобусом) с полной разрешенной массой (GVWR) 26,001 pounds или более без буксируемого прицепа. Какой класс CDL для этого требуется?","options":["Класс C","Класс B","Класс A","Класс E"],"explanation":"CDL класса B в Юте охватывает одиночное транспортное средство с GVWR 26,001 lbs или более, не имеющее буксируемого прицепа (или буксирующее прицеп 10,000 lbs или менее). Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"22":{"q":"По правилам Юты CDL класса C применяется к транспортному средству с GVWR менее 26,001 pounds, когда оно предназначено для перевозки как минимум скольких пассажиров, включая водителя?","options":["10 пассажиров","12 пассажиров","16 пассажиров","24 пассажира"],"explanation":"Юта определяет класс C как транспортное средство с GVWR менее 26,001 lbs, которое перевозит 16 или более пассажиров, включая водителя, либо имеет таблички (placards) для опасных грузов. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"23":{"q":"Каков минимальный возраст для получения CDL в Юте для перевозок внутри штата (вождение только в пределах Юты)?","options":["16 лет","18 лет","19 лет","21 год"],"explanation":"Юта разрешает получение CDL в 18 лет только для вождения внутри штата. Водители младше 21 года ограничены эксплуатацией в пределах Юты. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"24":{"q":"Каков минимальный возраст, необходимый для владения CDL в Юте, действительным для межштатных перевозок (вождение через границы штатов)?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Федеральные правила, принятые Ютой, требуют, чтобы водителю было не менее 21 года для управления коммерческим автотранспортным средством в межштатных перевозках. Водители 18-20 лет ограничены перевозками внутри штата. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info); 49 CFR 391.11."},"25":{"q":"19-летний владелец CDL в Юте имеет ограничение K-restriction. Какое из следующих дополнений (endorsement) этот водитель ИМЕЕТ ПРАВО получить?","options":["Опасные грузы (H)","Пассажирское (P)","Школьный автобус (S)","Цистерна (N)"],"explanation":"Водители младше 21 года в Юте ограничены перевозками внутри штата и НЕ имеют права на дополнения H (опасные грузы), P (пассажирское) или S (школьный автобус). Дополнение N (цистерна) не входит в этот запрещенный список. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"26":{"q":"Какое дополнение необходимо водителю в Юте для перевозки опасных грузов в количествах, требующих установки табличек (placards)?","options":["Дополнение N","Дополнение T","Дополнение H","Дополнение X"],"explanation":"Дополнение H (опасные грузы, HazMat) требуется для перевозки опасных грузов в количествах, требующих табличек. Оно также требует прохождения проверки благонадежности (security threat assessment) TSA. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"27":{"q":"Прежде чем Юта выдаст дополнение на опасные грузы (H), заявитель должен пройти какую дополнительную проверку?","options":["Федеральную проверку благонадежности (security threat assessment) TSA","Проверку на полиграфе, проводимую штатом","Проверку зрения у офтальмолога","Курс реабилитации от наркозависимости, спонсируемый работодателем"],"explanation":"Дополнение H требует прохождения проверки благонадежности (security threat assessment) / проверки данных TSA (Transportation Security Administration) согласно федеральному закону, в дополнение к тесту на знание правил перевозки опасных грузов. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info); 49 CFR 1572."},"28":{"q":"Водитель в Юте хочет буксировать сдвоенные и строенные прицепы. Какое дополнение требуется и на каком классе CDL оно может присутствовать?","options":["Дополнение T, доступно только на CDL класса A","Дополнение N, доступно на классе A или B","Дополнение T, доступно только на CDL класса B","Дополнение P, доступно на любом классе"],"explanation":"Дополнение T (сдвоенные/строенные прицепы) позволяет буксировать более одного прицепа и может быть добавлено только к CDL класса A. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info) и Utah CDL Handbook."},"29":{"q":"Какое дополнение необходимо водителю в Юте для управления цистерной, используемой для перевозки жидкостей или газов?","options":["Дополнение P","Дополнение N","Дополнение H","Дополнение T"],"explanation":"Дополнение N (цистерна) требуется для транспортных средств, перевозящих жидкости/газы в цистерне с индивидуальной паспортной вместимостью 119 gallons или более и суммарной паспортной вместимостью более 1,000 gallons. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"30":{"q":"Какое дополнение требуется, прежде чем водитель в Юте сможет получить дополнение на школьный автобус (S)?","options":["Дополнение на опасные грузы (H)","Дополнение на цистерну (N)","Пассажирское дополнение (P)","Дополнение на сдвоенные/строенные прицепы (T)"],"explanation":"В Юте дополнение на школьный автобус (S) добавляется поверх пассажирского дополнения (P); заявитель должен соответствовать требованиям для P (знания и навыки), а затем сдать дополнительные тесты на знания и навыки для S. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"31":{"q":"Какие два дополнения требуют от заявителя в Юте сдачи практического теста по ВОЖДЕНИЮ в дополнение к письменному тесту на знания?","options":["H (опасные грузы) и N (цистерна)","P (пассажирское) и S (школьный автобус)","T (сдвоенные/строенные прицепы) и N (цистерна)","H (опасные грузы) и T (сдвоенные/строенные прицепы)"],"explanation":"В Юте дополнения P (пассажирское) и S (школьный автобус) каждое требуют практического теста по вождению на соответствующем транспортном средстве, тогда как H, N и T требуют только теста на знания. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"32":{"q":"Согласно федеральным правилам, принятым Ютой, как долго водитель должен владеть учебным коммерческим разрешением (CLP), прежде чем ему будет разрешено сдавать практический тест по вождению на CDL?","options":["7 days","14 days","30 days","60 days"],"explanation":"Заявитель должен владеть CLP не менее 14 days, прежде чем сдавать практический тест на CDL. Это требование FMCSA, применяемое Utah DLD. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test); 49 CFR 383.25."},"33":{"q":"Как долго действует учебное коммерческое разрешение (CLP) в Юте с даты его выдачи?","options":["90 days","180 days","1 год","2 года"],"explanation":"CLP в Юте действует 180 days (около 6 месяцев). Оно может быть продлено один раз в течение двухлетнего периода. Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"34":{"q":"Какой минимальный балл должен набрать заявитель, чтобы сдать письменный тест на знания CDL в Юте (общие знания или тест на дополнение)?","options":["70%","75%","80%","90%"],"explanation":"Юта требует балл 80% для сдачи любого письменного теста на знания CDL. Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"35":{"q":"Какой тест на знания заявитель в Юте должен сдать ПЕРВЫМ, чтобы ему было выдано учебное коммерческое разрешение (CLP)?","options":["Тест на общие знания из 50 вопросов","Тест по пневматическим тормозам из 25 вопросов","Тест по составным транспортным средствам из 20 вопросов","Тест по опасным грузам из 30 вопросов"],"explanation":"Сдача теста на общие знания из 50 вопросов (на 80%) приводит к выдаче CLP, который действует 180 days. Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"36":{"q":"Начальная подготовка водителей (ELDT), требуемая для впервые обращающихся заявителей класса A или класса B в Юте, должна быть пройдена через провайдера, который:","options":["Утвержден местным школьным округом","Внесен в реестр провайдеров обучения FMCSA (Training Provider Registry)","Сертифицирован Налоговой комиссией штата Юта","Аккредитован Министерством образования США"],"explanation":"ELDT должна быть пройдена через провайдера, внесенного в реестр провайдеров обучения FMCSA (Training Provider Registry, TPR), до сдачи практического теста. ELDT применяется к впервые обращающимся заявителям класса A/B, к повышению с класса B до A, а также к первичным дополнениям H, P и S. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info); 49 CFR Part 380."},"37":{"q":"Для чего из перечисленного Юта НЕ требует начальную подготовку водителей (ELDT)?","options":["Для впервые обращающегося заявителя на CDL класса A","Для впервые обращающегося заявителя на дополнение по опасным грузам (H)","Для добавления дополнения на цистерну (N)","Для впервые обращающегося заявителя на дополнение по школьному автобусу (S)"],"explanation":"Федеральная ELDT применяется к впервые получаемым CDL класса A/B, к повышению с класса B до A, а также к первичным дополнениям H, P и S. Дополнения N (цистерна) и T (сдвоенные/строенные прицепы) не подпадают под ELDT. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info); 49 CFR Part 380."},"38":{"q":"При подаче заявления на CDL в Юте какую комбинацию документов заявитель должен предоставить в Driver License Division?","options":["Подтверждение личности и законного пребывания, полный номер социального страхования (Social Security number) и два документа, подтверждающих проживание в Юте","Только паспорт","Аттестат об окончании средней школы и один счет за коммунальные услуги","Только регистрацию транспортного средства и подтверждение страховки"],"explanation":"Utah DLD требует подтверждение личности/законного пребывания, полный номер социального страхования (Social Security number) заявителя и два документа, подтверждающих проживание в Юте (плюс действующая медицинская справка, где это требуется). Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"39":{"q":"Заявитель на CDL в Юте, который ездит только в пределах Юты и перевозит неосвобожденный груз и имеет действующую медицинскую карту DOT, должен пройти самосертификацию по какой категории?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Юта использует четыре категории самосертификации. Водитель, работающий только в пределах Юты в неосвобожденных перевозках, сертифицируется как Non-Excepted Intrastate. Межштатные категории применяются к вождению через границы штатов; освобожденные категории применяются к определенным операциям, освобожденным федеральным законом. Источник: страница Utah DLD CDL Self-Certification (dld.utah.gov/cdl-self-certification)."},"40":{"q":"В Юте при какой концентрации алкоголя в крови/выдыхаемом воздухе (BAC) и выше человеку запрещено управлять коммерческим автотранспортным средством (CMV)?","options":["0.04","0.08","0.02","0.05"],"explanation":"Utah Code 53-3-414(1)(a)(ii) делает серьезным нарушением управление CMV с концентрацией алкоголя 0.04 грамма или более. Лимит 0.08 применяется только к некоммерческому вождению. Источник: Utah Code 53-3-414; Utah CDL Manual."},"41":{"q":"Водитель CDL в Юте осужден за ПЕРВОЕ серьезное нарушение (например, управление CMV с BAC 0.04 или более) и НЕ перевозил опасные грузы с табличками (placards). Каков минимальный срок дисквалификации CDL?","options":["1 год","60 days","3 года","6 месяцев"],"explanation":"Согласно Utah Code 53-3-414(1)(a), первое серьезное нарушение приводит к дисквалификации на срок не менее одного года. Источник: Utah Code 53-3-414; Utah CDL Manual."},"42":{"q":"Если водитель CDL в Юте совершает первое серьезное нарушение (например, DUI) ВО ВРЕМЯ перевозки опасного груза, требующего установки табличек (placards), до какого срока увеличивается минимальная дисквалификация?","options":["3 года","1 год","2 года","Пожизненно"],"explanation":"Utah Code 53-3-414(2) повышает минимальную дисквалификацию за первое серьезное нарушение до не менее трех лет, когда нарушение происходит во время перевозки опасных грузов с табличками (placards). Источник: Utah Code 53-3-414."},"43":{"q":"Что происходит с владельцем CDL в Юте, который осужден за ВТОРОЕ серьезное нарушение, возникшее в результате отдельного инцидента?","options":["Пожизненная дисквалификация от управления CMV","Дисквалификация на 3 года","Дисквалификация на 1 год","Дисквалификация на 120 days"],"explanation":"Utah Code 53-3-414(3)(a) предусматривает, что два или более серьезных нарушения из отдельных инцидентов приводят к пожизненной дисквалификации от управления CMV. Источник: Utah Code 53-3-414; Utah CDL Manual."},"44":{"q":"Согласно правилам подразумеваемого согласия (implied consent) в Юте, каковы последствия для водителя CDL, который отказывается пройти химический тест на концентрацию алкоголя или наркотиков?","options":["Это рассматривается как серьезное нарушение, дисквалифицирующее CDL не менее чем на 1 год","Только предупреждение при первом отказе","Дисквалификация на 60 days","Штраф $500 без дисквалификации"],"explanation":"Utah Code 53-3-414(1)(a)(vi) относит отказ пройти химический тест к серьезным нарушениям, влекущим такую же минимальную дисквалификацию на 1 год (3 года при перевозке опасных грузов с табличками). Источник: Utah Code 53-3-414; Utah CDL Manual."},"45":{"q":"Сколько СЕРЬЕЗНЫХ нарушений правил дорожного движения в течение трехлетнего периода влекут дисквалификацию CDL на 60 days в Юте?","options":["2","3","1","4"],"explanation":"Utah Code 53-3-414(6)(a)(i) требует дисквалификации не менее чем на 60 days за два серьезных нарушения правил дорожного движения, произошедших в течение трех лет. Источник: Utah Code 53-3-414; Utah CDL Manual."},"46":{"q":"В Юте водитель CDL, осужденный за ТРИ или более серьезных нарушения правил дорожного движения в течение трехлетнего периода, дисквалифицируется как минимум на какой срок?","options":["120 days","60 days","1 год","90 days"],"explanation":"Utah Code 53-3-414(6)(a)(ii) налагает дисквалификацию не менее чем на 120 days за три или более серьезных нарушения правил дорожного движения в течение трех лет. Источник: Utah Code 53-3-414; Utah CDL Manual."},"47":{"q":"Что из перечисленного классифицируется как СЕРЬЕЗНОЕ нарушение правил дорожного движения для водителя CDL в Юте?","options":["Превышение скорости на 15 mph или более сверх установленного лимита","Превышение скорости на 5 mph сверх установленного лимита","Нарушение правил парковки","Движение на 3 mph ниже лимита"],"explanation":"Согласно Utah CDL Manual и списку кодов нарушений (ACD) Юты, превышение скорости на 15 mph или более сверх лимита является серьезным нарушением правил дорожного движения. Меньшее превышение скорости и парковка не являются серьезными. Источник: Utah CDL Manual; 49 CFR 383.51, применяемый в Юте."},"48":{"q":"Какое действие считается серьезным нарушением правил дорожного движения, которое может способствовать дисквалификации CDL в Юте?","options":["Набор текста или использование ручного телефона во время управления CMV","Использование телефона в режиме «свободные руки» (hands-free) во время управления CMV","Прием пищи во время управления CMV","Прослушивание радио во время управления CMV"],"explanation":"Юта следует федеральному списку серьезных нарушений (49 CFR 383.51): набор текста или использование ручного мобильного телефона во время управления CMV является серьезным нарушением правил дорожного движения. Использование в режиме «свободные руки» (hands-free) не является таковым. Источник: Utah CDL Manual; 49 CFR 383.51."},"49":{"q":"Водитель CDL в Юте осужден за ПЕРВОЕ нарушение приказа о выводе из эксплуатации (out-of-service, OOS) во время управления CMV (без опасных грузов, не большой автобус). Какова минимальная дисквалификация по законодательству Юты?","options":["180 days","90 days","60 days","1 год"],"explanation":"Utah Code 53-3-414(7)(a)(i) устанавливает минимальную дисквалификацию за первое нарушение приказа о выводе из эксплуатации на уровне 180 days, что превышает федеральный минимум в 90 days. Источник: Utah Code 53-3-414."},"50":{"q":"Помимо дисквалификации, какой минимальный ГРАЖДАНСКИЙ ШТРАФ налагает законодательство Юты на водителя CDL, осужденного за ПЕРВОЕ нарушение приказа о выводе из эксплуатации?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"Utah Code 53-3-414(7)(b) требует гражданский штраф не менее $2,500 за первое нарушение приказа о выводе из эксплуатации. Источник: Utah Code 53-3-414."},"51":{"q":"Согласно законодательству Юты, минимальный гражданский штраф за ВТОРОЕ или последующее нарушение приказа о выводе из эксплуатации водителем CDL составляет как минимум:","options":["$5,000","$2,500","$3,500","$10,000"],"explanation":"Utah Code 53-3-414(7)(c) устанавливает гражданский штраф в размере не менее $5,000 за второе или последующее нарушение приказа о выводе из эксплуатации. Источник: Utah Code 53-3-414."},"52":{"q":"Водитель CDL в Юте осужден за ВТОРОЕ нарушение приказа о выводе из эксплуатации в отдельном инциденте в течение 10-летнего периода. Какова минимальная дисквалификация?","options":["2 года","1 год","180 days","3 года"],"explanation":"Utah Code 53-3-414(7)(a)(ii) требует дисквалификации не менее чем на два года за второе нарушение приказа о выводе из эксплуатации в отдельных инцидентах в течение любого 10-летнего периода. Источник: Utah Code 53-3-414."},"53":{"q":"Согласно законодательству Юты, ТРЕТЬЕ или более нарушение приказа о выводе из эксплуатации в отдельных инцидентах в течение 10-летнего периода приводит к дисквалификации на:","options":["от 3 до 5 лет","от 1 до 2 лет","от 180 days до 1 года","10 лет"],"explanation":"Utah Code 53-3-414(7)(a)(iii) требует дисквалификации не менее трех лет, но не более пяти лет за три или более нарушения приказа о выводе из эксплуатации в течение любого 10-летнего периода. Источник: Utah Code 53-3-414."},"54":{"q":"Водитель CDL в Юте осужден за ПЕРВОЕ нарушение на железнодорожном переезде во время управления CMV. Какова минимальная дисквалификация?","options":["60 days","30 days","120 days","1 год"],"explanation":"Utah Code 53-3-414(9)(a) налагает дисквалификацию не менее чем на 60 days за первое нарушение на железнодорожном переезде. Источник: Utah Code 53-3-414; Utah CDL Manual."},"55":{"q":"За ВТОРОЕ нарушение на железнодорожном переезде в течение трехлетнего периода (отдельные инциденты) водитель CDL в Юте дисквалифицируется как минимум на:","options":["120 days","60 days","1 год","90 days"],"explanation":"Utah Code 53-3-414(9)(b) требует дисквалификации не менее чем на 120 days за второе нарушение на переезде в течение любого трехлетнего периода. Источник: Utah Code 53-3-414."},"56":{"q":"Водитель CDL в Юте, осужденный за ТРЕТЬЕ или более нарушение на железнодорожном переезде в течение трехлетнего периода (отдельные инциденты), дисквалифицируется как минимум на:","options":["1 год","120 days","60 days","3 года"],"explanation":"Utah Code 53-3-414(9)(c) требует дисквалификации не менее чем на один год за три или более нарушения на переезде в течение любого трехлетнего периода. Источник: Utah Code 53-3-414."},"57":{"q":"Если водитель CMV, который обязан иметь CDL, дает положительный результат на ЛЮБОЕ определяемое количество алкоголя ниже 0.04, какие меры принимаются?","options":["Выводится из эксплуатации на 24 hours","Немедленная дисквалификация CDL на 1 год","Дисквалификация CDL на 60 days","Никаких мер, так как это менее 0.04"],"explanation":"Юта следует федеральному правилу (49 CFR 392.5): водитель CMV с любым определяемым количеством алкоголя менее 0.04 должен быть выведен из эксплуатации на 24 hours. Показатель 0.04 или выше является серьезным нарушением. Источник: Utah CDL Manual; 49 CFR 392.5."},"58":{"q":"В Юте какова минимальная дисквалификация CDL за использование CMV при совершении тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества?","options":["Пожизненная, без возможности восстановления","1 год","3 года","10 лет"],"explanation":"Utah Code 53-3-414(5) и 414(3)(b) налагают пожизненную дисквалификацию БЕЗ права на восстановление, когда CMV используется при совершении тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества. Источник: Utah Code 53-3-414."},"59":{"q":"Владелец CDL в Юте получает пожизненную дисквалификацию, дающую право на восстановление. Какой минимальный срок дисквалификации должен быть отбыт, прежде чем подавать заявление на восстановление CDL?","options":["10 лет","5 лет","3 года","15 лет"],"explanation":"Utah Code 53-3-414(4)(a) разрешает водителю подать заявление на восстановление только после отбытия минимальной дисквалификации в 10 лет и завершения утвержденной программы реабилитации, соответствующей 49 CFR 383.51. Источник: Utah Code 53-3-414."},"60":{"q":"Согласно закону штата Юта \"Move Over\", когда коммерческий водитель приближается к стоящему эвакуатору или машине дорожной службы с включёнными жёлтыми проблесковыми маячками на многополосной автомагистрали, что обязан сделать водитель?","options":["Снизить скорость и, если это практически возможно и безопасно, перестроиться в полосу, не примыкающую к остановившемуся транспортному средству","Сохранять скорость, но подать звуковой сигнал, чтобы предупредить работников","Полностью остановиться, пока остановившееся транспортное средство не покинет обочину","Ничего, потому что закон применяется только к полиции и каретам скорой помощи"],"explanation":"Utah Code 41-6a-904 (закон \"Move Over\") требует, чтобы водитель, приближающийся к стоящему уполномоченному аварийному транспортному средству, эвакуатору или машине дорожной службы с включёнными проблесковыми маячками, снизил скорость и, если он движется по примыкающей полосе и это практически возможно с надлежащим учётом безопасности, перестроился в полосу, не примыкающую к остановившемуся транспортному средству. Источник: Utah Code 41-6a-904."},"61":{"q":"Какую конкретную скорость согласно закону штата Юта \"Move Over\" (41-6a-904) водитель обязан снизить при проезде стоящего аварийного транспортного средства или машины дорожной службы?","options":["Фиксированного значения не установлено; закон требует, чтобы водитель \"снизил скорость\"","Ровно на 20 mph ниже установленного ограничения","Фиксированные 25 mph независимо от установленного ограничения","Ровно 10 mph во всех случаях"],"explanation":"Utah Code 41-6a-904 не называет фиксированного значения в mph. Он требует, чтобы водитель снизил скорость, обеспечил как можно больше пространства, насколько это практически возможно, и перестроился в полосу подальше от остановившегося транспортного средства, когда это практически осуществимо. Источник: Utah Code 41-6a-904."},"62":{"q":"На автомагистрали штата Юта с несколькими полосами в одном направлении грузовой коммерческий автомобиль (CMV), движущийся по левой полосе общего пользования, обгоняется более быстрым транспортным средством, идущим сзади. Что требует закон штата Юта?","options":["Безопасно перестроиться в полосу справа и не препятствовать свободному потоку движения в левой полосе","Удерживать полосу, потому что грузовик уже движется с установленной максимальной скоростью","Ускориться как минимум до 5 mph выше ограничения, чтобы освободить полосу","Сместиться влево на обочину разделительной полосы, чтобы пропустить транспортное средство"],"explanation":"Utah Code 41-6a-704 предусматривает, что водитель в левой полосе общего пользования, которого обгоняет другое транспортное средство, обязан уступить, безопасно перестроившись в полосу справа, и не вправе препятствовать движению или свободному потоку транспорта в левой полосе; нарушение является правонарушением (infraction). Источник: Utah Code 41-6a-704."},"63":{"q":"Какое максимальное установленное ограничение скорости коммерческий водитель может законно встретить на сельской межштатной автомагистрали в штате Юта?","options":["80 mph там, где это установлено знаками","65 mph — общий по штату предел для всех грузовиков","70 mph максимум для любого транспортного средства","85 mph там, где это установлено знаками"],"explanation":"В штате Юта на отдельных участках сельских межштатных автомагистралей установлено ограничение 80 mph (75 mph — распространённое значение по умолчанию), что является самым высоким в штате. Источник: Utah Code 41-6a-601/604 и установленные знаками ограничения Utah DOT."},"64":{"q":"Как штат Юта регулирует ограничения скорости для грузовиков по сравнению с легковыми автомобилями на межштатных автомагистралях?","options":["Грузовики подчиняются тому же установленному ограничению; в штате Юта нет отдельного более низкого общего ограничения скорости для грузовиков","Грузовики ограничены 55 mph по всему штату независимо от установленного ограничения","Грузовики всегда должны двигаться на 15 mph ниже ограничения для легковых автомобилей","Грузовики ограничены 60 mph на всех межштатных автомагистралях"],"explanation":"В отличие от штатов с раздельными ограничениями, таких как Калифорния, штат Юта не устанавливает отдельное более низкое общее по штату ограничение скорости для грузовиков; коммерческие автомобили (CMV) подчиняются тому же установленному ограничению (до 80 mph). Применяются лишь локальные обозначенные знаками снижения скорости для грузовиков на некоторых уклонах. Источник: Utah Code Title 41 Chapter 6a Part 6 и Utah DOT."},"65":{"q":"На железнодорожном переезде в штате Юта водитель автобуса с пассажирами или транспортного средства с табличками HazMat обязан остановить транспортное средство в пределах какого расстояния от ближайшего рельса?","options":["В пределах 50 feet, но не ближе 15 feet от ближайшего рельса","В пределах 25 feet, но не ближе 5 feet от ближайшего рельса","В пределах 100 feet, но не ближе 50 feet от ближайшего рельса","В пределах 75 feet, но не ближе 25 feet от ближайшего рельса"],"explanation":"Автобусы с пассажирами и транспортные средства с табличками HazMat обязаны остановиться в пределах 50 feet, но не ближе 15 feet от ближайшего рельса, а затем посмотреть и прислушаться перед пересечением. Источник: Utah CDL Handbook (DLD) и 49 CFR 392.10 в применении к штату Юта."},"66":{"q":"Какое из перечисленных коммерческих транспортных средств в штате Юта обязано ОСТАНОВИТЬСЯ на каждом железнодорожном переезде (где нет освобождения от этого требования)?","options":["Автобус с пассажирами и транспортное средство с табличками HazMat","Любой тягач с полуприцепом, перевозящий обычный груз","Только транспортные средства массой свыше 26 001 фунтов","Только составы с тройными прицепами"],"explanation":"Штат Юта следует федеральному правилу: только автобусы с пассажирами и транспортные средства с табличками HazMat обязаны останавливаться на железнодорожных переездах; большинство других коммерческих автомобилей (CMV) останавливаться не обязаны. Источник: Utah CDL Handbook (DLD); 49 CFR 392.10."},"67":{"q":"При остановке перед железнодорожным переездом в транспортном средстве с табличками HazMat в штате Юта, прежде чем любая часть транспортного средства окажется на путях, чего из перечисленного водитель НЕ должен делать?","options":["Переключать передачи, пока любая часть транспортного средства пересекает пути","Смотреть и прислушиваться в обоих направлениях на предмет приближающегося поезда","Включить аварийную сигнализацию (четыре поворотника) при приближении","Выбрать место пересечения, где транспортное средство сможет пройти пути без остановки"],"explanation":"Водитель коммерческого автомобиля (CMV) никогда не должен переключать передачи, пока любая часть транспортного средства находится на путях, поскольку неудачное переключение может привести к остановке транспортного средства на переезде. Источник: Utah CDL Handbook (DLD), раздел о железнодорожных переездах."},"68":{"q":"На неразделённой двухполосной дороге в штате Юта школьный автобус останавливается и включает попеременно мигающие красные огни. Что обязан сделать водитель, приближающийся со ВСТРЕЧНОГО направления?","options":["Остановиться, не доезжая до автобуса, и оставаться на месте, пока красные огни не перестанут мигать","Снизить скорость до 20 mph и осторожно проехать слева","Продолжать движение в обычном режиме, потому что встречный транспорт никогда не обязан останавливаться","Останавливаться только если на проезжей части явно видны дети"],"explanation":"Utah Code 41-6a-1302 требует, чтобы транспорт с обоих направлений остановился перед школьным автобусом с мигающими красными огнями и не продолжал движение, пока красные огни не погаснут. Источник: Utah Code 41-6a-1302."},"69":{"q":"Школьный автобус стоит с мигающими красными огнями по другую сторону приподнятой озеленённой медианы, разделяющей автомагистраль. Что обязан сделать водитель коммерческого автомобиля (CMV), движущийся во встречном направлении по другую сторону этой медианы, согласно закону штата Юта?","options":["Продолжать движение, потому что применяется исключение для автомагистрали, разделённой медианой, для транспорта встречного направления","Остановиться, потому что весь транспорт всегда обязан останавливаться перед мигающими красными огнями","Остановиться только если автобус находится в пределах 100 feet","Снизить скорость до 15 mph, но останавливаться не обязан"],"explanation":"Поскольку автомагистраль разделена чётко обозначенной разделительной секцией (приподнятой медианой), Utah Code 41-6a-1302 позволяет транспорту встречного направления продолжать движение без остановки. Источник: Utah Code 41-6a-1302."},"70":{"q":"Какой цвет мигающих огней школьного автобуса в штате Юта сигнализирует, что автобус готовится остановиться и что водителям следует снизить скорость и приготовиться к остановке?","options":["Попеременно мигающие жёлтые (янтарные) огни","Попеременно мигающие красные огни","Постоянные синие огни","Попеременно мигающие зелёные огни"],"explanation":"В штате Юта жёлтые (янтарные) мигающие огни предупреждают, что автобус собирается остановиться; красные мигающие огни с выдвинутым знаком \"стоп\" требуют, чтобы транспорт остановился. Источник: Utah Code 41-6a-1302; Utah CDL Handbook, раздел о школьных автобусах."},"71":{"q":"Когда коммерческий автомобиль (CMV) остановлен на обочине разделённой или односторонней автомагистрали в штате Юта, где водитель обязан разместить три аварийных предупреждающих треугольника?","options":["Примерно в 10, 100 и 200 feet позади транспортного средства в сторону приближающегося транспорта","Примерно в 10, 50 и 150 feet позади транспортного средства в сторону приближающегося транспорта","Примерно в 25, 75 и 125 feet позади транспортного средства в сторону приближающегося транспорта","Примерно в 50, 100 и 250 feet позади транспортного средства в сторону приближающегося транспорта"],"explanation":"На разделённой или односторонней автомагистрали треугольники размещаются примерно в 10 ft, 100 ft и 200 ft в сторону приближающегося транспорта. Источник: Utah CDL Handbook (DLD); 49 CFR 392.22."},"72":{"q":"После остановки коммерческого автомобиля (CMV) на проезжей части в штате Юта, в течение скольких минут водитель обязан разместить аварийные предупреждающие устройства (треугольники)?","options":["В течение 10 минут","В течение 2 минут","В течение 5 минут","В течение 30 минут"],"explanation":"Предупреждающие устройства должны быть выставлены в течение 10 минут после остановки. Источник: Utah CDL Handbook (DLD); 49 CFR 392.22."},"73":{"q":"На прямой ровной неразделённой двусторонней дороге в штате Юта, где размещаются три предупреждающих треугольника для остановившегося коммерческого автомобиля (CMV)?","options":["В 10 feet позади, в 100 feet позади и в 100 feet перед транспортным средством","В 10 feet, 200 feet и 300 feet, все позади","В 25 feet позади, в 50 feet позади и в 75 feet перед транспортным средством","В 100 feet позади, в 100 feet перед транспортным средством и один у бампера"],"explanation":"На двусторонней дороге разместите один треугольник примерно в 10 ft позади, один примерно в 100 ft позади и один примерно в 100 ft впереди (в сторону транспорта с обоих направлений). Источник: Utah CDL Handbook (DLD); 49 CFR 392.22."},"74":{"q":"Какова максимальная ШИРИНА транспортного средства, которое может двигаться по автомагистралям штата Юта без разрешения на негабаритный груз?","options":["8 feet 6 inches","8 feet 0 inches","10 feet 0 inches","9 feet 6 inches"],"explanation":"Установленная законом максимальная ширина в штате Юта без разрешения составляет 8 feet 6 inches (102 inches); всё, что шире, требует разрешения UDOT на негабаритный груз. Источник: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2."},"75":{"q":"Какова максимальная ВЫСОТА транспортного средства, допустимая на автомагистралях штата Юта, прежде чем потребуется разрешение на негабаритный груз?","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"explanation":"Штат Юта допускает высоту до 14 feet без разрешения, измеряемую от поверхности дороги до верха груза, что выше предела 13'6\", распространённого во многих штатах. Источник: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2."},"76":{"q":"Составное транспортное средство в штате Юта имеет полную массу 86 000 фунтов и ширину 9 feet. Что требуется, прежде чем оно сможет двигаться по автомагистралям штата Юта?","options":["Специальное транспортное разрешение UDOT на негабаритный/сверхтяжёлый груз","Ничего, потому что оно не превышает федеральный предел для межштатных перевозок","Только баннер \"широкий груз\", без разрешения","Только отметка HazMat в водительском удостоверении"],"explanation":"Грузы, превышающие 80 000 lb полной массы или шире 8'6\", превышают установленные законом пределы штата Юта и требуют разрешения UDOT на негабаритный/сверхтяжёлый груз (на одну поездку, полугодовое или годовое). Источник: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2."},"77":{"q":"На крутых горных уклонах штата Юта, таких как I-80 через каньон Парлис (Parleys Canyon), какое сооружение предусмотрено специально для остановки тяжёлого грузовика, у которого отказали тормоза?","options":["Аварийная тормозная эстакада для грузовиков с отказавшими тормозами (runaway truck escape ramp)","Обязательные весы для взвешивания в движении (weigh-in-motion)","Реверсивная полоса HOV","Пункт оплаты проезда только для грузовиков"],"explanation":"На уклонах штата Юта, таких как I-80 в каньоне Парлис (Parleys Canyon), есть аварийная тормозная эстакада для грузовиков с отказавшими тормозами (runaway truck escape ramp), а также обозначенные знаками зоны проверки тормозов перед спуском, поэтому водителям следует спускаться на низкой передаче и применять правильную технику торможения. Источник: Utah DOT; Utah CDL Handbook (вождение в горах)."},"78":{"q":"Перед длинным спуском в горах штата Юта какова самая безопасная практика для коммерческого водителя по контролю скорости?","options":["Выбрать низкую передачу и полагаться на торможение двигателем/вспомогательным тормозом перед началом спуска","Оставаться на высокой передаче и непрерывно держать рабочие тормоза до самого низа","Перейти на нейтраль, чтобы катиться накатом и экономить топливо на спуске","Набрать дополнительную скорость наверху, чтобы преодолеть следующий подъём"],"explanation":"Руководство штата Юта по вождению в горах рекомендует выбрать низкую передачу и использовать торможение двигателем/вспомогательным тормозом перед спуском, чтобы рабочие тормоза не перегревались; зоны проверки тормозов на уклонах, таких как каньон Парлис (Parleys Canyon), подтверждают это. Источник: Utah CDL Handbook (DLD), вождение в горах и торможение на спуске."},"79":{"q":"Какое ведомство выдаёт коммерческие водительские удостоверения (CDL) в штате Юта?","options":["Подразделение водительских удостоверений штата Юта (Utah Driver License Division, DLD)","Департамент транспортных средств штата Юта (DMV)","Департамент транспорта штата Юта (UDOT)","Федеральное управление по безопасности грузовых автоперевозок (FMCSA)"],"explanation":"В штате Юта CDL выдаются подразделением водительских удостоверений штата Юта (Utah Driver License Division, DLD), входящим в состав Департамента общественной безопасности. DMV занимается регистрацией транспортных средств, UDOT — дорогами и разрешениями на негабаритный/сверхтяжёлый груз, а FMCSA является федеральным регулятором. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"80":{"q":"Сколько вопросов содержится в письменном тесте на общие знания для CDL в штате Юта?","options":["50 вопросов","30 вопросов","40 вопросов","100 вопросов"],"explanation":"Письменный тест на общие знания в штате Юта состоит из 50 вопросов с вариантами ответов, все из которых основаны на CDL Handbook. Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test) и руководство 2025 CDL Manual."},"81":{"q":"Какой минимальный балл нужно набрать, чтобы сдать тест на знания для CDL в штате Юта?","options":["80%","70%","75%","90%"],"explanation":"Штат Юта требует 80% для сдачи каждого теста на знания для CDL (40 из 50 в тесте на общие знания). Это соответствует федеральному стандарту в 49 CFR 383.135. Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"82":{"q":"На каком языке проводятся тесты на знания для CDL в штате Юта?","options":["Только на английском; материалы для перевода запрещены","На английском или испанском, по выбору заявителя","На любом языке при наличии утверждённого переводчика","На английском, со словарями для перевода"],"explanation":"Штат Юта проводит все тесты на знания для CDL только на английском языке, и использование материалов для перевода строго запрещено. Тесты также проводятся при закрытой книге. Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"83":{"q":"Прежде чем сдавать какие-либо письменные тесты на знания для CDL в штате Юта, что заявитель уже должен иметь?","options":["Действующий медицинский сертификат экзаменатора DOT","Сданный практический тест вождения","Один год опыта работы с CDL за пределами штата","Проверку биографических данных для перевозки опасных грузов"],"explanation":"Штат Юта требует, чтобы заявители имели действующий медицинский сертификат экзаменатора (MEC), прежде чем сдавать письменные тесты на знания. Практический тест проводится позже, а проверка биографических данных для HazMat применяется только к этой отметке. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"84":{"q":"Каков максимальный срок действия медицинского сертификата экзаменатора DOT для владельца CDL в штате Юта?","options":["До 24 месяцев","До 12 месяцев","До 36 месяцев","До 6 месяцев"],"explanation":"Медосмотр DOT (медицинский сертификат экзаменатора) действителен до 24 месяцев в штате Юта, хотя экзаменатор может выдать его на более короткий срок при наблюдении за состоянием здоровья. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"85":{"q":"Кто уполномочен проводить медосмотр DOT для заявителя на CDL в штате Юта?","options":["Медицинский экзаменатор, указанный в Национальном реестре сертифицированных медицинских экзаменаторов FMCSA","Любой лицензированный врач по выбору заявителя","Сотрудник DLD в офисе тестирования","Только врач, нанятый UDOT"],"explanation":"Медосмотр DOT должен проводиться сертифицированным медицинским экзаменатором, указанным в Национальном реестре сертифицированных медицинских экзаменаторов FMCSA. Не любой врач имеет на это право. Источник: страница Utah DLD CDL Information и Национальный реестр FMCSA."},"86":{"q":"Из скольких категорий самосертификации должен выбирать заявитель на CDL в штате Юта?","options":["Из четырёх категорий, выбирая ровно одну","Из двух категорий, выбирая ровно одну","Из трёх категорий, выбирая ровно одну","Из пяти категорий, выбирая ровно одну"],"explanation":"Штат Юта использует четыре категории самосертификации, и водитель может сертифицировать себя только по одной. Это Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate. Источник: страница Utah DLD CDL Self-Certification (dld.utah.gov/cdl-self-certification)."},"87":{"q":"Водитель в штате Юта, который работает только в пределах штата Юта и должен соответствовать требованиям квалификации штата, по какой категории должен самосертифицироваться?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Exempt Federal"],"explanation":"Категория Non-Excepted Intrastate охватывает водителей, работающих только в пределах штата Юта, которые должны соответствовать медицинским квалификационным стандартам штата (UCA 53-3-303.5); она несёт ограничение \"только Юта\". Межштатные категории применяются к общенациональной коммерции. Источник: страница Utah DLD CDL Self-Certification (dld.utah.gov/cdl-self-certification)."},"88":{"q":"В какие из перечисленных моментов водитель CDL в штате Юта обязан подать самосертификацию (и действующий медицинский сертификат) в DLD?","options":["При выдаче любого CDL, при изменении условий вождения и при каждом продлении","Только один раз, при самой первой выдаче CDL","Только при смене работодателя","Только при добавлении новой отметки"],"explanation":"Чтобы процесс медицинской сертификации оставался полным, форма самосертификации должна подаваться в DLD при выдаче любого CDL, при изменении статуса условий вождения и при каждом продлении CDL. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"89":{"q":"Какое обучение должны пройти впервые подающие заявители на CDL класса A или класса B в штате Юта, прежде чем получить удостоверение?","options":["Обучение водителей начального уровня (Entry-Level Driver Training, ELDT) у зарегистрированного поставщика","160-часовое ученичество штата","Курс безопасного вождения, утверждённый UDOT","Шесть месяцев обучения под наблюдением работодателя"],"explanation":"Федеральные правила и правила штата Юта требуют, чтобы впервые подающие заявители на класс A/B (а также впервые подающие на отметки школьного автобуса, пассажирскую или HazMat) прошли обучение водителей начального уровня (ELDT) у поставщика из Реестра поставщиков обучения FMCSA (FMCSA Training Provider Registry), прежде чем получить CDL. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"90":{"q":"ELDT состоит из двух частей. Что должен получить заявитель, прежде чем может быть проведена часть с обучением вождению за рулём?","options":["Коммерческое ученическое разрешение (commercial learner permit, CLP)","Проходной балл на практическом тесте","Отметку HazMat","Полноценный CDL без ограничений"],"explanation":"ELDT состоит из теоретической части и части с обучением вождению за рулём. Теория может быть пройдена до подачи заявления, но коммерческое ученическое разрешение (CLP) должно быть получено, прежде чем может быть проведено любое обучение вождению за рулём. Источник: страница Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"91":{"q":"После сдачи письменного теста на знания в штате Юта, сколько времени действует коммерческое ученическое разрешение (CLP)?","options":["180 дней","90 дней","1 год","60 дней"],"explanation":"После сдачи теста на общие знания штат Юта выдаёт коммерческое ученическое разрешение (CLP), действительное в течение 180 дней (около 6 месяцев). Источник: страница Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test) и руководство 2025 CDL Manual."},"92":{"q":"Сколько времени заявитель в штате Юта должен владеть CLP, прежде чем ему будет разрешено сдавать практический тест на CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Штат Юта требует, чтобы заявитель владел CLP не менее 14 дней (и завершил ELDT), прежде чем сдавать практический тест, что соответствует федеральному правилу о CLP. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)."},"93":{"q":"Из каких трёх частей состоит практический тест на CDL в штате Юта, по порядку?","options":["Предрейсовый осмотр транспортного средства, базовые навыки управления и вождение по дороге","Письменный экзамен, базовые навыки управления и вождение по дороге","Предрейсовый осмотр, экзамен по пневматическим тормозам и вождение по дороге","Базовые навыки управления, вождение по дороге и итоговый письменный экзамен"],"explanation":"Практический тест на CDL в штате Юта состоит из трёх частей: предрейсовый осмотр транспортного средства, тест на базовые навыки управления и тест вождения по дороге. Письменные тесты проводятся отдельно от практического теста. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)."},"94":{"q":"Что в первую очередь оценивает часть предрейсового осмотра в практическом тесте штата Юта?","options":["Ваше знание того, безопасно ли транспортное средство для управления","Вашу способность сдавать транспортное средство задним ходом к погрузочной платформе","Вашу скорость реакции в плотном потоке транспорта","Ваше письменное знание правил дорожного движения"],"explanation":"Предрейсовый осмотр проверяет знание заявителем того, безопасно ли транспортное средство для управления, охватывая такие элементы, как двигатель, тягач, прицеп, фонари, приборы, оборудование безопасности и пневматические тормоза, если они установлены. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)."},"95":{"q":"Чтобы сдать часть с базовыми навыками управления в практическом тесте на CDL в штате Юта, сколько штрафных баллов вы можете набрать?","options":["Восемь или менее штрафных баллов","Двенадцать или менее штрафных баллов","Тридцать или менее штрафных баллов","Ноль штрафных баллов"],"explanation":"Тест на базовые навыки управления в штате Юта (остановка передним ходом, движение задним ходом по прямой, движение со смещением вперёд, движение задним ходом со смещением) требует восемь или менее штрафных баллов для сдачи. Тест вождения по дороге допускает до 30. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)."},"96":{"q":"Чтобы сдать часть с вождением по дороге в практическом тесте на CDL в штате Юта, сколько штрафных баллов вы можете набрать?","options":["Тридцать или менее штрафных баллов","Восемь или менее штрафных баллов","Пятнадцать или менее штрафных баллов","Пятьдесят или менее штрафных баллов"],"explanation":"Тест вождения по дороге в штате Юта, который проверяет, обладаете ли вы минимальными навыками для вождения в большинстве дорожных ситуаций, требует 30 или менее штрафных баллов для сдачи. Тест на базовые навыки управления допускает только восемь. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)."},"97":{"q":"Что штат Юта требует от заявителя предоставить, чтобы сдавать практический тест на CDL (вождение)?","options":["Ваше собственное зарегистрированное, готовое к дороге транспортное средство надлежащего класса","Транспортное средство, предоставленное подразделением водительских удостоверений (DLD)","Транспортное средство, взятое из автопарка UDOT","Только действующий CLP, поскольку штат предоставляет транспортное средство"],"explanation":"Штат Юта требует, чтобы заявитель привёз собственное зарегистрированное и готовое к дороге транспортное средство, представляющее класс CDL, на который он претендует. DLD не предоставляет тестовые транспортные средства. Источник: страница Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)."},"98":{"q":"Как часто владелец CDL в штате Юта обязан продлевать удостоверение при стандартном цикле продления?","options":["Каждые пять лет","Каждые четыре года","Каждые восемь лет","Каждые два года"],"explanation":"CDL в штате Юта следуют пятилетнему циклу продления, и каждое продление требует обновлённого заявления плюс действующей самосертификации и медицинской документации. Источник: информация о продлении Utah DLD CDL (dld.utah.gov) и Utah Uniform Commercial Driver License Act, UCA 53-3-400 et seq."}},"tr":{"0":{"q":"Utah karayollarında izin belgesi olmadan ticari bir aracın ve yükünün yasal azami genişliği nedir?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Utah, araç genişliğini yüklü veya yüksüz olarak en geniş noktalarda dıştan dışa ölçülmek üzere 8 feet 6 inches (102 inches) ile sınırlar. Kaynak: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length sayfası."},"1":{"q":"Utah karayollarında aşırı boyut izin belgesi olmadan bir aracın ve yükünün yasal azami yüksekliği nedir?","options":["14 feet","13 feet 6 inches","15 feet","13 feet"],"explanation":"Utah'ın yasal azami yüksekliği, düz yol yüzeyinden yükün veya aracın tepesine kadar ölçülmek üzere 14 feet'tir. Kaynak: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length sayfası."},"2":{"q":"Utah karayollarında aşırı ağırlık izin belgesi olmadan yasal azami brüt araç ağırlığı nedir?","options":["80,000 pounds","78,000 pounds","84,000 pounds","76,000 pounds"],"explanation":"Utah, yasal brüt araç ağırlığını federal limitle uyumlu olarak 80,000 pounds ile sınırlar; bu, aks ve köprü-formülü limitlerine tabidir. Kaynak: Utah Code 72-7-404; UDOT boyut/ağırlık izin belgesi düzenlemesi."},"3":{"q":"Utah karayollarında, izin belgesi olmadan tek bir aks üzerindeki yasal azami yük nedir?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Utah, tek bir aksı 20,000 pounds ile sınırlar. Kaynak: Utah Code 72-7-404(1); Utah Admin. Code R909-2."},"4":{"q":"Utah karayollarında, izin belgesi olmadan bir tandem aks grubu üzerindeki yasal azami yük nedir?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Utah, bir tandem aksı 34,000 pounds ile sınırlar. Kaynak: Utah Code 72-7-404(1); UDOT boyut/ağırlık izin belgesi düzenlemesi."},"5":{"q":"Utah karayollarında tek (düz) bir motorlu aracın yasal azami uzunluğu nedir?","options":["45 feet","40 feet","53 feet","48 feet"],"explanation":"Utah'ta tek bir motorlu araç, çıkıntılar hariç olmak üzere uzunlukta 45 feet'i aşamaz. Kaynak: Utah Admin. Code R909-2-4."},"6":{"q":"Utah karayollarında çekici-yarı römork kombinasyonunda kullanılan bir yarı römorkun yasal azami uzunluğu nedir?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"Utah, çekici-yarı römork kombinasyonunda yarı römorkun 53 feet'e kadar uzunlukta olmasına izin verir. Kaynak: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length."},"7":{"q":"Utah yasalarına göre, aşırı boyut izin belgesi gerekmeden önce bir yük güç biriminin ÖNÜNDEN ne kadar uzanabilir?","options":["3 feet","4 feet","5 feet","2 feet"],"explanation":"Bir araç, izin belgesi olmadan güç biriminin önünden 3 feet'ten fazla uzanan bir yük taşıyamaz. Kaynak: Utah Admin. Code R909-2-4 çıkıntı hükmü."},"8":{"q":"Utah yasalarına göre, aşırı boyut izin belgesi gerekmeden önce bir yük kasanın veya gövdenin ARKASINDAN ne kadar uzanabilir?","options":["6 feet","4 feet","8 feet","3 feet"],"explanation":"Bir yük, izin belgesi olmadan kasanın veya gövdenin arkasından 6 feet'ten fazla uzanamaz. Kaynak: Utah Admin. Code R909-2-4 çıkıntı hükmü."},"9":{"q":"Utah karayollarında çift römorklu (ikiz römorklu) bir kombinasyon için azami birleşik römork uzunluğu nedir?","options":["61 feet","65 feet","53 feet","68 feet"],"explanation":"Utah, çift römorklu kombinasyonlar için azami 61 feet birleşik römork uzunluğuna izin verir. Kaynak: Utah Admin. Code R909-2-4."},"10":{"q":"Utah Code 72-7-404 kapsamında, bir aracın tek bir TEKERLEĞİ üzerindeki azami izin verilen ağırlık nedir?","options":["10,500 pounds","8,000 pounds","12,000 pounds","9,000 pounds"],"explanation":"Utah, bir tekerlek üzerinde 10,500 pounds'u aşan brüt ağırlıkla araç kullanmayı yasaklar. Kaynak: Utah Code 72-7-404(1)."},"11":{"q":"Utah, ardışık aks grubu üzerindeki izin verilen brüt ağırlığı belirlemek için hangi formülü kullanır?","options":["Federal köprü formülü: W = 500[LN/(N-1) + 12N + 36]","Brüt ağırlığın lastik sayısına bölünmesi","20,000 pounds çarpı aks sayısı","Aks kapasitelerinin toplamı eksi yüzde 10"],"explanation":"Utah, federal köprü formülü W = 500[LN/(N-1) + 12N + 36]'yı benimser; burada W brüt ağırlık, L aks-grubu mesafesi ve N aks sayısıdır. Kaynak: Utah Code 72-7-404; UDOT çevrimiçi köprü hesaplayıcısı."},"12":{"q":"Utah köprü formülü W = 500[LN/(N-1) + 12N + 36]'da 'L' değişkeni neyi temsil eder?","options":["Aks grubunun uç noktaları arasındaki feet cinsinden mesafe","Aks başına yasal yük limiti","Römorkun feet cinsinden uzunluğu","Yüklü aks sayısı"],"explanation":"Köprü formülünde L, grubun uç aksları arasındaki feet cinsinden mesafedir, N aks sayısıdır ve W ise en yakın 500 pounds'a yuvarlanmış sonuç brüt ağırlıktır. Kaynak: Utah Code 72-7-404."},"13":{"q":"Utah Code 72-7-404 kapsamında, iki ardışık tandem aks seti, setlerin ilk ve son aksları arasındaki mesafenin en az kaç feet olması koşuluyla her biri 34,000 pounds taşıyabilir?","options":["36 feet","30 feet","40 feet","44 feet"],"explanation":"İki ardışık tandem aks seti, iki setin ilk ve son aksları arasındaki toplam mesafe 36 feet veya daha fazlaysa her biri 34,000 pounds taşıyabilir. Kaynak: Utah Code 72-7-404."},"14":{"q":"Utah'ta UDOT'tan ne zaman aşırı boyut/aşırı ağırlık izin belgesi gerekir?","options":["Araç veya yük, Utah Code 72-7-402 ve 72-7-404'teki yasal boyut veya ağırlık limitlerini aştığında","Yalnızca Utah'a eyalet sınırını geçerken","Yalnızca 200,000 pounds üzerindeki yükler için","Yalnızca eyaletler arası karayollarında seyahat ederken"],"explanation":"Araç veya yük, Utah Code 72-7-402 (boyut) ve 72-7-404 (ağırlık)'te belirlenen yasal boyut ve/veya ağırlık limitlerini aştığında bir UDOT izin belgesi gerekir. Kaynak: UDOT Oversize & Overweight Provisions; Utah Code 72-7-406."},"15":{"q":"Utah aşırı boyut/aşırı ağırlık izin belgeleri UDOT tarafından genellikle nasıl verilir?","options":["Tek seferlik, altı aylık veya yıllık olarak","Yalnızca ömür boyu izin belgesi olarak","Yalnızca tek seferlik izin belgesi olarak","Yalnızca aylık izin belgesi olarak"],"explanation":"UDOT, aşırı boyut/aşırı ağırlık izin belgelerini UDOT çevrimiçi izin belgesi (MCS) sistemi üzerinden alınmak üzere tek seferlik, altı aylık veya yıllık olarak verir. Kaynak: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2-8."},"16":{"q":"Utah'ta aşırı ağırlık BÖLÜNEBİLİR yük izin belgesi genellikle hangi brüt ağırlık aralığı için tescilli bir araç veya kombinasyon için mevcuttur?","options":["78,001 ila 80,000 pounds","60,000 ila 70,000 pounds","80,001 ila 90,000 pounds","70,000 ila 78,000 pounds"],"explanation":"Utah'ın aşırı ağırlık bölünebilir yük izin belgesi, 78,001 ila 80,000 pounds için usulüne uygun tescil edilmiş araçlara veya kombinasyonlara uygulanır ve yine de köprü formülünü ve yasal aks limitlerini karşılamak zorundadır. Kaynak: Utah Admin. Code R909-2-21; UDOT Overweight Divisible Load Provisions."},"17":{"q":"Utah saman kamyonu operasyonları için, iki rulo veya balya saman bölünemez aşırı boyut izin belgesi kapsamında yan yana yalnızca birleşik genişlikleri neyi aşmadığı takdirde taşınabilir?","options":["10 feet","8 feet 6 inches","12 feet","14 feet"],"explanation":"Utah, birleşik genişlikleri 10 feet veya daha az olduğunda ve geçerli bir bölünemez aşırı boyut izin belgesi bulunduğunda saman kamyonu kombinasyonlarının iki rulo veya balyayı yan yana taşımasına izin verir. Kaynak: UDOT/Utah Admin. Code R909-2 tarımsal (saman kamyonu) hükümleri."},"18":{"q":"Bölünmüş/eyaletler arası bir güzergah OLMAYAN tipik bir Utah karayolunda, aşırı boyutlu bir yük genellikle hangi genişlikte bir öncü/refakat aracı gerektirir?","options":["12 feet'ten fazla","8 feet 6 inches'ten fazla","14 feet'ten fazla","16 feet'ten fazla"],"explanation":"İki şeritli (bölünmemiş) Utah karayollarında, yük genişliği 12 feet'i aştığında genellikle bir refakat aracı gerekir; bölünmüş/eyaletler arası karayollarında ise eşik 14 feet'ten fazladır. Kaynak: UDOT/Utah Admin. Code R909-2 refakat hükümleri."},"19":{"q":"Utah'ın bölünemez aşırı ağırlık izin belgesi hükümleri kapsamında, UDOT bölünemez bir yük için azami hangi tek aks ağırlığına kadar izin verebilir?","options":["29,000 pounds","24,000 pounds","34,000 pounds","20,000 pounds"],"explanation":"UDOT, bölünemez yükler için tek aksta 29,000 pounds'a kadar, tandemde 50,000 pounds'a kadar ve izin verilen GVW olarak 125,000 pounds'a kadar aşırı ağırlık izin belgesi verebilir. Kaynak: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2."},"20":{"q":"Utah'ta, çekilen birimin 10,000 pounds üzerinde derecelendirildiği, Brüt Kombinasyon Ağırlık Derecesi 26,001 pounds veya daha fazla olan bir kombinasyon aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Utah, çekilen birim 10,000 lbs GVWR'yi aştığında (örneğin bir çekici-römork) GCWR'si 26,001 lbs veya daha fazla olan kombinasyon araçları için Class A CDL verir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info) ve Utah CDL Handbook."},"21":{"q":"Bir Utah sürücüsü, Brüt Araç Ağırlık Derecesi 26,001 pounds veya daha fazla olan ve çekilen birimi olmayan tek bir aracı (büyük bir damperli kamyon veya otobüs gibi) kullanır. Bu hangi CDL sınıfını gerektirir?","options":["Class C","Class B","Class A","Class E"],"explanation":"Utah Class B CDL, çekilen birimi olmayan (veya 10,000 lbs veya daha az bir birim çeken) ve GVWR'si 26,001 lbs veya daha fazla olan tek bir aracı kapsar. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"22":{"q":"Utah kurallarına göre, Class C CDL, GVWR'si 26,001 pounds'un altında olan bir araca, sürücü dahil en az kaç yolcu taşımak üzere tasarlandığında uygulanır?","options":["10 yolcu","12 yolcu","16 yolcu","24 yolcu"],"explanation":"Utah, Class C'yi 26,001 lbs GVWR'nin altında olan ve sürücü dahil 16 veya daha fazla yolcu taşıyan ya da tehlikeli maddeler için plakart taşıyan bir araç olarak tanımlar. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"23":{"q":"Eyalet içi operasyon (yalnızca Utah içinde sürüş) için Utah CDL almanın asgari yaşı nedir?","options":["16 yaşında","18 yaşında","19 yaşında","21 yaşında"],"explanation":"Utah, yalnızca eyalet içi sürüş için 18 yaşında CDL'ye izin verir. 21 yaşın altındaki sürücüler Utah içinde operasyonla sınırlıdır. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"24":{"q":"Eyaletler arası operasyon (eyalet sınırlarının ötesinde sürüş) için geçerli bir Utah CDL'ye sahip olmak için gereken asgari yaş nedir?","options":["18 yaşında","19 yaşında","20 yaşında","21 yaşında"],"explanation":"Utah tarafından benimsenen federal kurallar, bir sürücünün eyaletler arası ticarette ticari motorlu araç kullanması için en az 21 yaşında olmasını gerektirir. 18-20 yaş arası sürücüler eyalet içi operasyonla sınırlıdır. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info); 49 CFR 391.11."},"25":{"q":"19 yaşındaki bir Utah CDL sahibi K kısıtlamasına sahiptir. Bu sürücü aşağıdaki onaylardan hangisini almaya UYGUNDUR?","options":["Tehlikeli Maddeler (H)","Yolcu (P)","Okul Otobüsü (S)","Tanker (N)"],"explanation":"Utah'ta 21 yaşın altındaki sürücüler eyalet içi operasyonla sınırlıdır ve H (tehlikeli madde), P (yolcu) veya S (okul otobüsü) onaylarını almaya UYGUN DEĞİLDİR. N (tanker) onayı o yasaklı listede yer almaz. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"26":{"q":"Bir Utah sürücüsünün plakart gerektiren miktarlarda tehlikeli madde taşıması için hangi onaya ihtiyacı vardır?","options":["N onayı","T onayı","H onayı","X onayı"],"explanation":"Plakart gerektiren miktarlarda tehlikeli madde taşımak için H (Tehlikeli Maddeler) onayı gereklidir. Ayrıca bir TSA güvenlik tehdit değerlendirmesi geçmiş kontrolü de gerektirir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"27":{"q":"Utah bir Tehlikeli Maddeler (H) onayı vermeden önce, başvuru sahibinin hangi ek taramayı geçmesi gerekir?","options":["Federal bir TSA güvenlik tehdit değerlendirmesi geçmiş kontrolü","Eyalet tarafından uygulanan bir poligraf testi","Bir göz doktoru tarafından yapılan bir görme testi","İşveren destekli bir uyuşturucu rehabilitasyon kursu"],"explanation":"H onayı, tehlikeli madde bilgi testine ek olarak federal yasa kapsamında bir TSA (Ulaştırma Güvenliği İdaresi) güvenlik tehdit değerlendirmesi / geçmiş kontrolünü geçmeyi gerektirir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info); 49 CFR 1572."},"28":{"q":"Bir Utah sürücüsü çift ve üçlü römork çekmek istiyor. Hangi onay gereklidir ve hangi CDL sınıfında taşınabilir?","options":["T onayı, yalnızca Class A CDL'de mevcuttur","N onayı, Class A veya B'de mevcuttur","T onayı, yalnızca Class B CDL'de mevcuttur","P onayı, herhangi bir sınıfta mevcuttur"],"explanation":"T (Çift/Üçlü) onayı birden fazla römork çekmeye izin verir ve yalnızca bir Class A CDL'ye eklenebilir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info) ve Utah CDL Handbook."},"29":{"q":"Bir Utah sürücüsünün sıvı veya gaz taşımak için kullanılan bir tank aracı kullanması için hangi onaya ihtiyacı vardır?","options":["P onayı","N onayı","H onayı","T onayı"],"explanation":"N (Tanker) onayı, bireysel dereceli kapasitesi 119 gallons veya daha fazla ve toplam dereceli kapasitesi 1,000 gallons üzerinde olan bir tankta sıvı/gaz taşıyan araçlar için gereklidir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"30":{"q":"Bir Utah sürücüsü Okul Otobüsü (S) onayını alabilmeden önce hangi onay gereklidir?","options":["Tehlikeli madde (H) onayı","Tanker (N) onayı","Yolcu (P) onayı","Çift/Üçlü (T) onayı"],"explanation":"Utah'ta Okul Otobüsü (S) onayı, Yolcu (P) onayının üzerine eklenir; bir başvuru sahibinin P için (bilgi ve beceri) uygun olması ve ardından ek S bilgi ve beceri testlerini geçmesi gerekir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"31":{"q":"Hangi iki onay, bir Utah başvuru sahibinin yazılı bilgi testine ek olarak bir sürüş BECERİ testini geçmesini gerektirir?","options":["H (Tehlikeli madde) ve N (Tanker)","P (Yolcu) ve S (Okul Otobüsü)","T (Çift/Üçlü) ve N (Tanker)","H (Tehlikeli madde) ve T (Çift/Üçlü)"],"explanation":"Utah'ta P (Yolcu) ve S (Okul Otobüsü) onaylarının her biri uygun araçta bir sürüş beceri testi gerektirirken, H, N ve T yalnızca bir bilgi testi gerektirir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"32":{"q":"Utah tarafından benimsenen federal kurallar kapsamında, bir sürücünün CDL sürüş beceri testine girmesine izin verilmeden önce bir Ticari Öğrenme İzni'ni (CLP) ne kadar süre elinde tutması gerekir?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"Bir başvuru sahibinin CDL beceri testine girmeden önce CLP'yi en az 14 gün elinde tutması gerekir. Bu, Utah DLD tarafından uygulanan bir FMCSA gerekliliğidir. Kaynak: Utah DLD CDL Driving Skills Test sayfası (dld.utah.gov/cdl-driving-test); 49 CFR 383.25."},"33":{"q":"Bir Utah Ticari Öğrenme İzni (CLP) düzenlendiği tarihten itibaren ne kadar süre geçerlidir?","options":["90 gün","180 gün","1 yıl","2 yıl"],"explanation":"Bir Utah CLP'si 180 gün (yaklaşık 6 ay) geçerlidir. İki yıllık bir süre içinde bir kez yenilenebilir. Kaynak: Utah DLD CDL Written Knowledge Test sayfası (dld.utah.gov/cdl-written-test)."},"34":{"q":"Bir başvuru sahibinin bir Utah CDL yazılı bilgi testini (genel bilgi veya bir onay testi) geçmesi için elde etmesi gereken asgari puan nedir?","options":["70%","75%","80%","90%"],"explanation":"Utah, herhangi bir CDL yazılı bilgi testini geçmek için 80% puan gerektirir. Kaynak: Utah DLD CDL Written Knowledge Test sayfası (dld.utah.gov/cdl-written-test)."},"35":{"q":"Bir Ticari Öğrenme İzni verilmesi için bir Utah başvuru sahibinin İLK olarak hangi bilgi testini geçmesi gerekir?","options":["50 soruluk genel bilgi testi","25 soruluk hava frenleri testi","20 soruluk kombinasyon araçları testi","30 soruluk tehlikeli madde testi"],"explanation":"50 soruluk genel bilgi testini (80% ile) geçmek, 180 gün geçerli olan bir CLP verilmesiyle sonuçlanır. Kaynak: Utah DLD CDL Written Knowledge Test sayfası (dld.utah.gov/cdl-written-test)."},"36":{"q":"İlk kez Utah Class A veya Class B başvuru sahipleri için gereken Giriş Seviyesi Sürücü Eğitimi (ELDT), şu özelliklere sahip bir sağlayıcı aracılığıyla tamamlanmalıdır:","options":["Yerel okul bölgesi tarafından onaylı","FMCSA Training Provider Registry'de listeli","Utah State Tax Commission tarafından sertifikalı","ABD Eğitim Bakanlığı tarafından akredite"],"explanation":"ELDT, beceri testinden önce FMCSA Training Provider Registry'de (TPR) listeli bir sağlayıcı aracılığıyla tamamlanmalıdır. ELDT; ilk kez Class A/B başvuru sahiplerine, Class B'den A'ya yükseltmelere ve ilk kez H, P ve S onaylarına uygulanır. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info); 49 CFR Part 380."},"37":{"q":"Aşağıdakilerden hangisi için Utah Giriş Seviyesi Sürücü Eğitimi (ELDT) gerektirmez?","options":["İlk kez Class A CDL başvuru sahibi","İlk kez Tehlikeli madde (H) onayı başvuru sahibi","Tanker (N) onayı ekleme","İlk kez Okul Otobüsü (S) onayı başvuru sahibi"],"explanation":"Federal ELDT; ilk kez Class A/B CDL'lere, Class B'den A'ya yükseltmelere ve ilk kez H, P ve S onaylarına uygulanır. N (tanker) ve T (çift/üçlü) onayları ELDT'ye tabi değildir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info); 49 CFR Part 380."},"38":{"q":"Bir Utah CDL'sine başvururken, bir başvuru sahibinin Sürücü Belgesi Bölümü'ne hangi belge kombinasyonunu sağlaması gerekir?","options":["Kimlik ve yasal varlık kanıtı, tam Sosyal Güvenlik numarası ve Utah ikametini kanıtlayan iki belge","Yalnızca bir pasaport","Bir lise diploması ve bir fatura","Yalnızca bir araç tescili ve sigorta kanıtı"],"explanation":"Utah DLD, kimlik/yasal varlık kanıtı, başvuru sahibinin tam Sosyal Güvenlik numarası ve Utah ikametini kanıtlayan iki belge (ve gerektiğinde geçerli bir tıbbi sertifika) gerektirir. Kaynak: Utah DLD CDL Information sayfası (dld.utah.gov/cdl-info)."},"39":{"q":"Yalnızca Utah içinde sürüş yapan ve muafiyet kapsamında olmayan kargo taşıyan ve geçerli bir DOT tıbbi kartına sahip olan bir Utah CDL başvuru sahibi, hangi kategori altında öz beyanda bulunmalıdır?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"Utah, dört öz beyan kategorisi kullanır. Yalnızca Utah içinde muafiyet kapsamında olmayan ticarette faaliyet gösteren bir sürücü, Non-Excepted Intrastate olarak beyanda bulunur. Interstate kategorileri eyalet sınırları ötesindeki sürüşe uygulanır; excepted kategorileri belirli federal muaf operasyonlara uygulanır. Kaynak: Utah DLD CDL Self-Certification sayfası (dld.utah.gov/cdl-self-certification)."},"40":{"q":"Utah'ta, bir kişinin ticari motorlu araç (CMV) kullanmasının yasaklandığı kandaki/nefesteki alkol konsantrasyonu (BAC) hangi seviyede veya üzerindedir?","options":["0.04","0.08","0.02","0.05"],"explanation":"Utah Code 53-3-414(1)(a)(ii), 0.04 grams veya daha fazla alkol konsantrasyonuyla bir CMV kullanmayı büyük bir suç haline getirir. 0.08 limiti yalnızca ticari olmayan sürüşe uygulanır. Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"41":{"q":"Bir Utah CDL sürücüsü İLK büyük suçtan (bir CMV'yi 0.04 veya daha fazla BAC ile kullanmak gibi) mahkum edilir ve plakart gerektiren tehlikeli madde taşımıyordu. Asgari CDL diskalifiye süresi nedir?","options":["1 yıl","60 gün","3 yıl","6 ay"],"explanation":"Utah Code 53-3-414(1)(a) kapsamında, ilk büyük suç bir yıldan az olmamak üzere diskalifiye ile sonuçlanır. Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"42":{"q":"Bir Utah CDL sürücüsü, plakart gerektiren bir tehlikeli madde taşırken ilk büyük suçu (DUI gibi) işlerse, asgari diskalifiye hangi süreye yükselir?","options":["3 yıl","1 yıl","2 yıl","Ömür boyu"],"explanation":"Utah Code 53-3-414(2), suç plakart gerektiren tehlikeli madde taşınırken işlendiğinde ilk büyük suç için asgari diskalifiyeyi üç yıldan az olmamak üzere yükseltir. Kaynak: Utah Code 53-3-414."},"43":{"q":"Ayrı bir olaydan kaynaklanan İKİNCİ büyük suçtan mahkum edilen bir Utah CDL sahibine ne olur?","options":["Bir CMV kullanmaktan ömür boyu diskalifiye edilir","3 yıl diskalifiye edilir","1 yıl diskalifiye edilir","120 gün diskalifiye edilir"],"explanation":"Utah Code 53-3-414(3)(a), ayrı olaylardan iki veya daha fazla büyük suçun bir CMV kullanmaktan ömür boyu diskalifiye ile sonuçlanmasını öngörür. Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"44":{"q":"Utah'ın zımni rıza kuralları kapsamında, alkol veya uyuşturucu konsantrasyonu için kimyasal testi reddeden bir CDL sürücüsü için sonuç nedir?","options":["Büyük bir suç olarak ele alınır ve CDL'yi en az 1 yıl diskalifiye eder","İlk reddetmede yalnızca bir uyarı","60 günlük diskalifiye","Diskalifiye olmadan 500 dolar para cezası"],"explanation":"Utah Code 53-3-414(1)(a)(vi), kimyasal testi reddetmeyi büyük bir suç olarak listeler ve aynı asgari 1 yıllık diskalifiyeyi taşır (plakart gerektiren tehlikeli madde varsa 3 yıl). Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"45":{"q":"Utah'ta üç yıllık bir süre içinde kaç CİDDİ trafik ihlali 60 günlük bir CDL diskalifiyesini tetikler?","options":["2","3","1","4"],"explanation":"Utah Code 53-3-414(6)(a)(i), üç yıl içinde meydana gelen iki ciddi trafik ihlali için 60 günden az olmamak üzere diskalifiye gerektirir. Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"46":{"q":"Utah'ta, üç yıllık bir süre içinde ÜÇ veya daha fazla ciddi trafik ihlalinden mahkum edilen bir CDL sürücüsü en az ne kadar süre diskalifiye edilir?","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"Utah Code 53-3-414(6)(a)(ii), üç yıl içinde üç veya daha fazla ciddi trafik ihlali için 120 günden az olmamak üzere diskalifiye uygular. Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"47":{"q":"Aşağıdakilerden hangisi bir Utah CDL sürücüsü için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["İlan edilen limitin 15 mph veya daha fazla üzerinde hız yapmak","İlan edilen limitin 5 mph üzerinde hız yapmak","Bir park ihlali","Limitin 3 mph altında sürmek"],"explanation":"Utah CDL Manual'a ve Utah'ın ihlal (ACD) kod listesine göre, limitin 15 mph veya daha fazla üzerinde hız yapmak ciddi bir trafik ihlalidir. Daha az hız aşımı ve park etme ciddi değildir. Kaynak: Utah CDL Manual; Utah'ta uygulanan 49 CFR 383.51."},"48":{"q":"Hangi eylem, bir Utah CDL diskalifiyesine katkıda bulunabilecek ciddi bir trafik ihlali olarak sayılır?","options":["Bir CMV kullanırken mesaj atmak veya elde tutulan bir telefon kullanmak","Bir CMV kullanırken eller serbest bir telefon kullanmak","Bir CMV kullanırken yemek yemek","Bir CMV kullanırken radyo dinlemek"],"explanation":"Utah, federal ciddi ihlal listesini (49 CFR 383.51) takip eder: bir CMV kullanırken mesaj atmak veya elde tutulan bir cep telefonu kullanmak ciddi bir trafik ihlalidir. Eller serbest kullanım değildir. Kaynak: Utah CDL Manual; 49 CFR 383.51."},"49":{"q":"Bir Utah CDL sürücüsü, bir CMV kullanırken (tehlikeli madde yok, büyük bir otobüs değil) bir hizmet dışı (OOS) emrinin İLK ihlalinden mahkum edilir. Utah yasalarına göre asgari diskalifiye nedir?","options":["180 gün","90 gün","60 gün","1 yıl"],"explanation":"Utah Code 53-3-414(7)(a)(i), ilk hizmet dışı emir ihlali için asgari diskalifiyeyi 180 gün olarak belirler; bu, federal 90 günlük tabanı aşar. Kaynak: Utah Code 53-3-414."},"50":{"q":"Diskalifiyenin yanı sıra, Utah yasaları bir hizmet dışı emrin İLK ihlalinden mahkum edilen bir CDL sürücüsüne hangi asgari MEDENİ CEZAYI uygular?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"Utah Code 53-3-414(7)(b), ilk hizmet dışı emir ihlali için $2,500'dan az olmamak üzere medeni ceza gerektirir. Kaynak: Utah Code 53-3-414."},"51":{"q":"Utah yasalarına göre, bir CDL sürücüsünün İKİNCİ veya sonraki hizmet dışı emir ihlali için asgari medeni ceza en az:","options":["$5,000","$2,500","$3,500","$10,000"],"explanation":"Utah Code 53-3-414(7)(c), ikinci veya sonraki bir hizmet dışı emir ihlali için medeni cezayı $5,000'dan az olmamak üzere belirler. Kaynak: Utah Code 53-3-414."},"52":{"q":"Bir Utah CDL sürücüsü, 10 yıllık bir süre içinde ayrı bir olayda İKİNCİ bir hizmet dışı emir ihlalinden mahkum edilir. Asgari diskalifiye nedir?","options":["2 yıl","1 yıl","180 gün","3 yıl"],"explanation":"Utah Code 53-3-414(7)(a)(ii), herhangi bir 10 yıllık süre içinde ayrı olaylarda ikinci bir OOS-emri ihlali için iki yıldan az olmamak üzere diskalifiye gerektirir. Kaynak: Utah Code 53-3-414."},"53":{"q":"Utah yasalarına göre, 10 yıllık bir süre içinde ayrı olaylarda ÜÇÜNCÜ veya daha fazla hizmet dışı emir ihlali şu süreyle diskalifiye ile sonuçlanır:","options":["3 ila 5 yıl","1 ila 2 yıl","180 gün ila 1 yıl","10 yıl"],"explanation":"Utah Code 53-3-414(7)(a)(iii), herhangi bir 10 yıllık süre içinde üç veya daha fazla OOS-emri ihlali için üç yıldan az ama beş yıldan fazla olmamak üzere diskalifiye gerektirir. Kaynak: Utah Code 53-3-414."},"54":{"q":"Bir Utah CDL sürücüsü, bir CMV kullanırken İLK bir demiryolu-karayolu hemzemin geçit ihlalinden mahkum edilir. Asgari diskalifiye nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Utah Code 53-3-414(9)(a), ilk bir demiryolu-karayolu hemzemin geçit ihlali için 60 günden az olmamak üzere diskalifiye uygular. Kaynak: Utah Code 53-3-414; Utah CDL Manual."},"55":{"q":"Üç yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali için (ayrı olaylar), bir Utah CDL sürücüsü en az şu süreyle diskalifiye edilir:","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"Utah Code 53-3-414(9)(b), herhangi bir üç yıllık süre içinde ikinci bir hemzemin geçit ihlali için 120 günden az olmamak üzere diskalifiye gerektirir. Kaynak: Utah Code 53-3-414."},"56":{"q":"Üç yıllık bir süre içinde ÜÇÜNCÜ veya daha fazla demiryolu-karayolu hemzemin geçit ihlalinden (ayrı olaylar) mahkum edilen bir Utah CDL sürücüsü en az şu süreyle diskalifiye edilir:","options":["1 yıl","120 gün","60 gün","3 yıl"],"explanation":"Utah Code 53-3-414(9)(c), herhangi bir üç yıllık süre içinde üç veya daha fazla hemzemin geçit ihlali için bir yıldan az olmamak üzere diskalifiye gerektirir. Kaynak: Utah Code 53-3-414."},"57":{"q":"CDL bulundurması gereken bir CMV sürücüsü, 0.04'ün altında HERHANGİ bir tespit edilebilir alkol miktarı için pozitif test ederse, hangi işlem yapılır?","options":["24 saat hizmet dışı bırakılır","Anında 1 yıllık CDL diskalifiyesi","60 günlük CDL diskalifiyesi","0.04'ün altında olduğu için hiçbir işlem yapılmaz"],"explanation":"Utah, federal kuralı (49 CFR 392.5) takip eder: 0.04'ün altında herhangi bir tespit edilebilir alkole sahip bir CMV sürücüsü 24 saat hizmet dışı bırakılmalıdır. 0.04 veya daha yüksek bir okuma büyük bir suçtur. Kaynak: Utah CDL Manual; 49 CFR 392.5."},"58":{"q":"Utah'ta, bir kontrollü maddenin imalatı, dağıtımı veya temini ile ilgili bir ağır suçun işlenmesinde bir CMV kullanmak için asgari CDL diskalifiyesi nedir?","options":["Ömür boyu, yeniden ehliyet alma imkanı olmadan","1 yıl","3 yıl","10 yıl"],"explanation":"Utah Code 53-3-414(5) ve 414(3)(b), bir kontrollü madde imalatı, dağıtımı veya temini ile ilgili bir ağır suçta bir CMV kullanıldığında yeniden ehliyet alma uygunluğu OLMADAN ömür boyu diskalifiye uygular. Kaynak: Utah Code 53-3-414."},"59":{"q":"Bir Utah CDL sahibi, yeniden ehliyet almaya uygun bir ömür boyu diskalifiye alır. CDL'yi yeniden almak için başvurmadan önce tamamlanması gereken asgari diskalifiye süresi nedir?","options":["10 yıl","5 yıl","3 yıl","15 yıl"],"explanation":"Utah Code 53-3-414(4)(a), bir sürücünün yalnızca asgari 10 yıllık bir diskalifiyeyi tamamladıktan ve 49 CFR 383.51'i karşılayan onaylı bir rehabilitasyon programını bitirdikten sonra yeniden ehliyet almak için başvurmasına izin verir. Kaynak: Utah Code 53-3-414."},"60":{"q":"Utah'nın Geç (Move Over) yasasına göre, ticari bir sürücü çok şeritli bir karayolunda sarı renkte yanıp sönen ışıklar gösteren duran bir çekici veya karayolu bakım aracına yaklaştığında ne yapmalıdır?","options":["Hızını azaltmalı ve, uygun ve güvenliyse, duran araca bitişik olmayan bir şeride geçmelidir","Hızını korumalı ancak işçileri uyarmak için korna çalmalıdır","Duran araç banketten ayrılana kadar tamamen durmalıdır","Hiçbir şey, çünkü yasa yalnızca polis ve ambulanslar için geçerlidir"],"explanation":"Utah Code 41-6a-904 (Geç yasası), yanıp sönen ışıklarla duran yetkili bir acil durum aracına, çekici/kurtarıcı aracına veya yol bakım aracına yaklaşan bir sürücünün hızını azaltmasını ve bitişik şeritte ilerliyorsa ve güvenliği gözeterek uygunsa, duran aracın yanındaki şeritten farklı bir şeride geçmesini gerektirir. Kaynak: Utah Code 41-6a-904."},"61":{"q":"Utah'nın Geç (Move Over) yasası (41-6a-904), duran bir acil durum veya bakım aracını geçerken sürücünün hangi sayısal hıza yavaşlaması gerektiğini belirtir?","options":["Sabit bir sayı belirlenmemiştir; yasa sürücünün 'hızını azaltmasını' gerektirir","Belirlenen limitin tam olarak 20 mph altı","Belirlenen limitten bağımsız olarak sabit 25 mph","Her durumda tam olarak 10 mph"],"explanation":"Utah Code 41-6a-904 sabit bir mph değeri belirtmez. Sürücünün hızını azaltmasını, mümkün olduğunca fazla alan bırakmasını ve uygun olduğunda duran araçtan uzak bir şeride geçmesini gerektirir. Kaynak: Utah Code 41-6a-904."},"62":{"q":"Aynı yönde birden fazla şeride sahip bir Utah karayolunda, sol genel amaçlı şeritte ilerleyen bir ticari motorlu araç (CMV), arkasından gelen daha hızlı bir araç tarafından geçilmek isteniyor. Utah yasası ne gerektirir?","options":["Güvenli bir şekilde sağdaki bir şeride geçmeli ve sol şeritteki trafiğin serbest akışını engellememeli","Kamyon zaten belirlenen hız limitinde olduğu için şeritte kalmalı","Şeridi boşaltmak için limitin en az 5 mph üzerine çıkmalı","Aracın geçmesine izin vermek için sola, refüj bankete geçmeli"],"explanation":"Utah Code 41-6a-704, sol genel amaçlı şeritte başka bir araç tarafından geçilmek istenen sürücünün güvenli bir şekilde sağdaki bir şeride geçerek yol vermesi gerektiğini ve sol şeritteki trafiğin hareketini veya serbest akışını engelleyemeyeceğini öngörür; ihlali bir kabahattir. Kaynak: Utah Code 41-6a-704."},"63":{"q":"Bir ticari sürücünün kırsal bir Utah eyaletler arası otoyolunda yasal olarak karşılaşabileceği maksimum belirlenmiş hız limiti nedir?","options":["İşaretli yerlerde 80 mph","Tüm kamyonlar için eyalet genelinde 65 mph üst sınır","Herhangi bir araç için maksimum 70 mph","İşaretli yerlerde 85 mph"],"explanation":"Utah, belirlenmiş kırsal eyaletler arası otoyol kesimlerinde 80 mph işareti koyar (75 mph yaygın varsayılan değerdir), bu eyaletteki en yüksek limittir. Kaynak: Utah Code 41-6a-601/604 ve Utah DOT belirlenmiş limitleri."},"64":{"q":"Utah, eyaletler arası otoyolda kamyon hız limitlerini binek araç limitleriyle nasıl karşılaştırarak ele alır?","options":["Kamyonlar aynı belirlenmiş limite uyar; Utah eyalet genelinde ayrı bir düşük kamyon hız limiti belirlemez","Belirlenen limitten bağımsız olarak kamyonlar eyalet genelinde 55 mph ile sınırlıdır","Kamyonlar her zaman belirlenen binek araç limitinin 15 mph altında sürmelidir","Kamyonlar tüm eyaletler arası otoyollarda 60 mph ile sınırlıdır"],"explanation":"California gibi ayrık limitli eyaletlerin aksine, Utah kamyonlar için eyalet genelinde ayrı bir düşük hız limiti uygulamaz; CMV'ler aynı belirlenmiş limite (80 mph'ye kadar) uyar. Yalnızca belirli rampalarda işaretlenmiş yerel kamyon hızı düşürmeleri geçerlidir. Kaynak: Utah Code Başlık 41 Bölüm 6a Kısım 6 ve Utah DOT."},"65":{"q":"Utah'da bir hemzemin demiryolu geçidinde, yolcu taşıyan bir otobüsün veya plakartlı bir HazMat aracının sürücüsü, en yakın raya hangi mesafe içinde aracı durdurmalıdır?","options":["En yakın raya 50 fit içinde ama 15 fitten yakın olmayacak şekilde","En yakın raya 25 fit içinde ama 5 fitten yakın olmayacak şekilde","En yakın raya 100 fit içinde ama 50 fitten yakın olmayacak şekilde","En yakın raya 75 fit içinde ama 25 fitten yakın olmayacak şekilde"],"explanation":"Yolcu taşıyan otobüsler ve plakartlı HazMat araçları en yakın raya 50 fit içinde ama 15 fitten yakın olmamak üzere durmalı, sonra geçmeden önce bakmalı ve dinlemelidir. Kaynak: Utah CDL Handbook (DLD) ve Utah'da uygulandığı şekliyle 49 CFR 392.10."},"66":{"q":"Aşağıdaki Utah ticari araçlarından hangisinin her demiryolu geçidinde (muaf olmadığı yerlerde) DURMASI gerekir?","options":["Yolcu taşıyan bir otobüs ve HazMat plakartları gösteren bir araç","Genel yük taşıyan herhangi bir çekici-römork","Yalnızca 26.001 pound üzerinde ağırlığa sahip araçlar","Yalnızca üçlü römork kombinasyonları"],"explanation":"Utah federal kurala uyar: yalnızca yolcu taşıyan otobüsler ve plakartlı HazMat araçları demiryolu geçitlerinde durmalıdır; diğer CMV'lerin çoğunun durması gerekmez. Kaynak: Utah CDL Handbook (DLD); 49 CFR 392.10."},"67":{"q":"Utah'da plakartlı bir HazMat aracıyla bir demiryolu geçidinde dururken, aracın herhangi bir kısmı raylar üzerine gelmeden önce sürücü aşağıdakilerden hangisini YAPMAMALIDIR?","options":["Aracın herhangi bir kısmı rayları geçerken vites değiştirmek","Yaklaşan bir tren için her iki yönde bakmak ve dinlemek","Yaklaşırken dörtlü flaşörleri çalıştırmak","Aracın durmadan rayları geçebileceği bir geçiş noktası seçmek"],"explanation":"Bir CMV sürücüsü, aracın herhangi bir kısmı raylar üzerindeyken asla vites değiştirmemelidir, çünkü kaçırılan bir vites geçişi aracın geçitte stop etmesine neden olabilir. Kaynak: Utah CDL Handbook (DLD), demiryolu geçitleri bölümü."},"68":{"q":"Bölünmemiş iki şeritli bir Utah yolunda, bir okul otobüsü durur ve dönüşümlü yanıp sönen kırmızı ışıklar gösterir. KARŞI yönden yaklaşan bir sürücü ne yapmalıdır?","options":["Otobüse ulaşmadan önce durmalı ve kırmızı ışıklar yanıp sönmeyi kesene kadar durmaya devam etmelidir","20 mph'ye yavaşlamalı ve soldan dikkatle geçmelidir","Karşıdan gelen trafiğin asla durması gerekmediğinden normal şekilde devam etmelidir","Yalnızca çocuklar yolda görünür şekildeyse durmalıdır"],"explanation":"Utah Code 41-6a-1302, yanıp sönen kırmızı ışıklar gösteren bir okul otobüsü için her iki yöndeki trafiğin durmasını ve kırmızı ışıklar sönene kadar devam etmemesini gerektirir. Kaynak: Utah Code 41-6a-1302."},"69":{"q":"Bir okul otobüsü, karayolunu bölen yükseltilmiş, peyzajlı bir refüjün karşı tarafında yanıp sönen kırmızı ışıklarla durmuştur. Bu refüjün diğer tarafında karşı yönde ilerleyen bir CMV sürücüsünün Utah yasasına göre ne yapması gerekir?","options":["Devam etmelidir, çünkü refüjle bölünmüş karayolu istisnası karşı yöndeki trafiğe uygulanır","Durmalıdır, çünkü tüm trafik her zaman yanıp sönen kırmızı ışıklar için durmalıdır","Yalnızca otobüs 100 fit içindeyse durmalıdır","15 mph'ye düşmeli ama durması gerekmez"],"explanation":"Karayolu açıkça belirtilmiş bir ayırıcı kesimle (yükseltilmiş refüj) bölündüğü için, Utah Code 41-6a-1302 karşı yöndeki trafiğin durmadan devam etmesine izin verir. Kaynak: Utah Code 41-6a-1302."},"70":{"q":"Utah'da hangi renkteki yanıp sönen okul otobüsü ışıkları, otobüsün durmaya hazırlandığını ve sürücülerin yavaşlayıp durmaya hazırlanması gerektiğini bildirir?","options":["Dönüşümlü yanıp sönen sarı (kehribar) ışıklar","Dönüşümlü yanıp sönen kırmızı ışıklar","Sabit mavi ışıklar","Dönüşümlü yanıp sönen yeşil ışıklar"],"explanation":"Utah'da sarı (kehribar) yanıp sönen ışıklar otobüsün durmak üzere olduğunu uyarır; uzatılmış dur kolu ile yanıp sönen kırmızı ışıklar trafiğin durmasını gerektirir. Kaynak: Utah Code 41-6a-1302; Utah CDL Handbook okul otobüsü bölümü."},"71":{"q":"Bir CMV bölünmüş veya tek yönlü bir Utah karayolunun bankette durdurulduğunda, sürücü üç acil durum uyarı üçgenini nereye yerleştirmelidir?","options":["Aracın yaklaşık 10, 100 ve 200 fit arkasında, yaklaşan trafiğe doğru","Aracın yaklaşık 10, 50 ve 150 fit arkasında, yaklaşan trafiğe doğru","Aracın yaklaşık 25, 75 ve 125 fit arkasında, yaklaşan trafiğe doğru","Aracın yaklaşık 50, 100 ve 250 fit arkasında, yaklaşan trafiğe doğru"],"explanation":"Bölünmüş veya tek yönlü bir karayolunda, üçgenler yaklaşan trafiğe doğru yaklaşık 10 fit, 100 fit ve 200 fit mesafeye yerleştirilir. Kaynak: Utah CDL Handbook (DLD); 49 CFR 392.22."},"72":{"q":"Bir CMV'yi bir Utah yolunda durdurduktan sonra, sürücü acil durum uyarı cihazlarını (üçgenler) kaç dakika içinde yerleştirmiş olmalıdır?","options":["10 dakika içinde","2 dakika içinde","5 dakika içinde","30 dakika içinde"],"explanation":"Uyarı cihazları durduktan sonraki 10 dakika içinde yerleştirilmelidir. Kaynak: Utah CDL Handbook (DLD); 49 CFR 392.22."},"73":{"q":"Düz, eğimsiz, bölünmemiş iki yönlü bir Utah yolunda, durdurulmuş bir CMV için üç uyarı üçgeni nereye yerleştirilir?","options":["Aracın 10 fit arkasına, 100 fit arkasına ve 100 fit önüne","10 fit, 200 fit ve 300 fit, hepsi arkaya","25 fit arkaya, 50 fit arkaya ve 75 fit öne","100 fit arkaya, 100 fit öne ve biri tamponun yanına"],"explanation":"İki yönlü bir yolda, bir üçgeni yaklaşık 10 fit arkaya, birini yaklaşık 100 fit arkaya ve birini yaklaşık 100 fit öne (her iki yöndeki trafiğe doğru) yerleştirin. Kaynak: Utah CDL Handbook (DLD); 49 CFR 392.22."},"74":{"q":"Utah karayollarında bir aşırı boyut izni olmadan seyahat edebilecek maksimum araç GENİŞLİĞİ nedir?","options":["8 fit 6 inç","8 fit 0 inç","10 fit 0 inç","9 fit 6 inç"],"explanation":"Utah'nın izin olmadan yasal maksimum genişliği 8 fit 6 inçtir (102 inç); daha geniş olan herhangi bir şey için UDOT aşırı boyut izni gerekir. Kaynak: Utah DOT Boyut/Ağırlık İzinlendirmesi; Utah Admin. Code R909-2."},"75":{"q":"Utah karayollarında bir aşırı boyut izni gerekmeden önce izin verilen maksimum araç YÜKSEKLİĞİ nedir?","options":["14 fit 0 inç","13 fit 6 inç","13 fit 0 inç","15 fit 0 inç"],"explanation":"Utah, yol yüzeyinden yükün tepesine kadar ölçülen, izin olmadan 14 fite kadar yüksekliğe izin verir ki bu birçok eyalette yaygın olan 13'6\" limitinden daha yüksektir. Kaynak: Utah DOT Boyut/Ağırlık İzinlendirmesi; Utah Admin. Code R909-2."},"76":{"q":"Utah'da bir kombinasyon aracı brüt 86.000 pound ağırlığında ve 9 fit genişliğindedir. Utah karayollarında çalışabilmesi için ne gerekir?","options":["Bir UDOT aşırı boyut/aşırı ağırlık özel taşıma izni","Hiçbir şey, çünkü federal eyaletler arası üst sınırın altındadır","Yalnızca bir geniş yük afişi, izin gerekmez","Yalnızca sürücünün ehliyetinde bir HazMat onayı"],"explanation":"Brüt 80.000 lb'yi aşan veya 8'6\"den daha geniş yükler Utah yasal limitlerini aşar ve bir UDOT aşırı boyut/aşırı ağırlık izni (tek seferlik, altı aylık veya yıllık) gerektirir. Kaynak: Utah DOT Boyut/Ağırlık İzinlendirmesi; Utah Admin. Code R909-2."},"77":{"q":"Parleys Kanyonu'ndan geçen I-80 gibi dik Utah dağ rampalarında, frenleri arızalanmış ağır bir kamyonu durdurmak için özel olarak hangi özellik sağlanır?","options":["Bir kaçak kamyon kaçış rampası","Zorunlu bir hareket halinde tartım terazisi","Tersine çevrilebilir bir HOV şeridi","Yalnızca kamyona özel bir gişe"],"explanation":"Parleys Kanyonu'ndaki I-80 gibi Utah rampalarında bir kaçak kamyon kaçış rampası bulunur, ayrıca inişe yaklaşırken işaretli fren kontrol alanları vardır, bu nedenle sürücüler düşük vitesle inmeli ve uygun fren tekniği kullanmalıdır. Kaynak: Utah DOT; Utah CDL Handbook (dağ sürüşü)."},"78":{"q":"Utah dağlarında uzun bir iniş öncesinde, bir ticari sürücünün hızı kontrol etmesi için en güvenli uygulama nedir?","options":["İnişe başlamadan önce düşük bir vites seçmek ve motor/yardımcı frenlemeye güvenmek","Yüksek viteste kalmak ve aşağıya kadar servis frenlerine sürekli basmak","Yakıt tasarrufu için rampada boşa alıp kaymak","Bir sonraki yükselişi aşmak için tepede fazladan hız kazanmak"],"explanation":"Utah'nın dağ sürüşü rehberliği, servis frenlerinin aşırı ısınmaması için iniş öncesinde düşük bir vites seçmek ve motor/yardımcı frenleme kullanmaktır; Parleys Kanyonu gibi rampalardaki fren kontrol alanları bunu destekler. Kaynak: Utah CDL Handbook (DLD), dağ sürüşü ve iniş frenlemesi."},"79":{"q":"Utah'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Utah Sürücü Belgesi Bölümü (DLD)","Utah Motorlu Taşıtlar Departmanı (DMV)","Utah Ulaştırma Departmanı (UDOT)","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)"],"explanation":"Utah'da CDL'ler, Kamu Güvenliği Departmanı'nın bir parçası olan Utah Sürücü Belgesi Bölümü (DLD) tarafından verilir. DMV araç tescilini, UDOT yolları ve aşırı boyut/aşırı ağırlık izinlerini, FMCSA ise federal düzenleyiciyi yönetir. Kaynak: Utah DLD CDL Bilgi sayfası (dld.utah.gov/cdl-info)."},"80":{"q":"Utah'nın CDL genel bilgi yazılı sınavında kaç soru vardır?","options":["50 soru","30 soru","40 soru","100 soru"],"explanation":"Utah'nın genel bilgi yazılı sınavı, tümü CDL Handbook'a dayanan 50 çoktan seçmeli sorudan oluşur. Kaynak: Utah DLD CDL Yazılı Bilgi Sınavı sayfası (dld.utah.gov/cdl-written-test) ve 2025 CDL Manual."},"81":{"q":"Bir Utah CDL bilgi sınavını geçmek için hangi minimum puanı almanız gerekir?","options":["%80","%70","%75","%90"],"explanation":"Utah her CDL bilgi sınavını geçmek için %80 gerektirir (genel bilgi sınavında 50 sorunun 40'ı). Bu, 49 CFR 383.135'teki federal standartla eşleşir. Kaynak: Utah DLD CDL Yazılı Bilgi Sınavı sayfası (dld.utah.gov/cdl-written-test)."},"82":{"q":"Utah CDL bilgi sınavları hangi dilde uygulanır?","options":["Yalnızca İngilizce; çeviri materyalleri yasaktır","Başvuranın tercihine göre İngilizce veya İspanyolca","Onaylı bir tercüman hazır bulunması halinde herhangi bir dilde","Çeviri sözlüklerine izin verilerek İngilizce"],"explanation":"Utah tüm CDL bilgi sınavlarını yalnızca İngilizce uygular ve çeviri materyallerinin kullanımı kesinlikle yasaktır. Sınavlar ayrıca kapalı kitap usulüdür. Kaynak: Utah DLD CDL Yazılı Bilgi Sınavı sayfası (dld.utah.gov/cdl-written-test)."},"83":{"q":"Utah'da herhangi bir CDL yazılı bilgi sınavına girmeden önce, bir başvuranın halihazırda neye sahip olması gerekir?","options":["Geçerli bir DOT tıbbi muayene sertifikası","Tamamlanmış bir yol becerileri sınavı","Bir yıllık eyalet dışı CDL deneyimi","Bir tehlikeli maddeler geçmiş kontrolü"],"explanation":"Utah, başvuranların yazılı bilgi sınavlarına girmeden önce geçerli bir tıbbi muayene sertifikasına (MEC) sahip olmasını gerektirir. Beceri sınavı daha sonra gelir ve tehlikeli madde geçmiş kontrolü yalnızca o onay için geçerlidir. Kaynak: Utah DLD CDL Bilgi sayfası (dld.utah.gov/cdl-info)."},"84":{"q":"Bir Utah CDL sahibi için bir DOT tıbbi muayene sertifikası en fazla ne kadar süre geçerlidir?","options":["24 aya kadar","12 aya kadar","36 aya kadar","6 aya kadar"],"explanation":"Bir DOT muayenesi (tıbbi muayene sertifikası) Utah'da 24 aya kadar geçerlidir, ancak bir muayene uzmanı bir tıbbi durumu izlerken bunu daha kısa bir süre için düzenleyebilir. Kaynak: Utah DLD CDL Bilgi sayfası (dld.utah.gov/cdl-info)."},"85":{"q":"Bir Utah CDL başvuranı için DOT muayenesini yapmaya kim yetkilidir?","options":["FMCSA Sertifikalı Tıbbi Muayene Uzmanları Ulusal Sicilinde listelenen bir tıbbi muayene uzmanı","Başvuran tarafından seçilen herhangi bir lisanslı hekim","Sınav ofisindeki bir DLD çalışanı","Yalnızca UDOT istihdamlı bir hekim"],"explanation":"DOT muayenesi, FMCSA Sertifikalı Tıbbi Muayene Uzmanları Ulusal Sicilinde listelenen sertifikalı bir tıbbi muayene uzmanı tarafından yapılmalıdır. Herhangi bir hekim uygun değildir. Kaynak: Utah DLD CDL Bilgi sayfası ve FMCSA Ulusal Sicili."},"86":{"q":"Bir Utah CDL başvuranı kaç öz-sertifikasyon kategorisinden seçim yapmalıdır?","options":["Dört kategori, tam olarak birini seçerek","İki kategori, tam olarak birini seçerek","Üç kategori, tam olarak birini seçerek","Beş kategori, tam olarak birini seçerek"],"explanation":"Utah dört öz-sertifikasyon kategorisi kullanır ve bir sürücü yalnızca birini beyan edebilir. Bunlar Muaf Olmayan Eyaletler Arası, Muaf Eyaletler Arası, Muaf Olmayan Eyalet İçi ve Muaf Eyalet İçi kategorileridir. Kaynak: Utah DLD CDL Öz-Sertifikasyon sayfası (dld.utah.gov/cdl-self-certification)."},"87":{"q":"Yalnızca Utah içinde çalışan ve eyalet yeterlilik gerekliliklerini karşılaması gereken bir Utah sürücüsü hangi kategori altında öz-sertifikasyon yapardı?","options":["Muaf Olmayan Eyalet İçi","Muaf Olmayan Eyaletler Arası","Muaf Eyaletler Arası","Muaf Federal"],"explanation":"Muaf Olmayan Eyalet İçi kategorisi, yalnızca Utah içinde çalışan ve eyalet tıbbi yeterlilik standartlarını (UCA 53-3-303.5) karşılaması gereken sürücüleri kapsar; yalnızca Utah ile sınırlı bir kısıtlama taşır. Eyaletler arası kategoriler ülke çapında ticarete uygulanır. Kaynak: Utah DLD CDL Öz-Sertifikasyon sayfası (dld.utah.gov/cdl-self-certification)."},"88":{"q":"Bir Utah CDL sürücüsü, aşağıdaki zamanlardan hangisinde DLD'ye bir öz-sertifikasyon (ve güncel tıbbi sertifika) sunmalıdır?","options":["Herhangi bir CDL verildiğinde, sürüş durumu değiştiğinde ve her yenilemede","Yalnızca bir kez, bir CDL ilk verildiğinde","Yalnızca işveren değiştirirken","Yalnızca yeni bir onay eklerken"],"explanation":"Tıbbi sertifikasyon sürecinin eksiksiz kalması için, öz-sertifikasyon formu herhangi bir CDL verildiğinde, sürüş durumunun statüsü değiştiğinde ve her CDL yenilemesinde DLD'ye sunulmalıdır. Kaynak: Utah DLD CDL Bilgi sayfası (dld.utah.gov/cdl-info)."},"89":{"q":"Utah'da ilk kez Sınıf A veya Sınıf B CDL başvuranlarının ehliyeti almadan önce hangi eğitimi tamamlaması gerekir?","options":["Kayıtlı bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","160 saatlik bir eyalet çıraklığı","UDOT tarafından onaylanmış bir defansif sürüş kursu","Altı aylık denetimli işveren eğitimi"],"explanation":"Federal ve Utah kuralları, ilk kez Sınıf A/B başvuranlarının (ve ilk kez okul otobüsü, yolcu veya tehlikeli madde onayı başvuranlarının) CDL'yi almadan önce FMCSA Eğitim Sağlayıcı Sicilindeki bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT) tamamlamasını gerektirir. Kaynak: Utah DLD CDL Bilgi sayfası (dld.utah.gov/cdl-info)."},"90":{"q":"ELDT iki bölümden oluşur. Direksiyon başı bölümü uygulanmadan önce bir başvuranın neyi edinmesi gerekir?","options":["Bir ticari öğrenci izni (CLP)","Beceri sınavında geçer not","Bir tehlikeli madde onayı","Tam, kısıtlamasız bir CDL"],"explanation":"ELDT'nin bir teori bölümü ve bir direksiyon başı bölümü vardır. Teori başvurudan önce tamamlanabilir, ancak herhangi bir direksiyon başı eğitimi uygulanmadan önce bir ticari öğrenci izni (CLP) edinilmelidir. Kaynak: Utah DLD CDL Bilgi sayfası (dld.utah.gov/cdl-info)."},"91":{"q":"Utah'da yazılı bilgi sınavını geçtikten sonra, ticari öğrenci izni (CLP) ne kadar süre geçerlidir?","options":["180 gün","90 gün","1 yıl","60 gün"],"explanation":"Genel bilgi sınavı geçildikten sonra, Utah 180 gün (yaklaşık 6 ay) geçerli bir ticari öğrenci izni (CLP) verir. Kaynak: Utah DLD CDL Yazılı Bilgi Sınavı sayfası (dld.utah.gov/cdl-written-test) ve 2025 CDL Manual."},"92":{"q":"Bir Utah başvuranı, CDL beceri sınavına girmesine izin verilmeden önce CLP'yi ne kadar süre tutmalıdır?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Utah, beceri sınavına girmeden önce başvuranın CLP'yi en az 14 gün tutmasını (ve ELDT'yi tamamlamasını) gerektirir, bu federal CLP kuralıyla eşleşir. Kaynak: Utah DLD CDL Sürüş Beceri Sınavı sayfası (dld.utah.gov/cdl-driving-test)."},"93":{"q":"Utah CDL beceri sınavı, sırasıyla hangi üç bölümden oluşur?","options":["Sürüş öncesi araç muayenesi, temel kontrol becerileri ve yolda sürüş","Yazılı sınav, temel kontrol becerileri ve yolda sürüş","Sürüş öncesi muayene, hava freni sınavı ve yolda sürüş","Temel kontrol becerileri, yolda sürüş ve son bir yazılı sınav"],"explanation":"Utah'nın CDL beceri sınavının üç bölümü vardır: sürüş öncesi araç muayenesi, temel kontrol becerileri sınavı ve yolda sürüş sınavı. Yazılı sınavlar beceri sınavından ayrıdır. Kaynak: Utah DLD CDL Sürüş Beceri Sınavı sayfası (dld.utah.gov/cdl-driving-test)."},"94":{"q":"Utah beceri sınavının sürüş öncesi muayene bölümü öncelikle neyi değerlendirir?","options":["Aracın sürülmeye güvenli olup olmadığına dair bilginizi","Aracı bir rampaya geri geri sürme yeteneğinizi","Yoğun trafikteki tepki sürenizi","Trafik yasalarına dair yazılı bilginizi"],"explanation":"Sürüş öncesi muayene, başvuranın aracın sürülmeye güvenli olup olmadığına dair bilgisini sınar, motor, çekici, römork, ışıklar, göstergeler, güvenlik ekipmanı ve varsa hava frenleri gibi öğeleri kapsar. Kaynak: Utah DLD CDL Sürüş Beceri Sınavı sayfası (dld.utah.gov/cdl-driving-test)."},"95":{"q":"Utah CDL beceri sınavının temel kontrol becerileri bölümünü geçmek için kaç hata puanı biriktirebilirsiniz?","options":["Sekiz veya daha az hata puanı","On iki veya daha az hata puanı","Otuz veya daha az hata puanı","Sıfır hata puanı"],"explanation":"Utah'nın temel kontrol becerileri sınavı (ileri durma, düz çizgide geri gitme, ileri ofset takip, ters ofset geri gitme) geçmek için sekiz veya daha az hata puanı gerektirir. Yolda sürüş sınavı 30'a kadar izin verir. Kaynak: Utah DLD CDL Sürüş Beceri Sınavı sayfası (dld.utah.gov/cdl-driving-test)."},"96":{"q":"Utah CDL beceri sınavının yolda sürüş bölümünü geçmek için kaç hata puanı biriktirebilirsiniz?","options":["Otuz veya daha az hata puanı","Sekiz veya daha az hata puanı","On beş veya daha az hata puanı","Elli veya daha az hata puanı"],"explanation":"Çoğu trafik durumunda sürmek için minimum becerilere sahip olup olmadığınızı kontrol eden Utah'nın yolda sürüş sınavı, geçmek için 30 veya daha az hata puanı gerektirir. Temel kontrol becerileri sınavı yalnızca sekize izin verir. Kaynak: Utah DLD CDL Sürüş Beceri Sınavı sayfası (dld.utah.gov/cdl-driving-test)."},"97":{"q":"Utah, bir başvuranın CDL beceri (sürüş) sınavına girebilmesi için ne sağlamasını gerektirir?","options":["Doğru sınıfta, kendinize ait tescilli ve yola hazır bir araç","Sürücü Belgesi Bölümü tarafından sağlanan bir araç","Bir UDOT araç havuzundan ödünç alınan bir araç","Yalnızca geçerli bir CLP, çünkü aracı eyalet sağlar"],"explanation":"Utah, başvuranın aranan CDL sınıfını temsil eden, kendine ait tescilli ve yola hazır bir araç getirmesini gerektirir. DLD test araçları sağlamaz. Kaynak: Utah DLD CDL Sürüş Beceri Sınavı sayfası (dld.utah.gov/cdl-driving-test)."},"98":{"q":"Bir Utah CDL sahibi, standart yenileme döngüsü altında ehliyeti ne sıklıkla yenilemelidir?","options":["Her beş yılda bir","Her dört yılda bir","Her sekiz yılda bir","Her iki yılda bir"],"explanation":"Utah CDL'leri beş yıllık bir yenileme döngüsü izler ve her yenileme, güncellenmiş bir başvuru ile birlikte güncel öz-sertifikasyon ve tıbbi belgeleri gerektirir. Kaynak: Utah DLD CDL yenileme bilgileri (dld.utah.gov) ve Utah Uniform Commercial Driver License Act, UCA 53-3-400 ve devamı."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal de un vehículo comercial y su carga en las carreteras de Utah sin un permiso?","options":["8 pies 6 pulgadas","8 pies 0 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"Utah limita el ancho del vehículo a 8 pies 6 pulgadas (102 pulgadas), medido de extremo a extremo en los puntos más anchos, con o sin carga. Fuente: Utah Admin. Code R909-2-4; página de Altura, Ancho y Largo Legales de UDOT."},"1":{"q":"¿Cuál es la altura máxima legal para un vehículo y su carga en las carreteras de Utah sin un permiso de sobredimensión?","options":["14 pies","13 pies 6 pulgadas","15 pies","13 pies"],"explanation":"La altura máxima legal en Utah es de 14 pies, medida desde la superficie nivelada de la carretera hasta la parte superior de la carga o del vehículo. Fuente: Utah Admin. Code R909-2-4; página de Altura, Ancho y Largo Legales de UDOT."},"2":{"q":"¿Cuál es el peso bruto vehicular máximo legal en las carreteras de Utah sin un permiso de sobrepeso?","options":["80,000 libras","78,000 libras","84,000 libras","76,000 libras"],"explanation":"Utah fija el peso bruto vehicular legal máximo en 80,000 libras, en consonancia con el límite federal, sujeto a los límites por eje y a la fórmula de puente. Fuente: Utah Code 72-7-404; emisión de permisos de tamaño/peso de UDOT."},"3":{"q":"En las carreteras de Utah, ¿cuál es la carga máxima legal sobre un solo eje sin un permiso?","options":["20,000 libras","18,000 libras","22,400 libras","24,000 libras"],"explanation":"Utah limita un solo eje a 20,000 libras. Fuente: Utah Code 72-7-404(1); Utah Admin. Code R909-2."},"4":{"q":"En las carreteras de Utah, ¿cuál es la carga máxima legal sobre un grupo de ejes tándem sin un permiso?","options":["34,000 libras","32,000 libras","36,000 libras","40,000 libras"],"explanation":"Utah limita un eje tándem a 34,000 libras. Fuente: Utah Code 72-7-404(1); emisión de permisos de tamaño/peso de UDOT."},"5":{"q":"¿Cuál es el largo máximo legal de un vehículo automotor único (rígido) en las carreteras de Utah?","options":["45 pies","40 pies","53 pies","48 pies"],"explanation":"Un vehículo automotor único en Utah no puede exceder los 45 pies de largo, excluyendo los voladizos. Fuente: Utah Admin. Code R909-2-4."},"6":{"q":"¿Cuál es el largo máximo legal de un semirremolque operado en una combinación de tractor con semirremolque en las carreteras de Utah?","options":["53 pies","48 pies","57 pies","45 pies"],"explanation":"Utah permite un semirremolque de hasta 53 pies de largo en una combinación de tractor con semirremolque. Fuente: Utah Admin. Code R909-2-4; Altura, Ancho y Largo Legales de UDOT."},"7":{"q":"Según la ley de Utah, ¿cuánto puede sobresalir una carga más allá del FRENTE de la unidad motriz antes de que se requiera un permiso de sobredimensión?","options":["3 pies","4 pies","5 pies","2 pies"],"explanation":"Un vehículo no puede llevar una carga que sobresalga más de 3 pies por delante del frente de la unidad motriz sin un permiso. Fuente: disposición sobre voladizos de Utah Admin. Code R909-2-4."},"8":{"q":"Según la ley de Utah, ¿cuánto puede sobresalir una carga más allá de la PARTE TRASERA de la plataforma o caja antes de que se requiera un permiso de sobredimensión?","options":["6 pies","4 pies","8 pies","3 pies"],"explanation":"Una carga no puede sobresalir más de 6 pies por detrás de la parte trasera de la plataforma o caja sin un permiso. Fuente: disposición sobre voladizos de Utah Admin. Code R909-2-4."},"9":{"q":"¿Cuál es el largo combinado máximo de remolques para una combinación de doble remolque (remolques gemelos) en las carreteras de Utah?","options":["61 pies","65 pies","53 pies","68 pies"],"explanation":"Utah permite un máximo de 61 pies de largo combinado de remolques para las combinaciones de doble remolque. Fuente: Utah Admin. Code R909-2-4."},"10":{"q":"Según el Utah Code 72-7-404, ¿cuál es el peso máximo permitido sobre cualquier RUEDA individual de un vehículo?","options":["10,500 libras","8,000 libras","12,000 libras","9,000 libras"],"explanation":"Utah prohíbe operar un vehículo con un peso bruto que exceda las 10,500 libras sobre una rueda. Fuente: Utah Code 72-7-404(1)."},"11":{"q":"¿Qué fórmula utiliza Utah para determinar el peso bruto permitido sobre un grupo de ejes consecutivos?","options":["La fórmula de puente federal: W = 500[LN/(N-1) + 12N + 36]","El peso bruto dividido entre el número de llantas","20,000 libras multiplicadas por el número de ejes","La suma de las capacidades de los ejes menos 10 por ciento"],"explanation":"Utah adopta la fórmula de puente federal W = 500[LN/(N-1) + 12N + 36], donde W es el peso bruto, L es la distancia del grupo de ejes y N es el número de ejes. Fuente: Utah Code 72-7-404; calculadora de puente en línea de UDOT."},"12":{"q":"En la fórmula de puente de Utah W = 500[LN/(N-1) + 12N + 36], ¿qué representa la variable 'L'?","options":["La distancia en pies entre los extremos del grupo de ejes","El límite de carga legal por eje","El largo del remolque en pies","El número de ejes cargados"],"explanation":"En la fórmula de puente, L es la distancia en pies entre los ejes extremos del grupo, N es el número de ejes y W es el peso bruto resultante redondeado a las 500 libras más cercanas. Fuente: Utah Code 72-7-404."},"13":{"q":"Según el Utah Code 72-7-404, dos conjuntos consecutivos de ejes tándem pueden llevar cada uno 34,000 libras siempre que la distancia entre el primer y el último eje de los conjuntos sea de al menos cuántos pies?","options":["36 pies","30 pies","40 pies","44 pies"],"explanation":"Dos conjuntos consecutivos de ejes tándem pueden llevar cada uno 34,000 libras si la distancia total entre el primer y el último eje de los dos conjuntos es de 36 pies o más. Fuente: Utah Code 72-7-404."},"14":{"q":"¿Cuándo se requiere un permiso de sobredimensión/sobrepeso de UDOT en Utah?","options":["Cuando el vehículo o la carga excede los límites legales de tamaño o peso del Utah Code 72-7-402 y 72-7-404","Solo al cruzar una línea estatal hacia Utah","Solo para cargas de más de 200,000 libras","Solo al circular por carreteras interestatales"],"explanation":"Se requiere un permiso de UDOT siempre que un vehículo o carga exceda los límites legales de tamaño o peso establecidos en el Utah Code 72-7-402 (tamaño) y 72-7-404 (peso). Fuente: Disposiciones de Sobredimensión y Sobrepeso de UDOT; Utah Code 72-7-406."},"15":{"q":"¿Cómo emite UDOT normalmente los permisos de sobredimensión/sobrepeso de Utah?","options":["Por viaje único, semestral o anual","Solo como permisos vitalicios","Solo como permisos de viaje único","Solo como permisos mensuales"],"explanation":"UDOT emite permisos de sobredimensión/sobrepeso por viaje único, semestral o anual, obtenidos a través del sistema de emisión de permisos en línea (MCS) de UDOT. Fuente: Disposiciones de Sobredimensión y Sobrepeso de UDOT; Utah Admin. Code R909-2-8."},"16":{"q":"Un permiso de carga DIVISIBLE con sobrepeso en Utah generalmente está disponible para un vehículo o combinación registrado para qué rango de peso bruto?","options":["78,001 a 80,000 libras","60,000 a 70,000 libras","80,001 a 90,000 libras","70,000 a 78,000 libras"],"explanation":"El permiso de carga divisible con sobrepeso de Utah aplica a vehículos o combinaciones debidamente registrados para 78,001 a 80,000 libras y aún debe cumplir con la fórmula de puente y los límites legales por eje. Fuente: Utah Admin. Code R909-2-21; Disposiciones de Carga Divisible con Sobrepeso de UDOT."},"17":{"q":"Para las operaciones de camiones de heno en Utah, dos rollos o pacas de heno pueden transportarse lado a lado bajo un permiso de sobredimensión no divisible solo si su ancho combinado no excede de cuánto?","options":["10 pies","8 pies 6 pulgadas","12 pies","14 pies"],"explanation":"Utah permite que las combinaciones de camiones de heno transporten dos rollos o pacas lado a lado cuando su ancho combinado es de 10 pies o menos y se cuenta con un permiso de sobredimensión no divisible válido. Fuente: disposiciones agrícolas (camión de heno) de UDOT/Utah Admin. Code R909-2."},"18":{"q":"En una carretera típica de Utah que NO es una ruta dividida/interestatal, ¿a partir de qué ancho una carga de sobredimensión generalmente requiere un vehículo piloto/escolta?","options":["Más de 12 pies","Más de 8 pies 6 pulgadas","Más de 14 pies","Más de 16 pies"],"explanation":"En las carreteras de Utah de dos carriles (no divididas), generalmente se requiere una escolta cuando el ancho de la carga excede los 12 pies; en las carreteras divididas/interestatales el umbral es de más de 14 pies. Fuente: disposiciones de escolta de UDOT/Utah Admin. Code R909-2."},"19":{"q":"Bajo las disposiciones de permisos de sobrepeso no divisible de Utah, ¿hasta qué peso máximo por eje único puede autorizar UDOT para una carga no divisible?","options":["29,000 libras","24,000 libras","34,000 libras","20,000 libras"],"explanation":"UDOT puede emitir permisos de sobrepeso para cargas no divisibles de hasta 29,000 libras sobre un solo eje, 50,000 libras sobre un tándem y un GVW autorizado de hasta 125,000 libras. Fuente: Disposiciones de Sobredimensión y Sobrepeso de UDOT; Utah Admin. Code R909-2."},"20":{"q":"En Utah, ¿qué clase de CDL se requiere para operar un vehículo combinado con una Capacidad de Peso Bruto Combinado de 26,001 libras o más, donde la unidad remolcada tiene una capacidad superior a 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Utah emite una CDL Clase A para vehículos combinados con un GCWR de 26,001 lbs o más cuando la unidad remolcada excede los 10,000 lbs de GVWR (por ejemplo, un tractocamión con remolque). Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info) y el Manual de CDL de Utah."},"21":{"q":"Un conductor de Utah opera un vehículo único (como un camión volquete grande o un autobús) con una Capacidad de Peso Bruto Vehicular de 26,001 libras o más y sin unidad remolcada. ¿Qué clase de CDL requiere esto?","options":["Clase C","Clase B","Clase A","Clase E"],"explanation":"Una CDL Clase B de Utah cubre un vehículo único con un GVWR de 26,001 lbs o más que no tiene unidad remolcada (o que remolca una unidad de 10,000 lbs o menos). Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"22":{"q":"Según las reglas de Utah, una CDL Clase C aplica a un vehículo con un GVWR inferior a 26,001 libras cuando está diseñado para transportar al menos cuántos pasajeros, incluido el conductor?","options":["10 pasajeros","12 pasajeros","16 pasajeros","24 pasajeros"],"explanation":"Utah define la Clase C como un vehículo de menos de 26,001 lbs de GVWR que transporta 16 o más pasajeros incluido el conductor, o que lleva rótulos (placards) por materiales peligrosos. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"23":{"q":"¿Cuál es la edad mínima para obtener una CDL de Utah para operación intraestatal (conducir solo dentro de Utah)?","options":["16 años","18 años","19 años","21 años"],"explanation":"Utah permite una CDL a los 18 años solo para conducir de forma intraestatal. Los conductores menores de 21 años están restringidos a operar dentro de Utah. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"24":{"q":"¿Cuál es la edad mínima requerida para tener una CDL de Utah válida para operación interestatal (conducir cruzando líneas estatales)?","options":["18 años","19 años","20 años","21 años"],"explanation":"Las reglas federales adoptadas por Utah exigen que un conductor tenga al menos 21 años para operar un vehículo automotor comercial en el comercio interestatal. Los conductores de 18 a 20 años están limitados a la operación intraestatal. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info); 49 CFR 391.11."},"25":{"q":"Un titular de CDL de Utah de 19 años tiene una restricción K. ¿Cuál de los siguientes endosos es ELEGIBLE para obtener este conductor?","options":["Materiales Peligrosos (H)","Pasajeros (P)","Autobús Escolar (S)","Cisterna (N)"],"explanation":"Los conductores menores de 21 años en Utah están restringidos a la operación intraestatal y NO son elegibles para los endosos H (materiales peligrosos), P (pasajeros) ni S (autobús escolar). El endoso N (cisterna) no está en esa lista de prohibidos. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"26":{"q":"¿Qué endoso necesita un conductor de Utah para transportar materiales peligrosos en cantidades que requieren rótulos (placards)?","options":["Endoso N","Endoso T","Endoso H","Endoso X"],"explanation":"El endoso H (Materiales Peligrosos) es requerido para transportar HazMat en cantidades que requieren rótulos. También requiere una verificación de antecedentes de evaluación de amenazas a la seguridad de la TSA. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"27":{"q":"Antes de que Utah emita un endoso de Materiales Peligrosos (H), el solicitante debe aprobar cuál evaluación adicional?","options":["Una verificación de antecedentes de evaluación de amenazas a la seguridad de la TSA federal","Un examen de polígrafo administrado por el estado","Un examen de la vista por un oftalmólogo","Un curso de rehabilitación de drogas patrocinado por el empleador"],"explanation":"El endoso H requiere aprobar una evaluación de amenazas a la seguridad / verificación de antecedentes de la TSA (Administración de Seguridad en el Transporte) conforme a la ley federal, además del examen de conocimientos sobre HazMat. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info); 49 CFR 1572."},"28":{"q":"Un conductor de Utah quiere remolcar dobles y triples remolques. ¿Qué endoso se requiere y en qué clase de CDL puede llevarse?","options":["Endoso T, disponible solo en una CDL Clase A","Endoso N, disponible en Clase A o B","Endoso T, disponible solo en una CDL Clase B","Endoso P, disponible en cualquier clase"],"explanation":"El endoso T (Dobles/Triples) permite remolcar más de un remolque y solo puede agregarse a una CDL Clase A. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info) y el Manual de CDL de Utah."},"29":{"q":"¿Qué endoso necesita un conductor de Utah para operar un vehículo cisterna usado para transportar líquidos o gases?","options":["Endoso P","Endoso N","Endoso H","Endoso T"],"explanation":"El endoso N (Cisterna) es requerido para vehículos que transportan líquidos/gases en un tanque con una capacidad nominal individual de 119 galones o más y una capacidad nominal agregada de más de 1,000 galones. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"30":{"q":"¿Qué endoso se requiere antes de que un conductor de Utah pueda obtener el endoso de Autobús Escolar (S)?","options":["Endoso de HazMat (H)","Endoso de Cisterna (N)","Endoso de Pasajeros (P)","Endoso de Dobles/Triples (T)"],"explanation":"En Utah el endoso de Autobús Escolar (S) se agrega sobre el endoso de Pasajeros (P); el solicitante debe calificar para el P (conocimientos y habilidades) y luego aprobar los exámenes adicionales de conocimientos y habilidades del S. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"31":{"q":"¿Cuáles dos endosos requieren que un solicitante de Utah apruebe un examen de HABILIDADES de manejo además de un examen escrito de conocimientos?","options":["H (HazMat) y N (Cisterna)","P (Pasajeros) y S (Autobús Escolar)","T (Dobles/Triples) y N (Cisterna)","H (HazMat) y T (Dobles/Triples)"],"explanation":"En Utah los endosos P (Pasajeros) y S (Autobús Escolar) requieren cada uno un examen de habilidades de manejo en el vehículo apropiado, mientras que el H, N y T requieren solo un examen de conocimientos. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"32":{"q":"Según las reglas federales adoptadas por Utah, ¿cuánto tiempo debe tener un conductor un Permiso de Aprendiz Comercial (CLP) antes de que se le permita tomar el examen de habilidades de manejo de la CDL?","options":["7 días","14 días","30 días","60 días"],"explanation":"Un solicitante debe tener el CLP durante al menos 14 días antes de tomar el examen de habilidades de la CDL. Este es un requisito de la FMCSA aplicado por el Utah DLD. Fuente: página de Examen de Habilidades de Manejo de CDL de Utah DLD (dld.utah.gov/cdl-driving-test); 49 CFR 383.25."},"33":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Utah a partir de su fecha de emisión?","options":["90 días","180 días","1 año","2 años"],"explanation":"Un CLP de Utah es válido por 180 días (aproximadamente 6 meses). Puede renovarse una vez dentro de un período de dos años. Fuente: página de Examen Escrito de Conocimientos de CDL de Utah DLD (dld.utah.gov/cdl-written-test)."},"34":{"q":"¿Qué puntaje mínimo debe alcanzar un solicitante para aprobar un examen escrito de conocimientos de CDL de Utah (conocimientos generales o un examen de endoso)?","options":["70%","75%","80%","90%"],"explanation":"Utah requiere un puntaje de 80% para aprobar cualquier examen escrito de conocimientos de CDL. Fuente: página de Examen Escrito de Conocimientos de CDL de Utah DLD (dld.utah.gov/cdl-written-test)."},"35":{"q":"¿Qué examen de conocimientos debe aprobar PRIMERO un solicitante de Utah para que se le emita un Permiso de Aprendiz Comercial?","options":["El examen de conocimientos generales de 50 preguntas","El examen de frenos de aire de 25 preguntas","El examen de vehículos combinados de 20 preguntas","El examen de HazMat de 30 preguntas"],"explanation":"Aprobar el examen de conocimientos generales de 50 preguntas (con 80%) resulta en la emisión de un CLP, que es válido por 180 días. Fuente: página de Examen Escrito de Conocimientos de CDL de Utah DLD (dld.utah.gov/cdl-written-test)."},"36":{"q":"La Capacitación para Conductores de Nivel Inicial (ELDT) requerida para los solicitantes primerizos de Clase A o Clase B de Utah debe completarse a través de un proveedor que esté:","options":["Aprobado por el distrito escolar local","Incluido en el Registro de Proveedores de Capacitación de la FMCSA","Certificado por la Comisión Tributaria del Estado de Utah","Acreditado por el Departamento de Educación de los EE. UU."],"explanation":"La ELDT debe completarse a través de un proveedor incluido en el Registro de Proveedores de Capacitación (TPR) de la FMCSA antes del examen de habilidades. La ELDT aplica a solicitantes primerizos de Clase A/B, ascensos de Clase B a A, y primeros endosos H, P y S. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info); 49 CFR Parte 380."},"37":{"q":"¿Para cuál de los siguientes NO requiere Utah la Capacitación para Conductores de Nivel Inicial (ELDT)?","options":["Un solicitante primerizo de CDL Clase A","Un solicitante primerizo del endoso de HazMat (H)","Agregar un endoso de Cisterna (N)","Un solicitante primerizo del endoso de Autobús Escolar (S)"],"explanation":"La ELDT federal aplica a las CDL primerizas de Clase A/B, los ascensos de Clase B a A, y los primeros endosos H, P y S. Los endosos N (cisterna) y T (dobles/triples) no están sujetos a la ELDT. Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info); 49 CFR Parte 380."},"38":{"q":"Al solicitar una CDL de Utah, ¿qué combinación de documentos debe presentar un solicitante a la División de Licencias de Conducir?","options":["Prueba de identidad y presencia legal, número completo de Seguro Social, y dos documentos que prueben residencia en Utah","Solo un pasaporte","Un diploma de preparatoria y una factura de servicios","Solo un registro vehicular y prueba de seguro"],"explanation":"El Utah DLD requiere prueba de identidad/presencia legal, el número completo de Seguro Social del solicitante, y dos documentos que prueben residencia en Utah (además de un certificado médico válido cuando se requiera). Fuente: página de Información de CDL de Utah DLD (dld.utah.gov/cdl-info)."},"39":{"q":"Un solicitante de CDL de Utah que conduce solo dentro de Utah y transporta carga no exenta, y que tiene una tarjeta médica del DOT válida, ¿bajo qué categoría debe autocertificarse?","options":["Interestatal No Exento","Interestatal Exento","Intraestatal No Exento","Intraestatal Exento"],"explanation":"Utah utiliza cuatro categorías de autocertificación. Un conductor que opera solo dentro de Utah en comercio no exento se certifica como Intraestatal No Exento. Las categorías interestatales aplican a la conducción que cruza líneas estatales; las categorías exentas aplican a operaciones específicas exentas a nivel federal. Fuente: página de Autocertificación de CDL de Utah DLD (dld.utah.gov/cdl-self-certification)."},"40":{"q":"En Utah, ¿cuál es la concentración de alcohol en sangre/aliento (BAC) en la que, o por encima de la cual, una persona tiene prohibido operar un vehículo automotor comercial (CMV)?","options":["0.04","0.08","0.02","0.05"],"explanation":"El Utah Code 53-3-414(1)(a)(ii) tipifica como delito mayor conducir un CMV con una concentración de alcohol de 0.04 gramos o más. El límite de 0.08 aplica solo a la conducción no comercial. Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"41":{"q":"Un conductor con CDL de Utah es condenado por un PRIMER delito mayor (como conducir un CMV con un BAC de 0.04 o más) y NO estaba transportando materiales peligrosos con rótulos. ¿Cuál es el período mínimo de descalificación de la CDL?","options":["1 año","60 días","3 años","6 meses"],"explanation":"Bajo el Utah Code 53-3-414(1)(a), un primer delito mayor resulta en una descalificación de no menos de un año. Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"42":{"q":"Si un conductor con CDL de Utah comete un primer delito mayor (como un DUI) MIENTRAS transporta un material peligroso que debe llevar rótulos, ¿a qué período aumenta la descalificación mínima?","options":["3 años","1 año","2 años","De por vida"],"explanation":"El Utah Code 53-3-414(2) eleva la descalificación mínima por un primer delito mayor a no menos de tres años cuando el delito ocurre mientras se transportan materiales peligrosos con rótulos. Fuente: Utah Code 53-3-414."},"43":{"q":"¿Qué le sucede a un titular de CDL de Utah que es condenado por un SEGUNDO delito mayor que surge de un incidente separado?","options":["Descalificado de por vida para conducir un CMV","Descalificado por 3 años","Descalificado por 1 año","Descalificado por 120 días"],"explanation":"El Utah Code 53-3-414(3)(a) establece que dos o más delitos mayores provenientes de incidentes separados resultan en una descalificación de por vida para conducir un CMV. Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"44":{"q":"Bajo las reglas de consentimiento implícito de Utah, ¿cuál es la consecuencia para un conductor con CDL que se niega a someterse a una prueba química para determinar la concentración de alcohol o drogas?","options":["Se trata como un delito mayor, descalificando la CDL por al menos 1 año","Solo una advertencia en la primera negativa","Una descalificación de 60 días","Una multa de $500 sin descalificación"],"explanation":"El Utah Code 53-3-414(1)(a)(vi) incluye la negativa a someterse a una prueba química como un delito mayor, que conlleva la misma descalificación mínima de 1 año (3 años si se transporta HazMat con rótulos). Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"45":{"q":"¿Cuántas infracciones de tránsito GRAVES dentro de un período de tres años activan una descalificación de la CDL de 60 días en Utah?","options":["2","3","1","4"],"explanation":"El Utah Code 53-3-414(6)(a)(i) requiere una descalificación de no menos de 60 días por dos infracciones de tránsito graves ocurridas dentro de tres años. Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"46":{"q":"En Utah, un conductor con CDL condenado por TRES o más infracciones de tránsito graves dentro de un período de tres años es descalificado por al menos cuánto tiempo?","options":["120 días","60 días","1 año","90 días"],"explanation":"El Utah Code 53-3-414(6)(a)(ii) impone una descalificación de no menos de 120 días por tres o más infracciones de tránsito graves dentro de tres años. Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"47":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un conductor con CDL de Utah?","options":["Exceso de velocidad de 15 mph o más sobre el límite señalizado","Exceso de velocidad de 5 mph sobre el límite señalizado","Una infracción de estacionamiento","Conducir 3 mph por debajo del límite"],"explanation":"Según el Manual de CDL de Utah y la lista de códigos de infracciones (ACD) de Utah, el exceso de velocidad de 15 mph o más sobre el límite es una infracción de tránsito grave. Los excesos de velocidad menores y el estacionamiento no son graves. Fuente: Manual de CDL de Utah; 49 CFR 383.51 aplicado en Utah."},"48":{"q":"¿Qué acto cuenta como una infracción de tránsito grave que puede contribuir a una descalificación de la CDL de Utah?","options":["Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV","Usar un teléfono de manos libres mientras se conduce un CMV","Comer mientras se conduce un CMV","Escuchar la radio mientras se conduce un CMV"],"explanation":"Utah sigue la lista federal de infracciones graves (49 CFR 383.51): enviar mensajes de texto o usar un teléfono móvil de mano mientras se opera un CMV es una infracción de tránsito grave. El uso de manos libres no lo es. Fuente: Manual de CDL de Utah; 49 CFR 383.51."},"49":{"q":"Un conductor con CDL de Utah es condenado por una PRIMERA violación de una orden de fuera de servicio (OOS) mientras conducía un CMV (sin HazMat, no un autobús grande). ¿Cuál es la descalificación mínima bajo la ley de Utah?","options":["180 días","90 días","60 días","1 año"],"explanation":"El Utah Code 53-3-414(7)(a)(i) fija la descalificación mínima por una primera violación de una orden de fuera de servicio en 180 días, lo cual excede el mínimo federal de 90 días. Fuente: Utah Code 53-3-414."},"50":{"q":"Además de la descalificación, ¿qué SANCIÓN CIVIL mínima impone la ley de Utah a un conductor con CDL condenado por una PRIMERA violación de una orden de fuera de servicio?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"El Utah Code 53-3-414(7)(b) requiere una sanción civil de no menos de $2,500 por una primera violación de una orden de fuera de servicio. Fuente: Utah Code 53-3-414."},"51":{"q":"Bajo la ley de Utah, la sanción civil mínima por una SEGUNDA o posterior violación de una orden de fuera de servicio de un conductor con CDL es de al menos:","options":["$5,000","$2,500","$3,500","$10,000"],"explanation":"El Utah Code 53-3-414(7)(c) fija la sanción civil en no menos de $5,000 por una segunda o posterior violación de una orden de fuera de servicio. Fuente: Utah Code 53-3-414."},"52":{"q":"Un conductor con CDL de Utah es condenado por una SEGUNDA violación de una orden de fuera de servicio, en un incidente separado, dentro de un período de 10 años. ¿Cuál es la descalificación mínima?","options":["2 años","1 año","180 días","3 años"],"explanation":"El Utah Code 53-3-414(7)(a)(ii) requiere una descalificación de no menos de dos años por una segunda violación de una orden de OOS en incidentes separados dentro de cualquier período de 10 años. Fuente: Utah Code 53-3-414."},"53":{"q":"Bajo la ley de Utah, una TERCERA o más violación de una orden de fuera de servicio en incidentes separados dentro de un período de 10 años resulta en una descalificación de:","options":["3 a 5 años","1 a 2 años","180 días a 1 año","10 años"],"explanation":"El Utah Code 53-3-414(7)(a)(iii) requiere una descalificación de no menos de tres años pero no más de cinco años por tres o más violaciones de órdenes de OOS dentro de cualquier período de 10 años. Fuente: Utah Code 53-3-414."},"54":{"q":"Un conductor con CDL de Utah es condenado por una PRIMERA violación en un cruce a nivel de ferrocarril y carretera mientras conducía un CMV. ¿Cuál es la descalificación mínima?","options":["60 días","30 días","120 días","1 año"],"explanation":"El Utah Code 53-3-414(9)(a) impone una descalificación de no menos de 60 días por una primera violación en un cruce a nivel de ferrocarril y carretera. Fuente: Utah Code 53-3-414; Manual de CDL de Utah."},"55":{"q":"Por una SEGUNDA violación en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años (incidentes separados), un conductor con CDL de Utah es descalificado por al menos:","options":["120 días","60 días","1 año","90 días"],"explanation":"El Utah Code 53-3-414(9)(b) requiere una descalificación de no menos de 120 días por una segunda violación en un cruce a nivel dentro de cualquier período de tres años. Fuente: Utah Code 53-3-414."},"56":{"q":"Un conductor con CDL de Utah condenado por una TERCERA o más violación en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años (incidentes separados) es descalificado por al menos:","options":["1 año","120 días","60 días","3 años"],"explanation":"El Utah Code 53-3-414(9)(c) requiere una descalificación de no menos de un año por tres o más violaciones en cruces a nivel dentro de cualquier período de tres años. Fuente: Utah Code 53-3-414."},"57":{"q":"Si un conductor de CMV que está obligado a tener una CDL da positivo por CUALQUIER cantidad detectable de alcohol por debajo de 0.04, ¿qué medida se toma?","options":["Se le coloca fuera de servicio por 24 horas","Descalificación inmediata de la CDL por 1 año","Descalificación de la CDL por 60 días","Ninguna medida ya que está por debajo de 0.04"],"explanation":"Utah sigue la regla federal (49 CFR 392.5): un conductor de CMV con cualquier cantidad detectable de alcohol por debajo de 0.04 debe ser colocado fuera de servicio por 24 horas. Una lectura de 0.04 o más es un delito mayor. Fuente: Manual de CDL de Utah; 49 CFR 392.5."},"58":{"q":"En Utah, ¿cuál es la descalificación mínima de la CDL por usar un CMV en la comisión de un delito grave que involucre la fabricación, distribución o dispensación de una sustancia controlada?","options":["De por vida, sin posibilidad de reinstauración","1 año","3 años","10 años"],"explanation":"El Utah Code 53-3-414(5) y 414(3)(b) imponen una descalificación de por vida SIN elegibilidad para reinstauración cuando se usa un CMV en un delito grave que involucra la fabricación, distribución o dispensación de sustancias controladas. Fuente: Utah Code 53-3-414."},"59":{"q":"Un titular de CDL de Utah recibe una descalificación de por vida que es elegible para reinstauración. ¿Cuál es el período mínimo de descalificación que debe cumplirse antes de solicitar la reinstauración de la CDL?","options":["10 años","5 años","3 años","15 años"],"explanation":"El Utah Code 53-3-414(4)(a) permite que un conductor solicite la reinstauración solo después de cumplir una descalificación mínima de 10 años y completar un programa de rehabilitación aprobado que cumpla con el 49 CFR 383.51. Fuente: Utah Code 53-3-414."},"60":{"q":"Según la ley \"Cámbiate de carril\" (Move Over) de Utah, cuando un conductor comercial se aproxima a una grúa o a un vehículo de mantenimiento de carreteras detenido que muestra luces ámbar intermitentes en una autopista de varios carriles, ¿qué debe hacer el conductor?","options":["Reducir la velocidad y, si es práctico y seguro, cambiarse a un carril que no sea adyacente al vehículo detenido","Mantener la velocidad pero tocar la bocina para advertir a los trabajadores","Detenerse por completo hasta que el vehículo detenido abandone el acotamiento","Nada, porque la ley solo aplica a la policía y a las ambulancias"],"explanation":"El Utah Code 41-6a-904 (la ley \"Cámbiate de carril\") exige que un conductor que se aproxima a un vehículo de emergencia autorizado detenido, a una grúa o vehículo de remolque, o a un vehículo de mantenimiento de carreteras con luces intermitentes, reduzca la velocidad y, si circula por un carril adyacente y es práctico teniendo en cuenta la seguridad, se cambie a un carril que no esté junto al vehículo detenido. Fuente: Utah Code 41-6a-904."},"61":{"q":"La ley \"Cámbiate de carril\" de Utah (41-6a-904) especifica, ¿a qué velocidad numérica debe reducir un conductor al pasar junto a un vehículo de emergencia o de mantenimiento detenido?","options":["No se fija ningún número específico; la ley exige que el conductor 'reduzca la velocidad'","Exactamente 20 mph por debajo del límite señalado","Una velocidad fija de 25 mph sin importar el límite señalado","Exactamente 10 mph en todos los casos"],"explanation":"El Utah Code 41-6a-904 no indica una cifra fija de mph. Exige que el conductor reduzca la velocidad, deje todo el espacio que sea práctico y se cambie de carril alejándose del vehículo detenido cuando sea práctico. Fuente: Utah Code 41-6a-904."},"62":{"q":"En una carretera de Utah con más de un carril en la misma dirección, un CMV que circula por el carril izquierdo de uso general es alcanzado por un vehículo más rápido que viene detrás. ¿Qué exige la ley de Utah?","options":["Cambiarse de forma segura a un carril a la derecha y no obstaculizar el flujo libre del tránsito en el carril izquierdo","Mantener el carril porque el camión ya va al límite de velocidad señalado","Acelerar al menos 5 mph por encima del límite para despejar el carril","Moverse a la izquierda hacia el acotamiento del camellón para dejar pasar al vehículo"],"explanation":"El Utah Code 41-6a-704 establece que un conductor en el carril izquierdo de uso general que es alcanzado por otro vehículo debe ceder el paso cambiándose de forma segura a un carril a la derecha y no puede obstaculizar el movimiento ni el flujo libre del tránsito en el carril izquierdo; la infracción se considera una falta menor. Fuente: Utah Code 41-6a-704."},"63":{"q":"¿Cuál es el límite de velocidad señalado máximo que un conductor comercial puede encontrar legalmente en una autopista interestatal rural de Utah?","options":["80 mph donde esté señalado","65 mph como tope estatal para todos los camiones","70 mph máximo para cualquier vehículo","85 mph donde esté señalado"],"explanation":"Utah señala 80 mph en tramos designados de autopistas interestatales rurales (75 mph es el valor predeterminado común), el más alto del estado. Fuente: Utah Code 41-6a-601/604 y los límites señalados por el Utah DOT."},"64":{"q":"¿Cómo trata Utah los límites de velocidad de los camiones en comparación con los límites de los autos de pasajeros en la autopista interestatal?","options":["Los camiones siguen el mismo límite señalado; Utah no establece un límite de velocidad estatal más bajo aparte para camiones","Los camiones tienen un tope de 55 mph en todo el estado sin importar el límite señalado","Los camiones siempre deben circular 15 mph por debajo del límite de los autos","Los camiones están limitados a 60 mph en todas las autopistas interestatales"],"explanation":"A diferencia de estados con límites diferenciados como California, Utah no impone un límite de velocidad estatal más bajo aparte para camiones; los CMV obedecen el mismo límite señalado (hasta 80 mph). Solo aplican reducciones de velocidad para camiones señalizadas de forma local en ciertas pendientes. Fuente: Utah Code Título 41 Capítulo 6a Parte 6 y Utah DOT."},"65":{"q":"En un cruce de ferrocarril a nivel en Utah, el conductor de un autobús que transporta pasajeros o de un vehículo con carteles de HazMat debe detener el vehículo, ¿dentro de qué distancia del riel más cercano?","options":["Dentro de 50 feet pero a no menos de 15 feet del riel más cercano","Dentro de 25 feet pero a no menos de 5 feet del riel más cercano","Dentro de 100 feet pero a no menos de 50 feet del riel más cercano","Dentro de 75 feet pero a no menos de 25 feet del riel más cercano"],"explanation":"Los autobuses con pasajeros y los vehículos con carteles de HazMat deben detenerse dentro de 50 feet pero a no menos de 15 feet del riel más cercano, y luego mirar y escuchar antes de cruzar. Fuente: Manual CDL de Utah (DLD) y 49 CFR 392.10 según se aplica en Utah."},"66":{"q":"¿Cuál de estos vehículos comerciales de Utah está obligado a DETENERSE en cada cruce de ferrocarril (donde no esté exento)?","options":["Un autobús que transporta pasajeros y un vehículo que muestra carteles de HazMat","Cualquier tractocamión que transporte carga general","Solo los vehículos que pesan más de 26,001 pounds","Solo las combinaciones de triple remolque"],"explanation":"Utah sigue la regla federal: solo los autobuses que transportan pasajeros y los vehículos con carteles de HazMat deben detenerse en los cruces de ferrocarril; la mayoría de los demás CMV no están obligados a detenerse. Fuente: Manual CDL de Utah (DLD); 49 CFR 392.10."},"67":{"q":"Al detenerse en un cruce de ferrocarril con un vehículo que lleva carteles de HazMat en Utah, antes de que cualquier parte del vehículo esté sobre las vías, ¿cuál de las siguientes acciones NO debe realizar el conductor?","options":["Cambiar de marcha mientras cualquier parte del vehículo está cruzando las vías","Mirar y escuchar en ambas direcciones por si se aproxima un tren","Activar las luces intermitentes de cuatro vías al aproximarse","Elegir un punto de cruce donde el vehículo pueda despejar las vías sin detenerse"],"explanation":"El conductor de un CMV nunca debe cambiar de marcha mientras cualquier parte del vehículo esté sobre las vías, ya que un cambio fallido podría dejar el vehículo varado en el cruce. Fuente: Manual CDL de Utah (DLD), sección de cruces de ferrocarril."},"68":{"q":"En un camino de Utah de dos carriles, sin dividir y de doble sentido, un autobús escolar se detiene y muestra luces rojas intermitentes alternantes. ¿Qué debe hacer un conductor que se aproxima desde la dirección OPUESTA?","options":["Detenerse antes de llegar al autobús y permanecer detenido hasta que las luces rojas dejen de parpadear","Reducir la velocidad a 20 mph y pasar con precaución por la izquierda","Continuar normalmente porque el tránsito en sentido contrario nunca está obligado a detenerse","Detenerse solo si hay niños visiblemente en la vía"],"explanation":"El Utah Code 41-6a-1302 exige que el tránsito de ambas direcciones se detenga ante un autobús escolar que muestra luces rojas intermitentes y no avance hasta que las luces rojas cesen. Fuente: Utah Code 41-6a-1302."},"69":{"q":"Un autobús escolar está detenido con luces rojas intermitentes en el lado opuesto de un camellón elevado y ajardinado que divide la autopista. Un conductor de CMV que circula en la dirección opuesta, al otro lado de ese camellón, ¿qué está obligado a hacer según la ley de Utah?","options":["Continuar, porque aplica la excepción de autopista dividida por camellón para el tránsito en sentido opuesto","Detenerse, porque todo el tránsito siempre debe detenerse ante luces rojas intermitentes","Detenerse solo si el autobús está a menos de 100 feet","Reducir a 15 mph pero no es necesario detenerse"],"explanation":"Debido a que la autopista está dividida por una sección divisoria claramente indicada (el camellón elevado), el Utah Code 41-6a-1302 permite que el tránsito en sentido opuesto avance sin detenerse. Fuente: Utah Code 41-6a-1302."},"70":{"q":"¿Qué color de luces intermitentes del autobús escolar indica que el autobús se prepara para detenerse y que los conductores deben reducir la velocidad y prepararse para detenerse en Utah?","options":["Luces ámbar (amarillas) intermitentes alternantes","Luces rojas intermitentes alternantes","Luces azules fijas","Luces verdes intermitentes alternantes"],"explanation":"En Utah, las luces ámbar (amarillas) intermitentes advierten que el autobús está a punto de detenerse; las luces rojas intermitentes con el brazo de alto extendido exigen que el tránsito se detenga. Fuente: Utah Code 41-6a-1302; sección de autobuses escolares del Manual CDL de Utah."},"71":{"q":"Cuando un CMV está detenido en el acotamiento de una autopista dividida o de un solo sentido en Utah, ¿dónde debe colocar el conductor los tres triángulos de advertencia de emergencia?","options":["Aproximadamente a 10, 100 y 200 feet detrás del vehículo, hacia el tránsito que se aproxima","Aproximadamente a 10, 50 y 150 feet detrás del vehículo, hacia el tránsito que se aproxima","Aproximadamente a 25, 75 y 125 feet detrás del vehículo, hacia el tránsito que se aproxima","Aproximadamente a 50, 100 y 250 feet detrás del vehículo, hacia el tránsito que se aproxima"],"explanation":"En una autopista dividida o de un solo sentido, los triángulos se colocan aproximadamente a 10 ft, 100 ft y 200 ft hacia el tránsito que se aproxima. Fuente: Manual CDL de Utah (DLD); 49 CFR 392.22."},"72":{"q":"Después de detener un CMV en una vía de Utah, ¿dentro de cuántos minutos debe el conductor tener colocados los dispositivos de advertencia de emergencia (triángulos)?","options":["Dentro de 10 minutos","Dentro de 2 minutos","Dentro de 5 minutos","Dentro de 30 minutos"],"explanation":"Los dispositivos de advertencia deben colocarse dentro de los 10 minutos posteriores a la detención. Fuente: Manual CDL de Utah (DLD); 49 CFR 392.22."},"73":{"q":"En un camino de Utah recto, plano, sin dividir y de doble sentido, ¿dónde se colocan los tres triángulos de advertencia para un CMV detenido?","options":["A 10 feet hacia atrás, a 100 feet hacia atrás y a 100 feet hacia el frente del vehículo","A 10 feet, 200 feet y 300 feet, todos hacia atrás","A 25 feet hacia atrás, a 50 feet hacia atrás y a 75 feet hacia el frente","A 100 feet hacia atrás, a 100 feet hacia el frente y uno en la defensa"],"explanation":"En un camino de doble sentido, coloque un triángulo a aproximadamente 10 ft hacia atrás, uno a aproximadamente 100 ft hacia atrás y uno a aproximadamente 100 ft hacia el frente (hacia el tránsito en ambas direcciones). Fuente: Manual CDL de Utah (DLD); 49 CFR 392.22."},"74":{"q":"¿Cuál es el ANCHO máximo del vehículo que puede circular por las carreteras de Utah sin un permiso de sobredimensión?","options":["8 feet 6 inches","8 feet 0 inches","10 feet 0 inches","9 feet 6 inches"],"explanation":"El ancho máximo legal en Utah sin un permiso es de 8 feet 6 inches (102 inches); cualquier cosa más ancha requiere un permiso de sobredimensión del UDOT. Fuente: Permisos de Tamaño/Peso del Utah DOT; Utah Admin. Code R909-2."},"75":{"q":"¿Cuál es la ALTURA máxima del vehículo permitida en las carreteras de Utah antes de que se requiera un permiso de sobredimensión?","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"explanation":"Utah permite hasta 14 feet de altura sin un permiso, medidos desde la superficie del camino hasta la parte superior de la carga, lo cual es más alto que el límite de 13'6\" común en muchos estados. Fuente: Permisos de Tamaño/Peso del Utah DOT; Utah Admin. Code R909-2."},"76":{"q":"Un vehículo combinado en Utah tiene un peso bruto de 86,000 pounds y mide 9 feet de ancho. ¿Qué se requiere antes de que pueda operar en las carreteras de Utah?","options":["Un permiso especial de transporte de sobredimensión/sobrepeso del UDOT","Nada, porque está por debajo del tope federal interestatal","Solo un letrero de carga ancha, sin permiso","Solo un endoso de HazMat en la licencia del conductor"],"explanation":"Las cargas que exceden las 80,000 lb de peso bruto o que son más anchas que 8'6\" superan los límites legales de Utah y requieren un permiso de sobredimensión/sobrepeso del UDOT (de un solo viaje, semestral o anual). Fuente: Permisos de Tamaño/Peso del Utah DOT; Utah Admin. Code R909-2."},"77":{"q":"En pendientes empinadas de montaña en Utah, como la I-80 a través de Parleys Canyon, ¿qué elemento se proporciona específicamente para detener un camión pesado cuyos frenos han fallado?","options":["Una rampa de escape para camiones sin frenos","Una báscula obligatoria de pesaje en movimiento","Un carril HOV reversible","Una caseta de peaje exclusiva para camiones"],"explanation":"Las pendientes de Utah como la I-80 en Parleys Canyon cuentan con una rampa de escape para camiones sin frenos, además de zonas señalizadas de verificación de frenos al aproximarse al descenso, por lo que los conductores deben descender en una marcha baja y usar la técnica de frenado adecuada. Fuente: Utah DOT; Manual CDL de Utah (conducción en montaña)."},"78":{"q":"Antes de una bajada larga en las montañas de Utah, ¿cuál es la práctica más segura para que un conductor comercial controle la velocidad?","options":["Seleccionar una marcha baja y depender del freno de motor/freno auxiliar antes de comenzar a bajar","Permanecer en marcha alta y usar continuamente los frenos de servicio hasta abajo","Poner en neutro para rodar por inercia y ahorrar combustible en la bajada","Tomar velocidad adicional en la cima para poder superar la siguiente subida"],"explanation":"La guía de conducción en montaña de Utah indica elegir una marcha baja y usar el freno de motor/freno auxiliar antes del descenso para que los frenos de servicio no se sobrecalienten; las zonas de verificación de frenos en pendientes como Parleys Canyon respaldan esto. Fuente: Manual CDL de Utah (DLD), conducción en montaña y frenado en bajada."},"79":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Utah?","options":["La Utah Driver License Division (DLD)","El Departamento de Vehículos Motorizados de Utah (DMV)","El Departamento de Transporte de Utah (UDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Utah, las CDL son emitidas por la Utah Driver License Division (DLD), que forma parte del Departamento de Seguridad Pública. El DMV se encarga del registro de vehículos, el UDOT se encarga de los caminos y los permisos de sobredimensión/sobrepeso, y la FMCSA es el regulador federal. Fuente: página de Información sobre la CDL de la DLD de Utah (dld.utah.gov/cdl-info)."},"80":{"q":"¿Cuántas preguntas tiene el examen escrito de conocimientos generales de la CDL de Utah?","options":["50 preguntas","30 preguntas","40 preguntas","100 preguntas"],"explanation":"El examen escrito de conocimientos generales de Utah consta de 50 preguntas de opción múltiple, todas basadas en el Manual CDL. Fuente: página del Examen Escrito de Conocimientos de la CDL de la DLD de Utah (dld.utah.gov/cdl-written-test) y el Manual CDL 2025."},"81":{"q":"¿Cuál es la calificación mínima que debe obtener para aprobar un examen de conocimientos de la CDL de Utah?","options":["80%","70%","75%","90%"],"explanation":"Utah requiere 80% para aprobar cada examen de conocimientos de la CDL (40 de 50 en el examen de conocimientos generales). Esto coincide con el estándar federal del 49 CFR 383.135. Fuente: página del Examen Escrito de Conocimientos de la CDL de la DLD de Utah (dld.utah.gov/cdl-written-test)."},"82":{"q":"¿En qué idioma se administran los exámenes de conocimientos de la CDL de Utah?","options":["Solo en inglés; los materiales de traducción están prohibidos","En inglés o español, a elección del solicitante","En cualquier idioma con un intérprete aprobado presente","En inglés, con diccionarios de traducción permitidos"],"explanation":"Utah administra todos los exámenes de conocimientos de la CDL únicamente en inglés, y el uso de materiales de traducción está estrictamente prohibido. Los exámenes también son a libro cerrado. Fuente: página del Examen Escrito de Conocimientos de la CDL de la DLD de Utah (dld.utah.gov/cdl-written-test)."},"83":{"q":"Antes de presentar cualquier examen escrito de conocimientos de la CDL en Utah, ¿qué debe tener ya el solicitante?","options":["Un certificado vigente de examinador médico del DOT","Un examen de habilidades en carretera completado","Un año de experiencia con CDL fuera del estado","Una verificación de antecedentes de materiales peligrosos"],"explanation":"Utah exige que los solicitantes tengan un certificado vigente de examinador médico (MEC) antes de presentar los exámenes escritos de conocimientos. El examen de habilidades viene después, y la verificación de antecedentes de hazmat aplica únicamente para ese endoso. Fuente: página de Información sobre la CDL de la DLD de Utah (dld.utah.gov/cdl-info)."},"84":{"q":"¿Cuánto tiempo es válido como máximo un certificado de examinador médico del DOT para un titular de CDL de Utah?","options":["Hasta 24 months","Hasta 12 months","Hasta 36 months","Hasta 6 months"],"explanation":"Un examen físico del DOT (certificado de examinador médico) es válido por hasta 24 months en Utah, aunque un examinador puede emitirlo por un período más corto cuando hace seguimiento de una condición médica. Fuente: página de Información sobre la CDL de la DLD de Utah (dld.utah.gov/cdl-info)."},"85":{"q":"¿Quién está autorizado para realizar el examen físico del DOT a un solicitante de CDL de Utah?","options":["Un examinador médico que figure en el National Registry of Certified Medical Examiners de la FMCSA","Cualquier médico con licencia elegido por el solicitante","Un empleado de la DLD en la oficina de exámenes","Únicamente un médico empleado por el UDOT"],"explanation":"El examen físico del DOT debe ser realizado por un examinador médico certificado que figure en el National Registry of Certified Medical Examiners de la FMCSA. No califica cualquier médico. Fuente: página de Información sobre la CDL de la DLD de Utah y el National Registry de la FMCSA."},"86":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL de Utah?","options":["Cuatro categorías, eligiendo exactamente una","Dos categorías, eligiendo exactamente una","Tres categorías, eligiendo exactamente una","Cinco categorías, eligiendo exactamente una"],"explanation":"Utah utiliza cuatro categorías de autocertificación, y un conductor solo puede certificarse en una. Son: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate y Excepted Intrastate. Fuente: página de Autocertificación de la CDL de la DLD de Utah (dld.utah.gov/cdl-self-certification)."},"87":{"q":"Un conductor de Utah que opera únicamente dentro de Utah y que debe cumplir con los requisitos de calificación estatales, ¿bajo cuál categoría se autocertificaría?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Exempt Federal"],"explanation":"La categoría Non-Excepted Intrastate cubre a los conductores que operan únicamente dentro de Utah y que deben cumplir con los estándares estatales de calificación médica (UCA 53-3-303.5); conlleva una restricción de solo Utah. Las categorías interestatales aplican al comercio a nivel nacional. Fuente: página de Autocertificación de la CDL de la DLD de Utah (dld.utah.gov/cdl-self-certification)."},"88":{"q":"¿En cuáles de estos momentos debe un conductor de CDL de Utah presentar una autocertificación (y un certificado médico vigente) ante la DLD?","options":["Al emitirse cualquier CDL, cuando cambia la condición de conducción y en cada renovación","Solo una vez, la primera vez que se emite una CDL","Solo al cambiar de empleador","Solo al agregar un nuevo endoso"],"explanation":"Para que el proceso de certificación médica se mantenga completo, el formulario de autocertificación debe presentarse ante la DLD al emitirse cualquier CDL, si cambia el estatus de la condición de conducción y en cada renovación de la CDL. Fuente: página de Información sobre la CDL de la DLD de Utah (dld.utah.gov/cdl-info)."},"89":{"q":"¿Qué capacitación deben completar en Utah los solicitantes primerizos de CDL Clase A o Clase B antes de obtener la licencia?","options":["Entry-Level Driver Training (ELDT) de un proveedor registrado","Una pasantía estatal de 160 horas","Un curso de manejo defensivo aprobado por el UDOT","Seis meses de capacitación supervisada por el empleador"],"explanation":"Las reglas federales y de Utah exigen que los solicitantes primerizos de Clase A/B (y los solicitantes primerizos de endosos de autobús escolar, de pasajeros o de hazmat) completen el Entry-Level Driver Training (ELDT) de un proveedor que figure en el FMCSA Training Provider Registry antes de obtener la CDL. Fuente: página de Información sobre la CDL de la DLD de Utah (dld.utah.gov/cdl-info)."},"90":{"q":"El ELDT consta de dos partes. ¿Qué debe obtener un solicitante antes de que se pueda administrar la parte detrás del volante?","options":["Un permiso de aprendiz comercial (CLP)","Una calificación aprobatoria en el examen de habilidades","Un endoso de hazmat","Una CDL completa sin restricciones"],"explanation":"El ELDT tiene una parte teórica y una parte detrás del volante. La teoría se puede completar antes de presentar la solicitud, pero se debe obtener un permiso de aprendiz comercial (CLP) antes de que se pueda administrar cualquier capacitación detrás del volante. Fuente: página de Información sobre la CDL de la DLD de Utah (dld.utah.gov/cdl-info)."},"91":{"q":"Después de aprobar el examen escrito de conocimientos en Utah, ¿cuánto tiempo es válido el permiso de aprendiz comercial (CLP)?","options":["180 días","90 días","1 año","60 días"],"explanation":"Una vez aprobado el examen de conocimientos generales, Utah emite un permiso de aprendiz comercial (CLP) válido por 180 días (aproximadamente 6 meses). Fuente: página del Examen Escrito de Conocimientos de la CDL de la DLD de Utah (dld.utah.gov/cdl-written-test) y el Manual CDL 2025."},"92":{"q":"¿Cuánto tiempo debe tener un solicitante de Utah el CLP antes de que se le permita presentar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Utah exige que el solicitante tenga el CLP durante al menos 14 días (y complete el ELDT) antes de presentar el examen de habilidades, en concordancia con la regla federal del CLP. Fuente: página del Examen de Habilidades de Manejo de la CDL de la DLD de Utah (dld.utah.gov/cdl-driving-test)."},"93":{"q":"El examen de habilidades de la CDL de Utah está compuesto por, ¿cuáles tres partes, en orden?","options":["Inspección del vehículo previa al viaje, habilidades básicas de control y manejo en carretera","Examen escrito, habilidades básicas de control y manejo en carretera","Inspección previa al viaje, examen de frenos de aire y manejo en carretera","Habilidades básicas de control, manejo en carretera y un examen escrito final"],"explanation":"El examen de habilidades de la CDL de Utah tiene tres partes: la inspección del vehículo previa al viaje, el examen de habilidades básicas de control y el examen de manejo en carretera. Los exámenes escritos son independientes del examen de habilidades. Fuente: página del Examen de Habilidades de Manejo de la CDL de la DLD de Utah (dld.utah.gov/cdl-driving-test)."},"94":{"q":"¿Qué evalúa principalmente la parte de inspección previa al viaje del examen de habilidades de Utah?","options":["Su conocimiento sobre si el vehículo es seguro para manejar","Su capacidad para retroceder el vehículo hacia un andén de carga","Su tiempo de reacción en tránsito pesado","Su conocimiento escrito de las leyes de tránsito"],"explanation":"La inspección previa al viaje evalúa el conocimiento del solicitante sobre si el vehículo es seguro para manejar, abarcando elementos como el motor, el tractor, el remolque, las luces, los indicadores, el equipo de seguridad y los frenos de aire, si está equipado con ellos. Fuente: página del Examen de Habilidades de Manejo de la CDL de la DLD de Utah (dld.utah.gov/cdl-driving-test)."},"95":{"q":"Para aprobar la parte de habilidades básicas de control del examen de habilidades de la CDL de Utah, ¿cuántos puntos de error puede acumular?","options":["Ocho o menos puntos de error","Doce o menos puntos de error","Treinta o menos puntos de error","Cero puntos de error"],"explanation":"El examen de habilidades básicas de control de Utah (alto hacia adelante, retroceso en línea recta, seguimiento con desplazamiento hacia adelante y retroceso con desplazamiento) requiere ocho o menos puntos de error para aprobar. El examen en carretera permite hasta 30. Fuente: página del Examen de Habilidades de Manejo de la CDL de la DLD de Utah (dld.utah.gov/cdl-driving-test)."},"96":{"q":"Para aprobar la parte de manejo en carretera del examen de habilidades de la CDL de Utah, ¿cuántos puntos de error puede acumular?","options":["Treinta o menos puntos de error","Ocho o menos puntos de error","Quince o menos puntos de error","Cincuenta o menos puntos de error"],"explanation":"El examen de manejo en carretera de Utah, que comprueba si usted tiene las habilidades mínimas para manejar en la mayoría de las situaciones de tránsito, requiere 30 o menos puntos de error para aprobar. El examen de habilidades básicas de control permite solo ocho. Fuente: página del Examen de Habilidades de Manejo de la CDL de la DLD de Utah (dld.utah.gov/cdl-driving-test)."},"97":{"q":"¿Qué exige Utah que proporcione un solicitante para poder presentar el examen de habilidades (manejo) de la CDL?","options":["Su propio vehículo registrado y listo para circular, de la clase apropiada","Un vehículo proporcionado por la Driver License Division","Un vehículo prestado de una flota del UDOT","Únicamente un CLP válido, ya que el estado proporciona el vehículo"],"explanation":"Utah exige que el solicitante traiga su propio vehículo registrado y listo para circular que sea representativo de la clase de CDL que se solicita. La DLD no proporciona vehículos para el examen. Fuente: página del Examen de Habilidades de Manejo de la CDL de la DLD de Utah (dld.utah.gov/cdl-driving-test)."},"98":{"q":"¿Con qué frecuencia debe un titular de CDL de Utah renovar la licencia bajo el ciclo de renovación estándar?","options":["Cada cinco años","Cada cuatro años","Cada ocho años","Cada dos años"],"explanation":"Las CDL de Utah siguen un ciclo de renovación de cinco años, y cada renovación requiere una solicitud actualizada más la autocertificación vigente y la documentación médica. Fuente: información de renovación de la CDL de la DLD de Utah (dld.utah.gov) y la Ley Uniforme de Licencias de Conducir Comerciales de Utah, UCA 53-3-400 y siguientes."}},"hi":{"0":{"q":"बिना परमिट के यूटा के राजमार्गों पर एक वाणिज्यिक वाहन और उसके भार की अधिकतम कानूनी चौड़ाई कितनी है?","options":["8 feet 6 inches","8 feet 0 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"यूटा वाहन की चौड़ाई को 8 feet 6 inches (102 inches) तक सीमित करता है, जिसे भार के साथ या बिना भार के सबसे चौड़े बिंदुओं पर बाहरी-से-बाहरी मापा जाता है। स्रोत: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length पृष्ठ।"},"1":{"q":"बिना ओवरसाइज़ परमिट के यूटा के राजमार्गों पर एक वाहन और भार की अधिकतम कानूनी ऊँचाई कितनी है?","options":["14 feet","13 feet 6 inches","15 feet","13 feet"],"explanation":"यूटा की अधिकतम कानूनी ऊँचाई 14 feet है, जिसे समतल सड़क की सतह से भार या वाहन के शीर्ष तक मापा जाता है। स्रोत: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length पृष्ठ।"},"2":{"q":"बिना ओवरवेट परमिट के यूटा के राजमार्गों पर अधिकतम कानूनी सकल वाहन वज़न कितना है?","options":["80,000 pounds","78,000 pounds","84,000 pounds","76,000 pounds"],"explanation":"यूटा कानूनी सकल वाहन वज़न को 80,000 pounds तक सीमित करता है, जो संघीय सीमा के अनुरूप है, और यह एक्सल तथा ब्रिज-फॉर्मूला सीमाओं के अधीन है। स्रोत: Utah Code 72-7-404; UDOT size/weight permitting।"},"3":{"q":"यूटा के राजमार्गों पर, बिना परमिट के एक सिंगल एक्सल पर अधिकतम कानूनी भार कितना है?","options":["20,000 pounds","18,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"यूटा एक सिंगल एक्सल को 20,000 pounds तक सीमित करता है। स्रोत: Utah Code 72-7-404(1); Utah Admin. Code R909-2।"},"4":{"q":"यूटा के राजमार्गों पर, बिना परमिट के एक टैंडम एक्सल समूह पर अधिकतम कानूनी भार कितना है?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"यूटा एक टैंडम एक्सल को 34,000 pounds तक सीमित करता है। स्रोत: Utah Code 72-7-404(1); UDOT size/weight permitting।"},"5":{"q":"यूटा के राजमार्गों पर एक सिंगल (सीधे) मोटर वाहन की अधिकतम कानूनी लंबाई कितनी है?","options":["45 feet","40 feet","53 feet","48 feet"],"explanation":"यूटा में एक सिंगल मोटर वाहन की लंबाई 45 feet से अधिक नहीं हो सकती, ओवरहैंग को छोड़कर। स्रोत: Utah Admin. Code R909-2-4।"},"6":{"q":"यूटा के राजमार्गों पर ट्रैक्टर-सेमीट्रेलर संयोजन में संचालित एक सेमीट्रेलर की अधिकतम कानूनी लंबाई कितनी है?","options":["53 feet","48 feet","57 feet","45 feet"],"explanation":"यूटा ट्रैक्टर-सेमीट्रेलर संयोजन में सेमीट्रेलर की लंबाई 53 feet तक की अनुमति देता है। स्रोत: Utah Admin. Code R909-2-4; UDOT Legal Height, Width & Length।"},"7":{"q":"यूटा कानून के तहत, ओवरसाइज़ परमिट की आवश्यकता होने से पहले एक भार पावर यूनिट के आगे (FRONT) से कितनी दूर तक बढ़ सकता है?","options":["3 feet","4 feet","5 feet","2 feet"],"explanation":"एक वाहन बिना परमिट के पावर यूनिट के आगे से 3 feet से अधिक बढ़ने वाला भार नहीं ले जा सकता। स्रोत: Utah Admin. Code R909-2-4 ओवरहैंग प्रावधान।"},"8":{"q":"यूटा कानून के तहत, ओवरसाइज़ परमिट की आवश्यकता होने से पहले एक भार बेड या बॉडी के पीछे (REAR) से कितनी दूर तक बढ़ सकता है?","options":["6 feet","4 feet","8 feet","3 feet"],"explanation":"एक भार बिना परमिट के बेड या बॉडी के पीछे से 6 feet से अधिक नहीं बढ़ सकता। स्रोत: Utah Admin. Code R909-2-4 ओवरहैंग प्रावधान।"},"9":{"q":"यूटा के राजमार्गों पर डबल-ट्रेलर (ट्विन-ट्रेलर) संयोजन के लिए अधिकतम संयुक्त ट्रेलर लंबाई कितनी है?","options":["61 feet","65 feet","53 feet","68 feet"],"explanation":"यूटा डबल-ट्रेलर संयोजनों के लिए अधिकतम 61 feet की संयुक्त ट्रेलर लंबाई की अनुमति देता है। स्रोत: Utah Admin. Code R909-2-4।"},"10":{"q":"Utah Code 72-7-404 के तहत, एक वाहन के किसी एक पहिये (WHEEL) पर अधिकतम स्वीकार्य वज़न कितना है?","options":["10,500 pounds","8,000 pounds","12,000 pounds","9,000 pounds"],"explanation":"यूटा एक पहिये पर 10,500 pounds से अधिक सकल वज़न वाले वाहन को चलाने पर रोक लगाता है। स्रोत: Utah Code 72-7-404(1)।"},"11":{"q":"लगातार एक्सल के समूह पर स्वीकार्य सकल वज़न निर्धारित करने के लिए यूटा कौन-सा फॉर्मूला उपयोग करता है?","options":["संघीय ब्रिज फॉर्मूला: W = 500[LN/(N-1) + 12N + 36]","सकल वज़न को टायरों की संख्या से विभाजित किया जाता है","20,000 pounds को एक्सल की संख्या से गुणा किया जाता है","एक्सल रेटिंग का योग घटा 10 प्रतिशत"],"explanation":"यूटा संघीय ब्रिज फॉर्मूला W = 500[LN/(N-1) + 12N + 36] अपनाता है, जहाँ W सकल वज़न है, L एक्सल-समूह की दूरी है, और N एक्सल की संख्या है। स्रोत: Utah Code 72-7-404; UDOT online bridge calculator।"},"12":{"q":"यूटा ब्रिज फॉर्मूला W = 500[LN/(N-1) + 12N + 36] में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["एक्सल समूह के दोनों छोरों के बीच की दूरी, फीट में","प्रति एक्सल कानूनी भार सीमा","ट्रेलर की लंबाई, फीट में","भरे हुए एक्सल की संख्या"],"explanation":"ब्रिज फॉर्मूला में, L समूह के सबसे बाहरी एक्सल के बीच की दूरी फीट में है, N एक्सल की संख्या है, और W निकटतम 500 pounds तक का परिणामी सकल वज़न है। स्रोत: Utah Code 72-7-404।"},"13":{"q":"Utah Code 72-7-404 के तहत, टैंडम एक्सल के दो लगातार सेट प्रत्येक 34,000 pounds ले जा सकते हैं बशर्ते सेटों के पहले और अंतिम एक्सल के बीच की दूरी कम से कम कितने फीट हो?","options":["36 feet","30 feet","40 feet","44 feet"],"explanation":"टैंडम एक्सल के दो लगातार सेट प्रत्येक 34,000 pounds ले जा सकते हैं यदि दोनों सेटों के पहले और अंतिम एक्सल के बीच की कुल दूरी 36 feet या उससे अधिक हो। स्रोत: Utah Code 72-7-404।"},"14":{"q":"यूटा में UDOT से ओवरसाइज़/ओवरवेट परमिट की आवश्यकता कब होती है?","options":["जब वाहन या भार Utah Code 72-7-402 और 72-7-404 में दी गई कानूनी आकार या वज़न सीमाओं से अधिक हो","केवल जब यूटा में राज्य की सीमा पार की जाए","केवल 200,000 pounds से अधिक के भार के लिए","केवल जब इंटरस्टेट राजमार्गों पर यात्रा की जाए"],"explanation":"जब भी कोई वाहन या भार Utah Code 72-7-402 (आकार) और 72-7-404 (वज़न) में निर्धारित कानूनी आकार और/या वज़न सीमाओं से अधिक होता है, तब UDOT परमिट की आवश्यकता होती है। स्रोत: UDOT Oversize & Overweight Provisions; Utah Code 72-7-406।"},"15":{"q":"यूटा के ओवरसाइज़/ओवरवेट परमिट आमतौर पर UDOT द्वारा कैसे जारी किए जाते हैं?","options":["एकल-यात्रा, अर्ध-वार्षिक, या वार्षिक आधार पर","केवल आजीवन परमिट के रूप में","केवल एकल-यात्रा परमिट के रूप में","केवल मासिक परमिट के रूप में"],"explanation":"UDOT ओवरसाइज़/ओवरवेट परमिट एकल-यात्रा, अर्ध-वार्षिक, या वार्षिक आधार पर जारी करता है, जो UDOT online permitting (MCS) प्रणाली के माध्यम से प्राप्त किए जाते हैं। स्रोत: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2-8।"},"16":{"q":"यूटा में एक ओवरवेट डिविज़िबल (विभाज्य) लोड परमिट आमतौर पर किस सकल वज़न सीमा के लिए पंजीकृत वाहन या संयोजन के लिए उपलब्ध है?","options":["78,001 to 80,000 pounds","60,000 to 70,000 pounds","80,001 to 90,000 pounds","70,000 to 78,000 pounds"],"explanation":"यूटा का ओवरवेट डिविज़िबल लोड परमिट उन वाहनों या संयोजनों पर लागू होता है जो 78,001 to 80,000 pounds के लिए उचित रूप से पंजीकृत हैं और इन्हें फिर भी ब्रिज फॉर्मूला तथा कानूनी एक्सल सीमाओं को पूरा करना होगा। स्रोत: Utah Admin. Code R909-2-21; UDOT Overweight Divisible Load Provisions।"},"17":{"q":"यूटा के हे-ट्रक (घास के ट्रक) संचालन के लिए, घास के दो रोल या गट्ठर एक गैर-विभाज्य ओवरसाइज़ परमिट के तहत साथ-साथ केवल तभी ढोए जा सकते हैं जब उनकी संयुक्त चौड़ाई किससे अधिक न हो?","options":["10 feet","8 feet 6 inches","12 feet","14 feet"],"explanation":"यूटा हे-ट्रक संयोजनों को दो रोल या गट्ठर साथ-साथ ले जाने की अनुमति देता है जब उनकी संयुक्त चौड़ाई 10 feet या उससे कम हो और एक वैध गैर-विभाज्य ओवरसाइज़ परमिट रखा गया हो। स्रोत: UDOT/Utah Admin. Code R909-2 कृषि (हे ट्रक) प्रावधान।"},"18":{"q":"एक सामान्य यूटा राजमार्ग पर जो विभाजित/इंटरस्टेट मार्ग नहीं है, किस चौड़ाई पर एक ओवरसाइज़ भार के लिए आमतौर पर एक पायलट/एस्कॉर्ट वाहन की आवश्यकता होती है?","options":["12 feet से अधिक","8 feet 6 inches से अधिक","14 feet से अधिक","16 feet से अधिक"],"explanation":"दो-लेन (गैर-विभाजित) यूटा राजमार्गों पर आमतौर पर एस्कॉर्ट की आवश्यकता होती है जब भार की चौड़ाई 12 feet से अधिक हो; विभाजित/इंटरस्टेट राजमार्गों पर सीमा 14 feet से अधिक होती है। स्रोत: UDOT/Utah Admin. Code R909-2 एस्कॉर्ट प्रावधान।"},"19":{"q":"यूटा के गैर-विभाज्य ओवरवेट परमिट प्रावधानों के तहत, UDOT एक गैर-विभाज्य भार के लिए अधिकतम कितने सिंगल-एक्सल वज़न को अधिकृत कर सकता है?","options":["29,000 pounds","24,000 pounds","34,000 pounds","20,000 pounds"],"explanation":"UDOT गैर-विभाज्य भार के लिए ओवरवेट परमिट जारी कर सकता है जो एक सिंगल एक्सल पर 29,000 pounds तक, एक टैंडम पर 50,000 pounds तक, और एक परमिटेड GVW 125,000 pounds तक हो। स्रोत: UDOT Oversize & Overweight Provisions; Utah Admin. Code R909-2।"},"20":{"q":"यूटा में, 26,001 pounds या उससे अधिक के सकल संयोजन वज़न रेटिंग वाले संयोजन वाहन को चलाने के लिए कौन-सी CDL श्रेणी आवश्यक है, जहाँ खींची जा रही यूनिट की रेटिंग 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"यूटा 26,001 lbs या उससे अधिक GCWR वाले संयोजन वाहनों के लिए Class A CDL जारी करता है जब खींची जा रही यूनिट 10,000 lbs GVWR से अधिक हो (जैसे, एक ट्रैक्टर-ट्रेलर)। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info) और Utah CDL Handbook।"},"21":{"q":"एक यूटा चालक 26,001 pounds या उससे अधिक के सकल वाहन वज़न रेटिंग वाले एकल वाहन (जैसे एक बड़ा डंप ट्रक या बस) को बिना किसी खींची गई यूनिट के चलाता है। इसके लिए कौन-सी CDL श्रेणी आवश्यक है?","options":["Class C","Class B","Class A","Class E"],"explanation":"एक यूटा Class B CDL एक ऐसे एकल वाहन को कवर करता है जिसका GVWR 26,001 lbs या उससे अधिक हो और जिसमें कोई खींची गई यूनिट न हो (या जो 10,000 lbs या उससे कम की यूनिट खींचता हो)। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"22":{"q":"यूटा के नियमों के तहत, एक Class C CDL ऐसे वाहन पर लागू होता है जिसका GVWR 26,001 pounds से कम हो जब इसे चालक सहित कम से कम कितने यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["10 passengers","12 passengers","16 passengers","24 passengers"],"explanation":"यूटा Class C को ऐसे वाहन के रूप में परिभाषित करता है जिसका GVWR 26,001 lbs से कम हो और जो चालक सहित 16 या उससे अधिक यात्रियों को ले जाता हो, या जो खतरनाक सामग्री के लिए प्लेकार्डेड हो। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"23":{"q":"इंट्रास्टेट संचालन (केवल यूटा के भीतर ड्राइविंग) के लिए यूटा CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years old","18 years old","19 years old","21 years old"],"explanation":"यूटा केवल इंट्रास्टेट ड्राइविंग के लिए 18 वर्ष की आयु में CDL की अनुमति देता है। 21 वर्ष से कम आयु के चालक केवल यूटा के भीतर संचालन तक सीमित हैं। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"24":{"q":"इंटरस्टेट संचालन (राज्य की सीमाओं के पार ड्राइविंग) के लिए वैध यूटा CDL रखने हेतु आवश्यक न्यूनतम आयु क्या है?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"यूटा द्वारा अपनाए गए संघीय नियमों के अनुसार एक चालक को इंटरस्टेट कॉमर्स में वाणिज्यिक मोटर वाहन चलाने के लिए कम से कम 21 वर्ष का होना आवश्यक है। 18-20 वर्ष के चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info); 49 CFR 391.11।"},"25":{"q":"एक 19 वर्षीय यूटा CDL धारक K-प्रतिबंध रखता है। निम्नलिखित में से कौन-सा एंडॉर्समेंट यह चालक प्राप्त करने के लिए पात्र (ELIGIBLE) है?","options":["Hazardous Materials (H)","Passenger (P)","School Bus (S)","Tanker (N)"],"explanation":"यूटा में 21 वर्ष से कम आयु के चालक इंट्रास्टेट संचालन तक सीमित हैं और H (hazmat), P (passenger), या S (school bus) एंडॉर्समेंट के लिए पात्र नहीं हैं। N (tanker) एंडॉर्समेंट उस निषिद्ध सूची में नहीं है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"26":{"q":"ऐसी मात्रा में खतरनाक सामग्री ढोने के लिए जिनके लिए प्लेकार्ड आवश्यक हैं, एक यूटा चालक को कौन-से एंडॉर्समेंट की आवश्यकता होती है?","options":["N endorsement","T endorsement","H endorsement","X endorsement"],"explanation":"प्लेकार्ड योग्य मात्रा में hazmat ले जाने के लिए H (Hazardous Materials) एंडॉर्समेंट आवश्यक है। इसके लिए एक TSA सुरक्षा खतरा आकलन पृष्ठभूमि जाँच भी आवश्यक है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"27":{"q":"यूटा द्वारा Hazardous Materials (H) एंडॉर्समेंट जारी किए जाने से पहले, आवेदक को कौन-सी अतिरिक्त जाँच पास करनी होगी?","options":["एक संघीय TSA सुरक्षा खतरा आकलन पृष्ठभूमि जाँच","एक राज्य-संचालित पॉलीग्राफ परीक्षा","एक नेत्र विशेषज्ञ द्वारा दृष्टि परीक्षण","एक नियोक्ता-प्रायोजित नशा पुनर्वास पाठ्यक्रम"],"explanation":"H एंडॉर्समेंट के लिए hazmat ज्ञान परीक्षण के अतिरिक्त संघीय कानून के तहत एक TSA (Transportation Security Administration) सुरक्षा खतरा आकलन / पृष्ठभूमि जाँच पास करना आवश्यक है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info); 49 CFR 1572।"},"28":{"q":"एक यूटा चालक डबल और ट्रिपल ट्रेलर खींचना चाहता है। कौन-सा एंडॉर्समेंट आवश्यक है, और इसे किस CDL श्रेणी पर रखा जा सकता है?","options":["T endorsement, केवल Class A CDL पर उपलब्ध","N endorsement, Class A या B पर उपलब्ध","T endorsement, केवल Class B CDL पर उपलब्ध","P endorsement, किसी भी श्रेणी पर उपलब्ध"],"explanation":"T (Doubles/Triples) एंडॉर्समेंट एक से अधिक ट्रेलर खींचने की अनुमति देता है और इसे केवल Class A CDL में जोड़ा जा सकता है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info) और Utah CDL Handbook।"},"29":{"q":"तरल पदार्थ या गैसें ढोने के लिए उपयोग किए जाने वाले एक टैंक वाहन को चलाने हेतु एक यूटा चालक को कौन-से एंडॉर्समेंट की आवश्यकता होती है?","options":["P endorsement","N endorsement","H endorsement","T endorsement"],"explanation":"N (Tanker) एंडॉर्समेंट उन वाहनों के लिए आवश्यक है जो किसी टैंक में तरल पदार्थ/गैसें ले जाते हैं जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons या उससे अधिक हो और कुल रेटेड क्षमता 1,000 gallons से अधिक हो। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"30":{"q":"एक यूटा चालक के School Bus (S) एंडॉर्समेंट प्राप्त करने से पहले कौन-सा एंडॉर्समेंट आवश्यक है?","options":["Hazmat (H) endorsement","Tanker (N) endorsement","Passenger (P) endorsement","Doubles/Triples (T) endorsement"],"explanation":"यूटा में School Bus (S) एंडॉर्समेंट को Passenger (P) एंडॉर्समेंट के ऊपर जोड़ा जाता है; एक आवेदक को P (ज्ञान और कौशल) के लिए योग्य होना चाहिए और फिर अतिरिक्त S ज्ञान तथा कौशल परीक्षण पास करने चाहिए। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"31":{"q":"किन दो एंडॉर्समेंट के लिए एक यूटा आवेदक को एक लिखित ज्ञान परीक्षण के अतिरिक्त एक ड्राइविंग कौशल (SKILLS) परीक्षण पास करना आवश्यक है?","options":["H (Hazmat) और N (Tanker)","P (Passenger) और S (School Bus)","T (Doubles/Triples) और N (Tanker)","H (Hazmat) और T (Doubles/Triples)"],"explanation":"यूटा में P (Passenger) और S (School Bus) एंडॉर्समेंट प्रत्येक के लिए उपयुक्त वाहन में एक ड्राइविंग कौशल परीक्षण आवश्यक है, जबकि H, N, और T के लिए केवल एक ज्ञान परीक्षण आवश्यक है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"32":{"q":"यूटा द्वारा अपनाए गए संघीय नियमों के तहत, CDL ड्राइविंग कौशल परीक्षण देने की अनुमति मिलने से पहले एक चालक को कितने समय तक एक Commercial Learner Permit (CLP) रखना आवश्यक है?","options":["7 days","14 days","30 days","60 days"],"explanation":"एक आवेदक को CDL कौशल परीक्षण देने से पहले कम से कम 14 days तक CLP रखना आवश्यक है। यह एक FMCSA आवश्यकता है जिसे Utah DLD द्वारा लागू किया जाता है। स्रोत: Utah DLD CDL Driving Skills Test पृष्ठ (dld.utah.gov/cdl-driving-test); 49 CFR 383.25।"},"33":{"q":"एक यूटा Commercial Learner Permit (CLP) उसके जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["90 days","180 days","1 year","2 years"],"explanation":"एक यूटा CLP 180 days (लगभग 6 महीने) के लिए वैध होता है। इसे दो-वर्ष की अवधि के भीतर एक बार नवीनीकृत किया जा सकता है। स्रोत: Utah DLD CDL Written Knowledge Test पृष्ठ (dld.utah.gov/cdl-written-test)।"},"34":{"q":"एक यूटा CDL लिखित ज्ञान परीक्षण (सामान्य ज्ञान या एक एंडॉर्समेंट परीक्षण) पास करने के लिए एक आवेदक को न्यूनतम कितने अंक प्राप्त करने होंगे?","options":["70%","75%","80%","90%"],"explanation":"यूटा किसी भी CDL लिखित ज्ञान परीक्षण को पास करने के लिए 80% अंक आवश्यक मानता है। स्रोत: Utah DLD CDL Written Knowledge Test पृष्ठ (dld.utah.gov/cdl-written-test)।"},"35":{"q":"एक Commercial Learner Permit जारी किए जाने के लिए एक यूटा आवेदक को सबसे पहले (FIRST) कौन-सा ज्ञान परीक्षण पास करना होगा?","options":["50-प्रश्नों वाला सामान्य ज्ञान परीक्षण","25-प्रश्नों वाला एयर ब्रेक परीक्षण","20-प्रश्नों वाला संयोजन वाहन परीक्षण","30-प्रश्नों वाला hazmat परीक्षण"],"explanation":"50-प्रश्नों वाला सामान्य ज्ञान परीक्षण (80% पर) पास करने से एक CLP जारी होता है, जो 180 days के लिए वैध होता है। स्रोत: Utah DLD CDL Written Knowledge Test पृष्ठ (dld.utah.gov/cdl-written-test)।"},"36":{"q":"पहली बार के यूटा Class A या Class B आवेदकों के लिए आवश्यक Entry-Level Driver Training (ELDT) एक ऐसे प्रदाता के माध्यम से पूरा किया जाना चाहिए जो:","options":["स्थानीय स्कूल जिले द्वारा अनुमोदित हो","FMCSA Training Provider Registry में सूचीबद्ध हो","Utah State Tax Commission द्वारा प्रमाणित हो","U.S. Department of Education द्वारा मान्यता प्राप्त हो"],"explanation":"ELDT कौशल परीक्षण से पहले FMCSA Training Provider Registry (TPR) में सूचीबद्ध एक प्रदाता के माध्यम से पूरा किया जाना चाहिए। ELDT पहली बार के Class A/B आवेदकों, Class B-से-A अपग्रेड, और पहली बार के H, P, और S एंडॉर्समेंट पर लागू होता है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info); 49 CFR Part 380।"},"37":{"q":"निम्नलिखित में से किसके लिए यूटा Entry-Level Driver Training (ELDT) की आवश्यकता नहीं रखता (NOT)?","options":["पहली बार का Class A CDL आवेदक","पहली बार का Hazmat (H) एंडॉर्समेंट आवेदक","एक Tanker (N) एंडॉर्समेंट जोड़ना","पहली बार का School Bus (S) एंडॉर्समेंट आवेदक"],"explanation":"संघीय ELDT पहली बार के Class A/B CDL, Class B-से-A अपग्रेड, और पहली बार के H, P, और S एंडॉर्समेंट पर लागू होता है। N (tanker) और T (doubles/triples) एंडॉर्समेंट ELDT के अधीन नहीं हैं। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info); 49 CFR Part 380।"},"38":{"q":"एक यूटा CDL के लिए आवेदन करते समय, एक आवेदक को Driver License Division को कौन-सा दस्तावेज़ों का संयोजन प्रदान करना होगा?","options":["पहचान और वैध उपस्थिति का प्रमाण, पूरा Social Security number, और यूटा निवास सिद्ध करने वाले दो दस्तावेज़","केवल एक पासपोर्ट","एक हाई स्कूल डिप्लोमा और एक उपयोगिता बिल","केवल एक वाहन पंजीकरण और बीमा का प्रमाण"],"explanation":"Utah DLD पहचान/वैध उपस्थिति का प्रमाण, आवेदक का पूरा Social Security number, और यूटा निवास सिद्ध करने वाले दो दस्तावेज़ (तथा जहाँ आवश्यक हो वहाँ एक वैध मेडिकल प्रमाणपत्र) आवश्यक मानता है। स्रोत: Utah DLD CDL Information पृष्ठ (dld.utah.gov/cdl-info)।"},"39":{"q":"एक यूटा CDL आवेदक जो केवल यूटा के भीतर ड्राइव करता है और गैर-छूट प्राप्त माल ढोता है, और जो एक वैध DOT मेडिकल कार्ड रखता है, उसे किस श्रेणी के तहत स्वयं-प्रमाणन करना चाहिए?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Intrastate"],"explanation":"यूटा चार स्वयं-प्रमाणन श्रेणियों का उपयोग करता है। केवल यूटा के भीतर गैर-छूट प्राप्त कॉमर्स में संचालन करने वाला एक चालक Non-Excepted Intrastate के रूप में प्रमाणित करता है। इंटरस्टेट श्रेणियाँ राज्य-सीमा-पार ड्राइविंग पर लागू होती हैं; छूट प्राप्त श्रेणियाँ विशिष्ट संघीय रूप से छूट प्राप्त संचालनों पर लागू होती हैं। स्रोत: Utah DLD CDL Self-Certification पृष्ठ (dld.utah.gov/cdl-self-certification)।"},"40":{"q":"यूटा में, रक्त/श्वास अल्कोहल सांद्रता (BAC) किस स्तर पर या उससे अधिक होने पर एक व्यक्ति को वाणिज्यिक मोटर वाहन (CMV) चलाने से प्रतिबंधित किया जाता है?","options":["0.04","0.08","0.02","0.05"],"explanation":"Utah Code 53-3-414(1)(a)(ii) के अनुसार 0.04 grams या उससे अधिक अल्कोहल सांद्रता के साथ CMV चलाना एक प्रमुख अपराध है। 0.08 सीमा केवल गैर-वाणिज्यिक ड्राइविंग पर लागू होती है। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"41":{"q":"एक यूटा CDL चालक को पहले (FIRST) प्रमुख अपराध (जैसे 0.04 या उससे अधिक BAC के साथ CMV चलाना) के लिए दोषी ठहराया जाता है और वह प्लेकार्डेड खतरनाक सामग्री नहीं ढो रहा था। न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["1 year","60 days","3 years","6 months"],"explanation":"Utah Code 53-3-414(1)(a) के तहत, पहले प्रमुख अपराध का परिणाम एक वर्ष से कम नहीं की अयोग्यता है। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"42":{"q":"यदि एक यूटा CDL चालक प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाते समय एक पहला प्रमुख अपराध (जैसे एक DUI) करता है, तो न्यूनतम अयोग्यता बढ़कर किस अवधि तक हो जाती है?","options":["3 years","1 year","2 years","Lifetime"],"explanation":"Utah Code 53-3-414(2) पहले प्रमुख अपराध के लिए न्यूनतम अयोग्यता को तीन वर्ष से कम नहीं तक बढ़ा देता है जब अपराध प्लेकार्डेड खतरनाक सामग्री ले जाते समय होता है। स्रोत: Utah Code 53-3-414।"},"43":{"q":"एक यूटा CDL धारक के साथ क्या होता है जिसे एक अलग घटना से उत्पन्न दूसरे (SECOND) प्रमुख अपराध के लिए दोषी ठहराया जाता है?","options":["CMV चलाने से आजीवन अयोग्य","3 वर्ष के लिए अयोग्य","1 वर्ष के लिए अयोग्य","120 दिनों के लिए अयोग्य"],"explanation":"Utah Code 53-3-414(3)(a) यह प्रावधान करता है कि अलग घटनाओं से दो या अधिक प्रमुख अपराधों का परिणाम CMV चलाने से आजीवन अयोग्यता है। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"44":{"q":"यूटा के अंतर्निहित-सहमति नियमों के तहत, उस CDL चालक के लिए क्या परिणाम होता है जो अल्कोहल या ड्रग सांद्रता के लिए एक रासायनिक परीक्षण कराने से इनकार करता है?","options":["इसे एक प्रमुख अपराध माना जाता है, जो CDL को कम से कम 1 year के लिए अयोग्य करता है","पहले इनकार पर केवल एक चेतावनी","एक 60-day अयोग्यता","बिना अयोग्यता के $500 का जुर्माना"],"explanation":"Utah Code 53-3-414(1)(a)(vi) रासायनिक परीक्षण कराने से इनकार को एक प्रमुख अपराध के रूप में सूचीबद्ध करता है, जो समान न्यूनतम 1-year अयोग्यता वहन करता है (प्लेकार्डेड hazmat होने पर 3 वर्ष)। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"45":{"q":"तीन-वर्ष की अवधि के भीतर कितने गंभीर (SERIOUS) यातायात उल्लंघन यूटा में 60-day CDL अयोग्यता को ट्रिगर करते हैं?","options":["2","3","1","4"],"explanation":"Utah Code 53-3-414(6)(a)(i) तीन वर्षों के भीतर होने वाले दो गंभीर यातायात उल्लंघनों के लिए 60 days से कम नहीं की अयोग्यता आवश्यक मानता है। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"46":{"q":"यूटा में, एक तीन-वर्ष की अवधि के भीतर तीन या अधिक गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया गया एक CDL चालक कम से कम कितने समय के लिए अयोग्य होता है?","options":["120 days","60 days","1 year","90 days"],"explanation":"Utah Code 53-3-414(6)(a)(ii) तीन वर्षों के भीतर तीन या अधिक गंभीर यातायात उल्लंघनों के लिए 120 days से कम नहीं की अयोग्यता लागू करता है। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"47":{"q":"निम्नलिखित में से कौन-सा एक यूटा CDL चालक के लिए एक गंभीर (SERIOUS) यातायात उल्लंघन के रूप में वर्गीकृत है?","options":["निर्धारित सीमा से 15 mph या उससे अधिक की गति से वाहन चलाना","निर्धारित सीमा से 5 mph अधिक गति से वाहन चलाना","एक पार्किंग उल्लंघन","सीमा से 3 mph कम गति से वाहन चलाना"],"explanation":"Utah CDL Manual और यूटा की उल्लंघन (ACD) कोड सूची के अनुसार, सीमा से 15 mph या उससे अधिक गति से वाहन चलाना एक गंभीर यातायात उल्लंघन है। इससे कम गति और पार्किंग गंभीर नहीं हैं। स्रोत: Utah CDL Manual; यूटा में लागू 49 CFR 383.51।"},"48":{"q":"कौन-सा कृत्य एक गंभीर यातायात उल्लंघन के रूप में गिना जाता है जो एक यूटा CDL अयोग्यता में योगदान दे सकता है?","options":["CMV चलाते समय टेक्स्टिंग करना या हाथ में पकड़े फोन का उपयोग करना","CMV चलाते समय हैंड्स-फ्री फोन का उपयोग करना","CMV चलाते समय खाना खाना","CMV चलाते समय रेडियो सुनना"],"explanation":"यूटा संघीय गंभीर-उल्लंघन सूची (49 CFR 383.51) का पालन करता है: CMV संचालित करते समय टेक्स्टिंग करना या हाथ में पकड़े मोबाइल फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है। हैंड्स-फ्री उपयोग नहीं है। स्रोत: Utah CDL Manual; 49 CFR 383.51।"},"49":{"q":"एक यूटा CDL चालक को CMV चलाते समय एक आउट-ऑफ-सर्विस (OOS) आदेश के पहले (FIRST) उल्लंघन के लिए दोषी ठहराया जाता है (कोई hazmat नहीं, कोई बड़ी बस नहीं)। यूटा कानून के तहत न्यूनतम अयोग्यता क्या है?","options":["180 days","90 days","60 days","1 year"],"explanation":"Utah Code 53-3-414(7)(a)(i) पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए न्यूनतम अयोग्यता 180 days निर्धारित करता है, जो संघीय 90-day न्यूनतम से अधिक है। स्रोत: Utah Code 53-3-414।"},"50":{"q":"अयोग्यता के अलावा, यूटा कानून एक पहले (FIRST) आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए दोषी ठहराए गए CDL चालक पर कौन-सा न्यूनतम नागरिक दंड (CIVIL PENALTY) लगाता है?","options":["$2,500","$1,000","$5,000","$500"],"explanation":"Utah Code 53-3-414(7)(b) पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए $2,500 से कम नहीं का नागरिक दंड आवश्यक मानता है। स्रोत: Utah Code 53-3-414।"},"51":{"q":"यूटा कानून के तहत, एक CDL चालक के दूसरे (SECOND) या उसके बाद के आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए न्यूनतम नागरिक दंड कम से कम है:","options":["$5,000","$2,500","$3,500","$10,000"],"explanation":"Utah Code 53-3-414(7)(c) दूसरे या उसके बाद के आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए नागरिक दंड $5,000 से कम नहीं निर्धारित करता है। स्रोत: Utah Code 53-3-414।"},"52":{"q":"एक यूटा CDL चालक को 10-वर्ष की अवधि के भीतर एक अलग घटना में, दूसरे (SECOND) आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता क्या है?","options":["2 years","1 year","180 days","3 years"],"explanation":"Utah Code 53-3-414(7)(a)(ii) किसी भी 10-वर्ष की अवधि के भीतर अलग घटनाओं में दूसरे OOS-आदेश उल्लंघन के लिए 2 years से कम नहीं की अयोग्यता आवश्यक मानता है। स्रोत: Utah Code 53-3-414।"},"53":{"q":"यूटा कानून के तहत, 10-वर्ष की अवधि के भीतर अलग घटनाओं में एक तीसरा (THIRD) या उससे अधिक आउट-ऑफ-सर्विस आदेश उल्लंघन किसकी अयोग्यता में परिणत होता है:","options":["3 to 5 years","1 to 2 years","180 days to 1 year","10 years"],"explanation":"Utah Code 53-3-414(7)(a)(iii) किसी भी 10-वर्ष की अवधि के भीतर तीन या अधिक OOS-आदेश उल्लंघनों के लिए 3 वर्ष से कम नहीं परंतु 5 वर्ष से अधिक नहीं की अयोग्यता आवश्यक मानता है। स्रोत: Utah Code 53-3-414।"},"54":{"q":"एक यूटा CDL चालक को CMV चलाते समय एक पहले (FIRST) रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"Utah Code 53-3-414(9)(a) एक पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए 60 days से कम नहीं की अयोग्यता लागू करता है। स्रोत: Utah Code 53-3-414; Utah CDL Manual।"},"55":{"q":"एक तीन-वर्ष की अवधि के भीतर एक दूसरे (SECOND) रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन (अलग घटनाएँ) के लिए, एक यूटा CDL चालक कम से कम कितने समय के लिए अयोग्य होता है:","options":["120 days","60 days","1 year","90 days"],"explanation":"Utah Code 53-3-414(9)(b) किसी भी तीन-वर्ष की अवधि के भीतर एक दूसरे ग्रेड-क्रॉसिंग उल्लंघन के लिए 120 days से कम नहीं की अयोग्यता आवश्यक मानता है। स्रोत: Utah Code 53-3-414।"},"56":{"q":"एक यूटा CDL चालक जिसे एक तीन-वर्ष की अवधि के भीतर एक तीसरे (THIRD) या उससे अधिक रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन (अलग घटनाएँ) के लिए दोषी ठहराया जाता है, वह कम से कम कितने समय के लिए अयोग्य होता है:","options":["1 year","120 days","60 days","3 years"],"explanation":"Utah Code 53-3-414(9)(c) किसी भी तीन-वर्ष की अवधि के भीतर तीन या अधिक ग्रेड-क्रॉसिंग उल्लंघनों के लिए 1 year से कम नहीं की अयोग्यता आवश्यक मानता है। स्रोत: Utah Code 53-3-414।"},"57":{"q":"यदि एक CMV चालक जिसके पास CDL रखना आवश्यक है, 0.04 से कम किसी भी पता लगाने योग्य मात्रा में अल्कोहल के लिए पॉज़िटिव परीक्षण करता है, तो क्या कार्रवाई की जाती है?","options":["24 घंटे के लिए आउट ऑफ सर्विस रखा जाता है","तत्काल 1-year CDL अयोग्यता","60-day CDL अयोग्यता","कोई कार्रवाई नहीं क्योंकि यह 0.04 से कम है"],"explanation":"यूटा संघीय नियम (49 CFR 392.5) का पालन करता है: 0.04 से कम किसी भी पता लगाने योग्य अल्कोहल वाले एक CMV चालक को 24 घंटे के लिए आउट ऑफ सर्विस रखा जाना चाहिए। 0.04 या उससे अधिक की रीडिंग एक प्रमुख अपराध है। स्रोत: Utah CDL Manual; 49 CFR 392.5।"},"58":{"q":"यूटा में, किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े एक अपराध (फेलनी) के दौरान एक CMV का उपयोग करने के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["आजीवन, बिना किसी पुनर्बहाली के उपलब्ध","1 year","3 years","10 years"],"explanation":"Utah Code 53-3-414(5) और 414(3)(b) नियंत्रित-पदार्थ के निर्माण, वितरण, या वितरण से जुड़े एक अपराध (फेलनी) में जब एक CMV का उपयोग किया जाता है, तो पुनर्बहाली के लिए बिना किसी पात्रता के आजीवन अयोग्यता लागू करते हैं। स्रोत: Utah Code 53-3-414।"},"59":{"q":"एक यूटा CDL धारक को एक आजीवन अयोग्यता प्राप्त होती है जो पुनर्बहाली के लिए पात्र है। CDL को पुनर्बहाल करने के लिए आवेदन करने से पहले न्यूनतम कितनी अयोग्यता अवधि पूरी की जानी चाहिए?","options":["10 years","5 years","3 years","15 years"],"explanation":"Utah Code 53-3-414(4)(a) एक चालक को पुनर्बहाली के लिए आवेदन करने की अनुमति केवल तभी देता है जब उसने 10 years की न्यूनतम अयोग्यता पूरी कर ली हो और 49 CFR 383.51 को पूरा करने वाला एक अनुमोदित पुनर्वास कार्यक्रम पूरा कर लिया हो। स्रोत: Utah Code 53-3-414।"},"60":{"q":"यूटा के मूव ओवर (Move Over) कानून के तहत, जब कोई व्यावसायिक चालक किसी बहु-लेन राजमार्ग पर चमकती एम्बर लाइटें दिखाते हुए खड़े टो ट्रक या राजमार्ग रखरखाव वाहन के पास पहुँचता है, तो चालक को क्या करना चाहिए?","options":["गति कम करें और, यदि व्यावहारिक और सुरक्षित हो, तो खड़े वाहन से सटी हुई न होने वाली लेन में बदल जाएँ","गति बनाए रखें लेकिन कर्मचारियों को सचेत करने के लिए हॉर्न बजाएँ","जब तक खड़ा वाहन शोल्डर से न चला जाए, तब तक पूरी तरह रुके रहें","कुछ नहीं, क्योंकि यह कानून केवल पुलिस और एम्बुलेंस पर लागू होता है"],"explanation":"Utah Code 41-6a-904 (मूव ओवर कानून) के अनुसार, चमकती लाइटों के साथ खड़े किसी अधिकृत आपातकालीन वाहन, टो/रेकर ट्रक, या सड़क रखरखाव वाहन के पास पहुँचने वाले चालक को गति कम करनी चाहिए और, यदि वह सटी हुई लेन में चल रहा हो तथा सुरक्षा का उचित ध्यान रखते हुए यह व्यावहारिक हो, तो खड़े वाहन से सटी हुई न होने वाली लेन में चला जाना चाहिए। स्रोत: Utah Code 41-6a-904।"},"61":{"q":"यूटा का मूव ओवर कानून (41-6a-904) यह निर्दिष्ट करता है कि किसी खड़े आपातकालीन या रखरखाव वाहन को पार करते समय चालक को किस संख्यात्मक गति तक धीमा होना चाहिए?","options":["कोई निश्चित संख्या तय नहीं है; कानून में चालक से 'गति कम करने' की अपेक्षा की गई है","पोस्ट की गई सीमा से ठीक 20 mph कम","पोस्ट की गई सीमा की परवाह किए बिना एक समान 25 mph","सभी मामलों में ठीक 10 mph"],"explanation":"Utah Code 41-6a-904 में कोई निश्चित mph आँकड़ा नहीं बताया गया है। इसमें चालक से अपेक्षा की गई है कि वह गति कम करे, यथासंभव अधिक जगह दे, और जब व्यावहारिक हो तो खड़े वाहन से दूर वाली लेन में बदल जाए। स्रोत: Utah Code 41-6a-904।"},"62":{"q":"एक ही दिशा में एक से अधिक लेन वाले यूटा राजमार्ग पर, बाईं सामान्य-उपयोग लेन में चल रहे एक CMV को उसके पीछे से एक तेज़ वाहन ओवरटेक करता है। यूटा कानून के अनुसार क्या आवश्यक है?","options":["सुरक्षित रूप से दाईं ओर की लेन में चले जाएँ और बाईं लेन में यातायात के मुक्त प्रवाह में बाधा न डालें","लेन बनाए रखें क्योंकि ट्रक पहले से ही पोस्ट की गई गति सीमा पर है","लेन खाली करने के लिए कम से कम सीमा से 5 mph अधिक तक गति बढ़ाएँ","वाहन को निकलने देने के लिए बाईं ओर मध्य शोल्डर (median shoulder) पर चले जाएँ"],"explanation":"Utah Code 41-6a-704 में प्रावधान है कि बाईं सामान्य-उपयोग लेन में चल रहे चालक को, जिसे कोई अन्य वाहन ओवरटेक करता है, सुरक्षित रूप से दाईं ओर की लेन में जाकर रास्ता देना चाहिए और बाईं लेन में यातायात की गति या मुक्त प्रवाह में बाधा नहीं डालनी चाहिए; उल्लंघन एक इन्फ्रैक्शन है। स्रोत: Utah Code 41-6a-704।"},"63":{"q":"किसी ग्रामीण यूटा इंटरस्टेट पर एक व्यावसायिक चालक कानूनी रूप से अधिकतम कितनी पोस्ट की गई गति सीमा का सामना कर सकता है?","options":["जहाँ पोस्ट किया गया हो वहाँ 80 mph","सभी ट्रकों के लिए राज्यव्यापी 65 mph की अधिकतम सीमा","किसी भी वाहन के लिए अधिकतम 70 mph","जहाँ पोस्ट किया गया हो वहाँ 85 mph"],"explanation":"यूटा निर्दिष्ट ग्रामीण इंटरस्टेट खंडों पर 80 mph पोस्ट करता है (75 mph सामान्य डिफ़ॉल्ट है), जो राज्य में सबसे अधिक है। स्रोत: Utah Code 41-6a-601/604 और Utah DOT द्वारा पोस्ट की गई सीमाएँ।"},"64":{"q":"इंटरस्टेट पर यूटा ट्रक गति सीमाओं को यात्री-कार सीमाओं की तुलना में कैसे मानता है?","options":["ट्रक उसी पोस्ट की गई सीमा का पालन करते हैं; यूटा ट्रकों के लिए कोई अलग कम राज्यव्यापी गति सीमा निर्धारित नहीं करता","पोस्ट की गई सीमा की परवाह किए बिना ट्रक राज्यव्यापी रूप से 55 mph तक सीमित हैं","ट्रकों को हमेशा पोस्ट की गई कार सीमा से 15 mph कम चलना चाहिए","सभी इंटरस्टेट पर ट्रक 60 mph तक सीमित हैं"],"explanation":"कैलिफ़ोर्निया जैसे विभाजित-सीमा (split-limit) वाले राज्यों के विपरीत, यूटा ट्रकों के लिए कोई अलग कम राज्यव्यापी गति सीमा नहीं लगाता; CMV उसी पोस्ट की गई सीमा (80 mph तक) का पालन करते हैं। केवल कुछ ढलानों पर स्थानीयकृत संकेतित ट्रक-गति कटौती लागू होती है। स्रोत: Utah Code Title 41 Chapter 6a Part 6 और Utah DOT।"},"65":{"q":"यूटा में किसी रेलरोड ग्रेड क्रॉसिंग पर, यात्रियों को ले जाने वाली बस या प्लेकार्ड लगे HazMat वाहन के चालक को निकटतम रेल से किस दूरी के भीतर वाहन रोकना चाहिए?","options":["निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं","निकटतम रेल से 25 फीट के भीतर लेकिन 5 फीट से कम नहीं","निकटतम रेल से 100 फीट के भीतर लेकिन 50 फीट से कम नहीं","निकटतम रेल से 75 फीट के भीतर लेकिन 25 फीट से कम नहीं"],"explanation":"यात्रियों वाली बसों और प्लेकार्ड लगे HazMat वाहनों को निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं की दूरी पर रुकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए। स्रोत: Utah CDL Handbook (DLD) और यूटा में लागू 49 CFR 392.10।"},"66":{"q":"इनमें से किस यूटा व्यावसायिक वाहन को हर रेलरोड क्रॉसिंग पर (जहाँ छूट प्राप्त न हो) रुकना आवश्यक है?","options":["यात्रियों को ले जाने वाली बस और HazMat प्लेकार्ड दिखाने वाला वाहन","सामान्य माल ढोने वाला कोई भी ट्रैक्टर-ट्रेलर","केवल 26,001 पाउंड से अधिक वजन वाले वाहन","केवल ट्रिपल-ट्रेलर संयोजन"],"explanation":"यूटा संघीय नियम का पालन करता है: केवल यात्रियों को ले जाने वाली बसों और प्लेकार्ड लगे HazMat वाहनों को रेलरोड क्रॉसिंग पर रुकना चाहिए; अधिकांश अन्य CMV को रुकना आवश्यक नहीं है। स्रोत: Utah CDL Handbook (DLD); 49 CFR 392.10।"},"67":{"q":"यूटा में किसी प्लेकार्ड लगे HazMat वाहन में रेलरोड क्रॉसिंग के लिए रुकते समय, वाहन का कोई भी हिस्सा पटरियों पर आने से पहले चालक को इनमें से क्या नहीं करना चाहिए?","options":["वाहन का कोई भी हिस्सा पटरियों को पार कर रहा हो तब गियर बदलना","आ रही ट्रेन के लिए दोनों दिशाओं में देखना और सुनना","पास आते समय फोर-वे फ्लैशर्स चालू करना","ऐसा क्रॉसिंग बिंदु चुनना जहाँ वाहन बिना रुके पटरियों को पार कर सके"],"explanation":"CMV चालक को कभी भी तब गियर नहीं बदलना चाहिए जब वाहन का कोई भी हिस्सा पटरियों पर हो, क्योंकि गियर बदलने में चूक होने पर वाहन क्रॉसिंग पर रुक सकता है। स्रोत: Utah CDL Handbook (DLD), रेलरोड क्रॉसिंग खंड।"},"68":{"q":"किसी अविभाजित दो-लेन वाली यूटा सड़क पर, एक स्कूल बस रुकती है और बारी-बारी से चमकती लाल लाइटें दिखाती है। विपरीत दिशा से आ रहे चालक को क्या करना चाहिए?","options":["बस तक पहुँचने से पहले रुक जाएँ और जब तक लाल लाइटें चमकना बंद न कर दें तब तक रुके रहें","20 mph तक धीमा हो जाएँ और बाईं ओर से सावधानी के साथ पार करें","सामान्य रूप से आगे बढ़ें क्योंकि आती हुई यातायात को कभी रुकने की आवश्यकता नहीं होती","केवल तभी रुकें जब बच्चे स्पष्ट रूप से सड़क पर दिखाई दें"],"explanation":"Utah Code 41-6a-1302 के अनुसार चमकती लाल लाइटें दिखाने वाली स्कूल बस के लिए दोनों दिशाओं के यातायात को रुकना चाहिए और जब तक लाल लाइटें बंद न हो जाएँ तब तक आगे नहीं बढ़ना चाहिए। स्रोत: Utah Code 41-6a-1302।"},"69":{"q":"एक स्कूल बस राजमार्ग को विभाजित करने वाले एक उठे हुए, भूदृश्य वाले मीडियन की दूसरी ओर चमकती लाल लाइटों के साथ रुकी हुई है। उस मीडियन के दूसरी ओर विपरीत दिशा में चल रहे एक CMV चालक को यूटा कानून के तहत क्या करना आवश्यक है?","options":["आगे बढ़ें, क्योंकि मीडियन-विभाजित राजमार्ग अपवाद विपरीत दिशा के यातायात पर लागू होता है","रुकें, क्योंकि सभी यातायात को हमेशा चमकती लाल लाइटों के लिए रुकना चाहिए","केवल तभी रुकें जब बस 100 फीट के भीतर हो","15 mph तक धीमा हो जाएँ लेकिन रुकने की आवश्यकता नहीं"],"explanation":"चूँकि राजमार्ग एक स्पष्ट रूप से चिह्नित विभाजक खंड (उठा हुआ मीडियन) से विभाजित है, Utah Code 41-6a-1302 विपरीत दिशा के यातायात को बिना रुके आगे बढ़ने की अनुमति देता है। स्रोत: Utah Code 41-6a-1302।"},"70":{"q":"यूटा में किस रंग की चमकती स्कूल-बस लाइटें यह संकेत देती हैं कि बस रुकने की तैयारी कर रही है और चालकों को धीमा होकर रुकने के लिए तैयार रहना चाहिए?","options":["बारी-बारी से चमकती एम्बर (पीली) लाइटें","बारी-बारी से चमकती लाल लाइटें","स्थिर नीली लाइटें","बारी-बारी से चमकती हरी लाइटें"],"explanation":"यूटा में, एम्बर (पीली) चमकती लाइटें चेतावनी देती हैं कि बस रुकने वाली है; विस्तारित स्टॉप आर्म के साथ लाल चमकती लाइटें यातायात को रुकने के लिए बाध्य करती हैं। स्रोत: Utah Code 41-6a-1302; Utah CDL Handbook स्कूल बस खंड।"},"71":{"q":"जब कोई CMV किसी विभाजित या एकतरफ़ा यूटा राजमार्ग के शोल्डर पर रुका हो, तो चालक को तीन आपातकालीन चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["आ रहे यातायात की ओर वाहन के पीछे लगभग 10, 100, और 200 फीट पर","आ रहे यातायात की ओर वाहन के पीछे लगभग 10, 50, और 150 फीट पर","आ रहे यातायात की ओर वाहन के पीछे लगभग 25, 75, और 125 फीट पर","आ रहे यातायात की ओर वाहन के पीछे लगभग 50, 100, और 250 फीट पर"],"explanation":"किसी विभाजित या एकतरफ़ा राजमार्ग पर, त्रिकोण आ रहे यातायात की ओर लगभग 10 फीट, 100 फीट, और 200 फीट पर रखे जाते हैं। स्रोत: Utah CDL Handbook (DLD); 49 CFR 392.22।"},"72":{"q":"किसी यूटा सड़क पर CMV रोकने के बाद, चालक को कितने मिनट के भीतर आपातकालीन चेतावनी उपकरण (त्रिकोण) रख देने चाहिए?","options":["10 मिनट के भीतर","2 मिनट के भीतर","5 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"रुकने के 10 मिनट के भीतर चेतावनी उपकरण रख देने चाहिए। स्रोत: Utah CDL Handbook (DLD); 49 CFR 392.22।"},"73":{"q":"किसी सीधी, समतल, अविभाजित दोतरफ़ा यूटा सड़क पर, किसी रुके हुए CMV के लिए तीन चेतावनी त्रिकोण कहाँ रखे जाते हैं?","options":["वाहन के पीछे 10 फीट, पीछे 100 फीट, और वाहन के आगे 100 फीट पर","10 फीट, 200 फीट, और 300 फीट, सभी पीछे की ओर","पीछे 25 फीट, पीछे 50 फीट, और आगे 75 फीट पर","पीछे 100 फीट, आगे 100 फीट, और एक बम्पर पर"],"explanation":"किसी दोतरफ़ा सड़क पर, एक त्रिकोण पीछे लगभग 10 फीट, एक पीछे लगभग 100 फीट, और एक आगे लगभग 100 फीट पर रखें (दोनों दिशाओं के यातायात की ओर)। स्रोत: Utah CDL Handbook (DLD); 49 CFR 392.22।"},"74":{"q":"किसी ओवरसाइज़ परमिट के बिना यूटा राजमार्गों पर चलने वाले वाहन की अधिकतम चौड़ाई कितनी हो सकती है?","options":["8 फीट 6 इंच","8 फीट 0 इंच","10 फीट 0 इंच","9 फीट 6 इंच"],"explanation":"परमिट के बिना यूटा की कानूनी अधिकतम चौड़ाई 8 फीट 6 इंच (102 inches) है; इससे अधिक चौड़ी किसी भी चीज़ के लिए UDOT ओवरसाइज़ परमिट आवश्यक है। स्रोत: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2।"},"75":{"q":"ओवरसाइज़ परमिट की आवश्यकता पड़ने से पहले यूटा राजमार्गों पर वाहन की अधिकतम ऊँचाई कितनी अनुमत है?","options":["14 फीट 0 इंच","13 फीट 6 इंच","13 फीट 0 इंच","15 फीट 0 इंच"],"explanation":"यूटा परमिट के बिना सड़क की सतह से लोड के शीर्ष तक मापी गई 14 फीट तक की ऊँचाई की अनुमति देता है, जो कई राज्यों में सामान्य 13'6\" सीमा से अधिक है। स्रोत: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2।"},"76":{"q":"यूटा में एक संयोजन वाहन का सकल वजन 86,000 पाउंड है और यह 9 फीट चौड़ा है। यूटा राजमार्गों पर चलने से पहले इसके लिए क्या आवश्यक है?","options":["एक UDOT ओवरसाइज़/ओवरवेट विशेष परिवहन परमिट","कुछ नहीं, क्योंकि यह संघीय इंटरस्टेट सीमा से कम है","केवल एक वाइड-लोड बैनर, कोई परमिट नहीं","केवल चालक के लाइसेंस पर एक HazMat एंडोर्समेंट"],"explanation":"80,000 lb सकल वजन से अधिक या 8'6\" से अधिक चौड़े लोड यूटा की कानूनी सीमाओं से अधिक हैं और इनके लिए एक UDOT ओवरसाइज़/ओवरवेट परमिट (एकल-यात्रा, अर्धवार्षिक, या वार्षिक) आवश्यक है। स्रोत: Utah DOT Size/Weight Permitting; Utah Admin. Code R909-2।"},"77":{"q":"I-80 जैसे यूटा पर्वतीय खड़ी ढलानों पर, जैसे कि Parleys Canyon से होकर, ऐसे भारी ट्रक को रोकने के लिए विशेष रूप से कौन-सी सुविधा प्रदान की जाती है जिसके ब्रेक विफल हो गए हों?","options":["एक रनअवे ट्रक एस्केप रैंप","एक अनिवार्य वेट-इन-मोशन स्केल","एक रिवर्सिबल HOV लेन","केवल ट्रकों के लिए एक टोल बूथ"],"explanation":"I-80 के Parleys Canyon जैसी यूटा ढलानों पर एक रनअवे ट्रक एस्केप रैंप होता है, साथ ही उतराई के पास संकेतित ब्रेक-चेक क्षेत्र भी होते हैं, इसलिए चालकों को निचले गियर में उतरना चाहिए और उचित ब्रेक तकनीक का उपयोग करना चाहिए। स्रोत: Utah DOT; Utah CDL Handbook (पर्वतीय ड्राइविंग)।"},"78":{"q":"यूटा पर्वतों में किसी लंबी उतराई से पहले, गति को नियंत्रित करने के लिए किसी व्यावसायिक चालक के लिए सबसे सुरक्षित अभ्यास क्या है?","options":["नीचे उतरना शुरू करने से पहले एक निचला गियर चुनें और इंजन/सहायक ब्रेकिंग पर निर्भर रहें","ऊँचे गियर में रहें और नीचे तक लगातार सर्विस ब्रेक का उपयोग करते रहें","ईंधन बचाने के लिए न्यूट्रल में डालकर ढलान पर कोस्ट करें","अगली चढ़ाई पार करने के लिए शीर्ष पर अतिरिक्त गति बना लें"],"explanation":"यूटा का पर्वतीय-ड्राइविंग मार्गदर्शन यह है कि उतराई से पहले एक निचला गियर चुनें और इंजन/सहायक ब्रेकिंग का उपयोग करें ताकि सर्विस ब्रेक अधिक गर्म न हों; Parleys Canyon जैसी ढलानों पर ब्रेक-चेक क्षेत्र इसका समर्थन करते हैं। स्रोत: Utah CDL Handbook (DLD), पर्वतीय ड्राइविंग और उतराई ब्रेकिंग।"},"79":{"q":"यूटा में व्यावसायिक चालक लाइसेंस (CDL) कौन-सी एजेंसी जारी करती है?","options":["Utah Driver License Division (DLD)","Utah Department of Motor Vehicles (DMV)","Utah Department of Transportation (UDOT)","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"यूटा में, CDL Utah Driver License Division (DLD) द्वारा जारी किए जाते हैं, जो Department of Public Safety का हिस्सा है। DMV वाहन पंजीकरण संभालता है, UDOT सड़कों और ओवरसाइज़/ओवरवेट परमिट संभालता है, और FMCSA संघीय नियामक है। स्रोत: Utah DLD CDL Information पेज (dld.utah.gov/cdl-info)।"},"80":{"q":"यूटा के CDL सामान्य ज्ञान लिखित परीक्षा में कितने प्रश्न होते हैं?","options":["50 प्रश्न","30 प्रश्न","40 प्रश्न","100 प्रश्न"],"explanation":"यूटा की सामान्य ज्ञान लिखित परीक्षा में 50 बहुविकल्पीय प्रश्न होते हैं, जो सभी CDL Handbook पर आधारित होते हैं। स्रोत: Utah DLD CDL Written Knowledge Test पेज (dld.utah.gov/cdl-written-test) और 2025 CDL Manual।"},"81":{"q":"यूटा CDL ज्ञान परीक्षा पास करने के लिए आपको कम से कम कितने अंक प्राप्त करने होंगे?","options":["80%","70%","75%","90%"],"explanation":"यूटा प्रत्येक CDL ज्ञान परीक्षा पास करने के लिए 80% की आवश्यकता रखता है (सामान्य ज्ञान परीक्षा में 50 में से 40)। यह 49 CFR 383.135 में दिए गए संघीय मानक से मेल खाता है। स्रोत: Utah DLD CDL Written Knowledge Test पेज (dld.utah.gov/cdl-written-test)।"},"82":{"q":"यूटा CDL ज्ञान परीक्षाएँ किस भाषा में आयोजित की जाती हैं?","options":["केवल अंग्रेज़ी; अनुवाद सामग्री प्रतिबंधित है","आवेदक की पसंद पर अंग्रेज़ी या स्पेनिश","एक अनुमोदित दुभाषिये की उपस्थिति में कोई भी भाषा","अंग्रेज़ी, जिसमें अनुवाद शब्दकोशों की अनुमति है"],"explanation":"यूटा सभी CDL ज्ञान परीक्षाएँ केवल अंग्रेज़ी में आयोजित करता है, और अनुवाद सामग्री का उपयोग सख्त रूप से प्रतिबंधित है। ये परीक्षाएँ क्लोज़्ड-बुक भी होती हैं। स्रोत: Utah DLD CDL Written Knowledge Test पेज (dld.utah.gov/cdl-written-test)।"},"83":{"q":"यूटा में कोई भी CDL लिखित ज्ञान परीक्षा देने से पहले, आवेदक के पास पहले से क्या होना चाहिए?","options":["एक वर्तमान DOT मेडिकल परीक्षक का प्रमाणपत्र","एक पूर्ण की गई रोड स्किल्स परीक्षा","राज्य के बाहर एक वर्ष का CDL अनुभव","एक खतरनाक सामग्री पृष्ठभूमि जाँच"],"explanation":"यूटा के लिए आवश्यक है कि आवेदकों के पास लिखित ज्ञान परीक्षा देने से पहले एक वर्तमान मेडिकल परीक्षक प्रमाणपत्र (MEC) हो। स्किल्स परीक्षा बाद में आती है, और हज़मत पृष्ठभूमि जाँच केवल उस एंडोर्समेंट पर लागू होती है। स्रोत: Utah DLD CDL Information पेज (dld.utah.gov/cdl-info)।"},"84":{"q":"किसी यूटा CDL धारक के लिए DOT मेडिकल परीक्षक का प्रमाणपत्र अधिकतम कितने समय तक वैध रहता है?","options":["24 महीने तक","12 महीने तक","36 महीने तक","6 महीने तक"],"explanation":"एक DOT फिजिकल (मेडिकल परीक्षक प्रमाणपत्र) यूटा में 24 महीने तक के लिए वैध होता है, हालाँकि किसी चिकित्सीय स्थिति की निगरानी करते समय परीक्षक इसे कम अवधि के लिए जारी कर सकता है। स्रोत: Utah DLD CDL Information पेज (dld.utah.gov/cdl-info)।"},"85":{"q":"किसी यूटा CDL आवेदक के लिए DOT फिजिकल करने के लिए कौन अधिकृत है?","options":["FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध एक मेडिकल परीक्षक","आवेदक द्वारा चुना गया कोई भी लाइसेंस प्राप्त चिकित्सक","परीक्षण कार्यालय में एक DLD कर्मचारी","केवल एक UDOT-नियोजित चिकित्सक"],"explanation":"DOT फिजिकल FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध एक प्रमाणित मेडिकल परीक्षक द्वारा किया जाना चाहिए। कोई भी चिकित्सक योग्य नहीं होता। स्रोत: Utah DLD CDL Information पेज और FMCSA National Registry।"},"86":{"q":"किसी यूटा CDL आवेदक को कितनी स्व-प्रमाणन (self-certification) श्रेणियों में से चुनना होता है?","options":["चार श्रेणियाँ, जिनमें से ठीक एक का चयन","दो श्रेणियाँ, जिनमें से ठीक एक का चयन","तीन श्रेणियाँ, जिनमें से ठीक एक का चयन","पाँच श्रेणियाँ, जिनमें से ठीक एक का चयन"],"explanation":"यूटा चार स्व-प्रमाणन श्रेणियों का उपयोग करता है, और कोई चालक केवल एक को प्रमाणित कर सकता है। वे हैं Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। स्रोत: Utah DLD CDL Self-Certification पेज (dld.utah.gov/cdl-self-certification)।"},"87":{"q":"एक यूटा चालक जो केवल यूटा के भीतर ही संचालन करता है और जिसे राज्य योग्यता आवश्यकताओं को पूरा करना होता है, वह किस श्रेणी के तहत स्व-प्रमाणन करेगा?","options":["Non-Excepted Intrastate","Non-Excepted Interstate","Excepted Interstate","Exempt Federal"],"explanation":"Non-Excepted Intrastate उन चालकों को कवर करता है जो केवल यूटा के भीतर संचालन करते हैं और जिन्हें राज्य की चिकित्सीय योग्यता मानकों (UCA 53-3-303.5) को पूरा करना होता है; इसमें यूटा-केवल प्रतिबंध होता है। इंटरस्टेट श्रेणियाँ देशव्यापी वाणिज्य पर लागू होती हैं। स्रोत: Utah DLD CDL Self-Certification पेज (dld.utah.gov/cdl-self-certification)।"},"88":{"q":"इनमें से किन समयों पर किसी यूटा CDL चालक को DLD को स्व-प्रमाणन (और वर्तमान मेडिकल प्रमाणपत्र) जमा करना चाहिए?","options":["किसी भी CDL के जारी होने पर, जब ड्राइविंग स्थिति बदलती है, और प्रत्येक नवीनीकरण पर","केवल एक बार, पहली बार जब CDL जारी होता है","केवल नियोक्ता बदलते समय","केवल कोई नया एंडोर्समेंट जोड़ते समय"],"explanation":"मेडिकल प्रमाणन प्रक्रिया को पूर्ण बनाए रखने के लिए, स्व-प्रमाणन फॉर्म DLD को किसी भी CDL के जारी होने पर, यदि ड्राइविंग स्थिति की स्थिति बदलती है, और प्रत्येक CDL नवीनीकरण पर जमा किया जाना चाहिए। स्रोत: Utah DLD CDL Information पेज (dld.utah.gov/cdl-info)।"},"89":{"q":"यूटा में लाइसेंस प्राप्त करने से पहले पहली बार Class A या Class B CDL आवेदकों को कौन-सा प्रशिक्षण पूरा करना चाहिए?","options":["किसी पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","एक 160-घंटे की राज्य अप्रेंटिसशिप","UDOT द्वारा अनुमोदित एक रक्षात्मक ड्राइविंग पाठ्यक्रम","छह महीने का पर्यवेक्षित नियोक्ता प्रशिक्षण"],"explanation":"संघीय और यूटा नियमों के अनुसार पहली बार Class A/B आवेदकों (और पहली बार स्कूल बस, यात्री, या हज़मत एंडोर्समेंट आवेदकों) को CDL प्राप्त करने से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना आवश्यक है। स्रोत: Utah DLD CDL Information पेज (dld.utah.gov/cdl-info)।"},"90":{"q":"ELDT में दो भाग होते हैं। बिहाइंड-द-व्हील भाग आयोजित किए जाने से पहले आवेदक को क्या प्राप्त करना चाहिए?","options":["एक commercial learner permit (CLP)","स्किल्स परीक्षा में उत्तीर्ण अंक","एक हज़मत एंडोर्समेंट","एक पूर्ण अप्रतिबंधित CDL"],"explanation":"ELDT में एक थ्योरी भाग और एक बिहाइंड-द-व्हील भाग होता है। थ्योरी आवेदन करने से पहले पूरी की जा सकती है, लेकिन कोई भी बिहाइंड-द-व्हील प्रशिक्षण आयोजित किए जाने से पहले एक commercial learner permit (CLP) प्राप्त करना आवश्यक है। स्रोत: Utah DLD CDL Information पेज (dld.utah.gov/cdl-info)।"},"91":{"q":"यूटा में लिखित ज्ञान परीक्षा पास करने के बाद, commercial learner permit (CLP) कितने समय तक वैध रहता है?","options":["180 दिन","90 दिन","1 वर्ष","60 दिन"],"explanation":"सामान्य ज्ञान परीक्षा पास हो जाने के बाद, यूटा 180 दिन (लगभग 6 महीने) के लिए वैध एक commercial learner permit (CLP) जारी करता है। स्रोत: Utah DLD CDL Written Knowledge Test पेज (dld.utah.gov/cdl-written-test) और 2025 CDL Manual।"},"92":{"q":"CDL स्किल्स परीक्षा देने की अनुमति मिलने से पहले किसी यूटा आवेदक को CLP कितने समय तक रखना चाहिए?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"यूटा के लिए आवश्यक है कि आवेदक स्किल्स परीक्षा देने से पहले CLP को कम से कम 14 दिन तक रखे (और ELDT पूरा करे), जो संघीय CLP नियम से मेल खाता है। स्रोत: Utah DLD CDL Driving Skills Test पेज (dld.utah.gov/cdl-driving-test)।"},"93":{"q":"यूटा CDL स्किल्स परीक्षा किन तीन भागों से, क्रम में, बनी होती है?","options":["प्री-ट्रिप वाहन निरीक्षण, बेसिक कंट्रोल स्किल्स, और ऑन-रोड ड्राइविंग","लिखित परीक्षा, बेसिक कंट्रोल स्किल्स, और ऑन-रोड ड्राइविंग","प्री-ट्रिप निरीक्षण, एयर ब्रेक परीक्षा, और ऑन-रोड ड्राइविंग","बेसिक कंट्रोल स्किल्स, ऑन-रोड ड्राइविंग, और एक अंतिम लिखित परीक्षा"],"explanation":"यूटा की CDL स्किल्स परीक्षा में तीन भाग होते हैं: प्री-ट्रिप वाहन निरीक्षण, बेसिक कंट्रोल स्किल्स परीक्षा, और ऑन-रोड ड्राइविंग परीक्षा। लिखित परीक्षाएँ स्किल्स परीक्षा से अलग होती हैं। स्रोत: Utah DLD CDL Driving Skills Test पेज (dld.utah.gov/cdl-driving-test)।"},"94":{"q":"यूटा स्किल्स परीक्षा का प्री-ट्रिप निरीक्षण भाग मुख्य रूप से किसका मूल्यांकन करता है?","options":["इस बारे में आपका ज्ञान कि क्या वाहन चलाने के लिए सुरक्षित है","वाहन को किसी डॉक में बैक करने की आपकी क्षमता","भारी यातायात में आपका प्रतिक्रिया समय","यातायात कानूनों का आपका लिखित ज्ञान"],"explanation":"प्री-ट्रिप निरीक्षण आवेदक के इस ज्ञान का परीक्षण करता है कि क्या वाहन चलाने के लिए सुरक्षित है, जिसमें इंजन, ट्रैक्टर, ट्रेलर, लाइटें, गेज, सुरक्षा उपकरण, और यदि लगे हों तो एयर ब्रेक जैसी वस्तुएँ शामिल हैं। स्रोत: Utah DLD CDL Driving Skills Test पेज (dld.utah.gov/cdl-driving-test)।"},"95":{"q":"यूटा CDL स्किल्स परीक्षा के बेसिक कंट्रोल स्किल्स भाग को पास करने के लिए, आप कितने एरर पॉइंट जमा कर सकते हैं?","options":["आठ या उससे कम एरर पॉइंट","बारह या उससे कम एरर पॉइंट","तीस या उससे कम एरर पॉइंट","शून्य एरर पॉइंट"],"explanation":"यूटा की बेसिक कंट्रोल स्किल्स परीक्षा (फॉरवर्ड स्टॉप, सीधी-रेखा बैकिंग, फॉरवर्ड ऑफसेट ट्रैकिंग, रिवर्स ऑफसेट बैकिंग) को पास करने के लिए आठ या उससे कम एरर पॉइंट आवश्यक हैं। ऑन-रोड परीक्षा में 30 तक की अनुमति है। स्रोत: Utah DLD CDL Driving Skills Test पेज (dld.utah.gov/cdl-driving-test)।"},"96":{"q":"यूटा CDL स्किल्स परीक्षा के ऑन-रोड ड्राइविंग भाग को पास करने के लिए, आप कितने एरर पॉइंट जमा कर सकते हैं?","options":["तीस या उससे कम एरर पॉइंट","आठ या उससे कम एरर पॉइंट","पंद्रह या उससे कम एरर पॉइंट","पचास या उससे कम एरर पॉइंट"],"explanation":"यूटा की ऑन-रोड ड्राइविंग परीक्षा, जो यह जाँचती है कि क्या आपके पास अधिकांश यातायात स्थितियों में गाड़ी चलाने के न्यूनतम कौशल हैं, पास करने के लिए 30 या उससे कम एरर पॉइंट की आवश्यकता होती है। बेसिक कंट्रोल स्किल्स परीक्षा में केवल आठ की अनुमति है। स्रोत: Utah DLD CDL Driving Skills Test पेज (dld.utah.gov/cdl-driving-test)।"},"97":{"q":"CDL स्किल्स (ड्राइविंग) परीक्षा देने के लिए यूटा किसी आवेदक से क्या प्रदान करने की अपेक्षा करता है?","options":["उचित श्रेणी का आपका अपना पंजीकृत, सड़क-तैयार वाहन","Driver License Division द्वारा आपूर्ति किया गया एक वाहन","किसी UDOT मोटर पूल से उधार लिया गया एक वाहन","केवल एक वैध CLP, क्योंकि राज्य वाहन प्रदान करता है"],"explanation":"यूटा के लिए आवश्यक है कि आवेदक अपना स्वयं का पंजीकृत और सड़क-तैयार वाहन लाए जो प्राप्त किए जा रहे CDL की श्रेणी का प्रतिनिधित्व करता हो। DLD परीक्षण वाहन प्रदान नहीं करता। स्रोत: Utah DLD CDL Driving Skills Test पेज (dld.utah.gov/cdl-driving-test)।"},"98":{"q":"मानक नवीनीकरण चक्र के तहत किसी यूटा CDL धारक को लाइसेंस का नवीनीकरण कितनी बार करना चाहिए?","options":["हर पाँच वर्ष में","हर चार वर्ष में","हर आठ वर्ष में","हर दो वर्ष में"],"explanation":"यूटा CDL पाँच-वर्षीय नवीनीकरण चक्र का पालन करते हैं, और प्रत्येक नवीनीकरण के लिए एक अद्यतन आवेदन के साथ वर्तमान स्व-प्रमाणन और मेडिकल दस्तावेज़ीकरण की आवश्यकता होती है। स्रोत: Utah DLD CDL नवीनीकरण जानकारी (dld.utah.gov) और Utah Uniform Commercial Driver License Act, UCA 53-3-400 et seq।"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة التجارية وحمولتها على طرق ولاية يوتا السريعة دون تصريح؟","options":["8 أقدام و6 بوصات","8 أقدام و0 بوصة","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"تحدّ ولاية يوتا عرض المركبة بمقدار 8 أقدام و6 بوصات (102 inches)، مقيسًا من الخارج إلى الخارج عند أعرض النقاط، سواء مع حمولة أو بدونها. المصدر: Utah Admin. Code R909-2-4؛ صفحة UDOT Legal Height, Width & Length."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة والحمولة على طرق ولاية يوتا السريعة دون تصريح للأحجام الزائدة؟","options":["14 قدمًا","13 قدمًا و6 بوصات","15 قدمًا","13 قدمًا"],"explanation":"الحد الأقصى القانوني للارتفاع في ولاية يوتا هو 14 قدمًا، مقيسًا من مستوى سطح الطريق إلى أعلى الحمولة أو المركبة. المصدر: Utah Admin. Code R909-2-4؛ صفحة UDOT Legal Height, Width & Length."},"2":{"q":"ما هو الحد الأقصى القانوني للوزن الإجمالي للمركبة على طرق ولاية يوتا السريعة دون تصريح للأوزان الزائدة؟","options":["80,000 رطل","78,000 رطل","84,000 رطل","76,000 رطل"],"explanation":"تحدّ ولاية يوتا الوزن الإجمالي القانوني للمركبة بمقدار 80,000 رطل، بما يتوافق مع الحد الفيدرالي، رهنًا بحدود المحور وصيغة الجسر. المصدر: Utah Code 72-7-404؛ منح تصاريح الحجم/الوزن لدى UDOT."},"3":{"q":"على طرق ولاية يوتا السريعة، ما هو الحد الأقصى القانوني للحمولة على محور واحد دون تصريح؟","options":["20,000 رطل","18,000 رطل","22,400 رطل","24,000 رطل"],"explanation":"تحدّ ولاية يوتا المحور الواحد بمقدار 20,000 رطل. المصدر: Utah Code 72-7-404(1)؛ Utah Admin. Code R909-2."},"4":{"q":"على طرق ولاية يوتا السريعة، ما هو الحد الأقصى القانوني للحمولة على مجموعة محاور مترادفة (تاندم) دون تصريح؟","options":["34,000 رطل","32,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تحدّ ولاية يوتا المحور المترادف بمقدار 34,000 رطل. المصدر: Utah Code 72-7-404(1)؛ منح تصاريح الحجم/الوزن لدى UDOT."},"5":{"q":"ما هو الحد الأقصى القانوني لطول المركبة الآلية المفردة (المستقيمة) على طرق ولاية يوتا السريعة؟","options":["45 قدمًا","40 قدمًا","53 قدمًا","48 قدمًا"],"explanation":"لا يجوز أن يتجاوز طول المركبة الآلية المفردة في ولاية يوتا 45 قدمًا، باستثناء الأجزاء البارزة. المصدر: Utah Admin. Code R909-2-4."},"6":{"q":"ما هو الحد الأقصى القانوني لطول المقطورة النصفية المُشغَّلة ضمن تركيبة جرّار-مقطورة نصفية على طرق ولاية يوتا السريعة؟","options":["53 قدمًا","48 قدمًا","57 قدمًا","45 قدمًا"],"explanation":"تسمح ولاية يوتا بمقطورة نصفية يصل طولها إلى 53 قدمًا ضمن تركيبة جرّار-مقطورة نصفية. المصدر: Utah Admin. Code R909-2-4؛ UDOT Legal Height, Width & Length."},"7":{"q":"بموجب قانون ولاية يوتا، إلى أي مدى يجوز أن تمتد الحمولة إلى ما هو أبعد من مقدمة وحدة القدرة قبل أن يُطلب تصريح للأحجام الزائدة؟","options":["3 أقدام","4 أقدام","5 أقدام","قدمان"],"explanation":"لا يجوز للمركبة أن تحمل حمولة تمتد أكثر من 3 أقدام إلى ما هو أبعد من مقدمة وحدة القدرة دون تصريح. المصدر: حكم الامتداد في Utah Admin. Code R909-2-4."},"8":{"q":"بموجب قانون ولاية يوتا، إلى أي مدى يجوز أن تمتد الحمولة إلى ما هو أبعد من مؤخرة المنصة أو الهيكل قبل أن يُطلب تصريح للأحجام الزائدة؟","options":["6 أقدام","4 أقدام","8 أقدام","3 أقدام"],"explanation":"لا يجوز أن تمتد الحمولة أكثر من 6 أقدام إلى ما هو أبعد من مؤخرة المنصة أو الهيكل دون تصريح. المصدر: حكم الامتداد في Utah Admin. Code R909-2-4."},"9":{"q":"ما هو الحد الأقصى لطول المقطورات مجتمعةً لتركيبة المقطورة المزدوجة (المقطورتين التوأم) على طرق ولاية يوتا السريعة؟","options":["61 قدمًا","65 قدمًا","53 قدمًا","68 قدمًا"],"explanation":"تسمح ولاية يوتا بحد أقصى قدره 61 قدمًا لطول المقطورات مجتمعةً لتركيبات المقطورة المزدوجة. المصدر: Utah Admin. Code R909-2-4."},"10":{"q":"بموجب Utah Code 72-7-404، ما هو الوزن الأقصى المسموح به على أي عجلة مفردة من المركبة؟","options":["10,500 رطل","8,000 رطل","12,000 رطل","9,000 رطل"],"explanation":"تحظر ولاية يوتا تشغيل مركبة بوزن إجمالي يتجاوز 10,500 رطل على عجلة واحدة. المصدر: Utah Code 72-7-404(1)."},"11":{"q":"ما هي الصيغة التي تستخدمها ولاية يوتا لتحديد الوزن الإجمالي المسموح به على مجموعة من المحاور المتتالية؟","options":["صيغة الجسر الفيدرالية: W = 500[LN/(N-1) + 12N + 36]","الوزن الإجمالي مقسومًا على عدد الإطارات","20,000 رطل مضروبة في عدد المحاور","مجموع تقييمات المحاور مطروحًا منه 10 في المئة"],"explanation":"تعتمد ولاية يوتا صيغة الجسر الفيدرالية W = 500[LN/(N-1) + 12N + 36]، حيث W هو الوزن الإجمالي، وL هو مسافة مجموعة المحاور، وN هو عدد المحاور. المصدر: Utah Code 72-7-404؛ حاسبة الجسر عبر الإنترنت لدى UDOT."},"12":{"q":"في صيغة الجسر لولاية يوتا W = 500[LN/(N-1) + 12N + 36]، ماذا يمثل المتغير 'L'؟","options":["المسافة بالأقدام بين طرفي مجموعة المحاور","الحد القانوني للحمولة لكل محور","طول المقطورة بالأقدام","عدد المحاور المحمَّلة"],"explanation":"في صيغة الجسر، L هو المسافة بالأقدام بين المحورين الطرفيين للمجموعة، وN هو عدد المحاور، وW هو الوزن الإجمالي الناتج لأقرب 500 رطل. المصدر: Utah Code 72-7-404."},"13":{"q":"بموجب Utah Code 72-7-404، يجوز لمجموعتين متتاليتين من المحاور المترادفة أن تحمل كل منهما 34,000 رطل بشرط أن تكون المسافة بين المحور الأول والأخير للمجموعتين لا تقل عن كم قدمًا؟","options":["36 قدمًا","30 قدمًا","40 قدمًا","44 قدمًا"],"explanation":"يجوز لمجموعتين متتاليتين من المحاور المترادفة أن تحمل كل منهما 34,000 رطل إذا كانت المسافة الكلية بين المحور الأول والأخير للمجموعتين 36 قدمًا أو أكثر. المصدر: Utah Code 72-7-404."},"14":{"q":"متى يُطلب تصريح للأحجام/الأوزان الزائدة من UDOT في ولاية يوتا؟","options":["عندما تتجاوز المركبة أو الحمولة حدود الحجم أو الوزن القانونية في Utah Code 72-7-402 و72-7-404","فقط عند عبور حدود الولاية إلى داخل ولاية يوتا","فقط للحمولات التي تزيد عن 200,000 رطل","فقط عند السفر على الطرق السريعة بين الولايات"],"explanation":"يُطلب تصريح من UDOT كلما تجاوزت المركبة أو الحمولة حدود الحجم و/أو الوزن القانونية المحددة في Utah Code 72-7-402 (الحجم) و72-7-404 (الوزن). المصدر: أحكام UDOT للأحجام والأوزان الزائدة؛ Utah Code 72-7-406."},"15":{"q":"كيف تُصدر UDOT عادةً تصاريح الأحجام/الأوزان الزائدة في ولاية يوتا؟","options":["على أساس رحلة واحدة، أو نصف سنوي، أو سنوي","فقط كتصاريح مدى الحياة","فقط كتصاريح لرحلة واحدة","فقط كتصاريح شهرية"],"explanation":"تصدر UDOT تصاريح الأحجام/الأوزان الزائدة على أساس رحلة واحدة، أو نصف سنوي، أو سنوي، ويتم الحصول عليها من خلال نظام منح التصاريح عبر الإنترنت لدى UDOT (MCS). المصدر: أحكام UDOT للأحجام والأوزان الزائدة؛ Utah Admin. Code R909-2-8."},"16":{"q":"يتوفر تصريح الأوزان الزائدة للحمولة القابلة للتجزئة في ولاية يوتا عمومًا لمركبة أو تركيبة مسجَّلة لأي نطاق وزن إجمالي؟","options":["78,001 إلى 80,000 رطل","60,000 إلى 70,000 رطل","80,001 إلى 90,000 رطل","70,000 إلى 78,000 رطل"],"explanation":"ينطبق تصريح الأوزان الزائدة للحمولة القابلة للتجزئة في ولاية يوتا على المركبات أو التركيبات المسجَّلة بشكل صحيح لوزن 78,001 إلى 80,000 رطل، ويجب أن تظل مستوفية لصيغة الجسر وحدود المحور القانونية. المصدر: Utah Admin. Code R909-2-21؛ أحكام UDOT للحمولة القابلة للتجزئة ذات الأوزان الزائدة."},"17":{"q":"بالنسبة لعمليات شاحنات التبن في ولاية يوتا، يجوز نقل لفّتين أو بالتين من التبن جنبًا إلى جنب بموجب تصريح للأحجام الزائدة لحمولة غير قابلة للتجزئة فقط إذا كان عرضهما مجتمعًا لا يتجاوز كم؟","options":["10 أقدام","8 أقدام و6 بوصات","12 قدمًا","14 قدمًا"],"explanation":"تسمح ولاية يوتا لتركيبات شاحنات التبن بحمل لفّتين أو بالتين جنبًا إلى جنب عندما يكون عرضهما مجتمعًا 10 أقدام أو أقل ويُحمل تصريح ساري المفعول للأحجام الزائدة لحمولة غير قابلة للتجزئة. المصدر: أحكام UDOT/Utah Admin. Code R909-2 الزراعية (شاحنات التبن)."},"18":{"q":"على طريق سريع نموذجي في ولاية يوتا ليس طريقًا مقسومًا/بين الولايات، عند أي عرض تتطلب الحمولة ذات الحجم الزائد عمومًا مركبة مرافقة/إرشادية؟","options":["أكثر من 12 قدمًا","أكثر من 8 أقدام و6 بوصات","أكثر من 14 قدمًا","أكثر من 16 قدمًا"],"explanation":"على الطرق السريعة ذات المسارين (غير المقسومة) في ولاية يوتا تُطلب مركبة مرافقة عمومًا عندما يتجاوز عرض الحمولة 12 قدمًا؛ أما على الطرق السريعة المقسومة/بين الولايات فتكون العتبة أكثر من 14 قدمًا. المصدر: أحكام UDOT/Utah Admin. Code R909-2 المتعلقة بالمرافقة."},"19":{"q":"بموجب أحكام تصريح الأوزان الزائدة للحمولة غير القابلة للتجزئة في ولاية يوتا، ما هو الحد الأقصى لوزن المحور الواحد الذي يجوز لـ UDOT أن تأذن به لحمولة غير قابلة للتجزئة؟","options":["29,000 رطل","24,000 رطل","34,000 رطل","20,000 رطل"],"explanation":"يجوز لـ UDOT إصدار تصاريح أوزان زائدة للحمولات غير القابلة للتجزئة حتى 29,000 رطل على محور واحد، و50,000 رطل على محور مترادف، ووزن إجمالي مصرَّح به يصل إلى 125,000 رطل. المصدر: أحكام UDOT للأحجام والأوزان الزائدة؛ Utah Admin. Code R909-2."},"20":{"q":"في ولاية يوتا، ما هي فئة CDL المطلوبة لتشغيل مركبة تركيبية بتقييم وزن إجمالي للتركيبة قدره 26,001 رطل أو أكثر، حيث تكون الوحدة المقطورة مقيَّمة بأكثر من 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تصدر Utah DLD رخصة CDL من الفئة A للمركبات التركيبية بتقييم وزن إجمالي للتركيبة قدره 26,001 رطل أو أكثر عندما تتجاوز الوحدة المقطورة 10,000 رطل من تقييم الوزن الإجمالي للمركبة (مثل الجرّار-المقطورة). المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info) ودليل Utah CDL Handbook."},"21":{"q":"يشغّل سائق في ولاية يوتا مركبة مفردة (مثل شاحنة قلّابة كبيرة أو حافلة) بتقييم وزن إجمالي للمركبة قدره 26,001 رطل أو أكثر ودون وحدة مقطورة. ما فئة CDL التي يتطلبها ذلك؟","options":["الفئة C","الفئة B","الفئة A","الفئة E"],"explanation":"تغطي رخصة Utah CDL من الفئة B مركبة مفردة بتقييم وزن إجمالي للمركبة قدره 26,001 رطل أو أكثر دون وحدة مقطورة (أو تقطر وحدة وزنها 10,000 رطل أو أقل). المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"22":{"q":"بموجب قواعد ولاية يوتا، تنطبق رخصة CDL من الفئة C على مركبة بتقييم وزن إجمالي للمركبة أقل من 26,001 رطل عندما تكون مصممة لنقل ما لا يقل عن كم راكبًا، بما في ذلك السائق؟","options":["10 ركاب","12 راكبًا","16 راكبًا","24 راكبًا"],"explanation":"تعرّف ولاية يوتا الفئة C بأنها مركبة بتقييم وزن إجمالي أقل من 26,001 رطل تنقل 16 راكبًا أو أكثر بما في ذلك السائق، أو تحمل لافتات تحذيرية للمواد الخطرة. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"23":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة Utah CDL للتشغيل داخل الولاية (القيادة داخل ولاية يوتا فقط)؟","options":["16 عامًا","18 عامًا","19 عامًا","21 عامًا"],"explanation":"تسمح ولاية يوتا برخصة CDL في سن 18 للقيادة داخل الولاية فقط. ويقتصر السائقون دون سن 21 على التشغيل داخل ولاية يوتا. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"24":{"q":"ما هو الحد الأدنى للعمر المطلوب لحمل رخصة Utah CDL صالحة للتشغيل بين الولايات (القيادة عبر حدود الولايات)؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"تتطلب القواعد الفيدرالية التي اعتمدتها ولاية يوتا أن يكون عمر السائق 21 عامًا على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات. ويقتصر السائقون من سن 18 إلى 20 على التشغيل داخل الولاية. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)؛ 49 CFR 391.11."},"25":{"q":"حامل رخصة Utah CDL يبلغ من العمر 19 عامًا لديه قيد K. أي من المصادقات التالية يكون هذا السائق مؤهلًا للحصول عليها؟","options":["المواد الخطرة (H)","الركاب (P)","حافلة المدرسة (S)","صهريج (N)"],"explanation":"يقتصر السائقون دون سن 21 في ولاية يوتا على التشغيل داخل الولاية وهم غير مؤهلين للحصول على مصادقات H (المواد الخطرة) أو P (الركاب) أو S (حافلة المدرسة). أما مصادقة N (الصهريج) فليست ضمن تلك القائمة المحظورة. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"26":{"q":"ما المصادقة التي يحتاجها سائق في ولاية يوتا لنقل المواد الخطرة بكميات تتطلب لافتات تحذيرية؟","options":["مصادقة N","مصادقة T","مصادقة H","مصادقة X"],"explanation":"مصادقة H (المواد الخطرة) مطلوبة لنقل المواد الخطرة بكميات تستلزم لافتات تحذيرية. وتتطلب أيضًا فحص خلفية لتقييم التهديد الأمني من قبل TSA. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"27":{"q":"قبل أن تصدر ولاية يوتا مصادقة المواد الخطرة (H)، يجب على مقدم الطلب اجتياز أي فحص إضافي؟","options":["فحص خلفية فيدرالي لتقييم التهديد الأمني من قبل TSA","اختبار كشف الكذب تجريه الولاية","اختبار نظر يجريه طبيب عيون","دورة لإعادة تأهيل من المخدرات يرعاها صاحب العمل"],"explanation":"تتطلب مصادقة H اجتياز فحص خلفية / تقييم التهديد الأمني من قبل TSA (إدارة أمن النقل) بموجب القانون الفيدرالي، إضافة إلى اختبار المعرفة بالمواد الخطرة. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)؛ 49 CFR 1572."},"28":{"q":"يريد سائق في ولاية يوتا قطر مقطورات مزدوجة وثلاثية. ما المصادقة المطلوبة، وعلى أي فئة CDL يمكن حملها؟","options":["مصادقة T، متاحة فقط على رخصة CDL من الفئة A","مصادقة N، متاحة على الفئة A أو B","مصادقة T، متاحة فقط على رخصة CDL من الفئة B","مصادقة P، متاحة على أي فئة"],"explanation":"تتيح مصادقة T (المزدوجة/الثلاثية) قطر أكثر من مقطورة واحدة ولا يمكن إضافتها إلا إلى رخصة CDL من الفئة A. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info) ودليل Utah CDL Handbook."},"29":{"q":"ما المصادقة التي يحتاجها سائق في ولاية يوتا لتشغيل مركبة صهريجية تُستخدم لنقل السوائل أو الغازات؟","options":["مصادقة P","مصادقة N","مصادقة H","مصادقة T"],"explanation":"مصادقة N (الصهريج) مطلوبة للمركبات التي تنقل السوائل/الغازات في صهريج بسعة مقيَّمة فردية قدرها 119 جالونًا أو أكثر وسعة مقيَّمة إجمالية تزيد عن 1,000 جالون. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"30":{"q":"ما المصادقة المطلوبة قبل أن يتمكن سائق في ولاية يوتا من الحصول على مصادقة حافلة المدرسة (S)؟","options":["مصادقة المواد الخطرة (H)","مصادقة الصهريج (N)","مصادقة الركاب (P)","مصادقة المزدوجة/الثلاثية (T)"],"explanation":"في ولاية يوتا تُضاف مصادقة حافلة المدرسة (S) فوق مصادقة الركاب (P)؛ ويجب على مقدم الطلب أن يكون مؤهلًا لـ P (المعرفة والمهارات) ثم يجتاز اختباري المعرفة والمهارات الإضافيين لـ S. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"31":{"q":"ما المصادقتان اللتان تتطلبان من مقدم الطلب في ولاية يوتا اجتياز اختبار مهارات قيادة إضافة إلى اختبار معرفة تحريري؟","options":["H (المواد الخطرة) وN (الصهريج)","P (الركاب) وS (حافلة المدرسة)","T (المزدوجة/الثلاثية) وN (الصهريج)","H (المواد الخطرة) وT (المزدوجة/الثلاثية)"],"explanation":"في ولاية يوتا تتطلب مصادقتا P (الركاب) وS (حافلة المدرسة) كل منهما اختبار مهارات قيادة في المركبة المناسبة، بينما تتطلب H وN وT اختبار معرفة فقط. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"32":{"q":"بموجب القواعد الفيدرالية التي اعتمدتها ولاية يوتا، كم من الوقت يجب على السائق حمل تصريح المتعلم التجاري (CLP) قبل السماح له بأداء اختبار مهارات قيادة CDL؟","options":["7 أيام","14 يومًا","30 يومًا","60 يومًا"],"explanation":"يجب على مقدم الطلب حمل CLP لمدة 14 يومًا على الأقل قبل أداء اختبار مهارات CDL. وهذا متطلب من FMCSA تطبّقه Utah DLD. المصدر: صفحة Utah DLD CDL Driving Skills Test (dld.utah.gov/cdl-driving-test)؛ 49 CFR 383.25."},"33":{"q":"كم تبلغ مدة صلاحية تصريح المتعلم التجاري (CLP) في ولاية يوتا من تاريخ إصداره؟","options":["90 يومًا","180 يومًا","سنة واحدة","سنتان"],"explanation":"تصريح CLP في ولاية يوتا صالح لمدة 180 يومًا (نحو 6 أشهر). ويمكن تجديده مرة واحدة خلال فترة سنتين. المصدر: صفحة Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"34":{"q":"ما الحد الأدنى للدرجة التي يجب أن يحققها مقدم الطلب لاجتياز اختبار المعرفة التحريري لـ CDL في ولاية يوتا (المعرفة العامة أو اختبار مصادقة)؟","options":["70%","75%","80%","90%"],"explanation":"تتطلب ولاية يوتا درجة 80% لاجتياز أي اختبار معرفة تحريري لـ CDL. المصدر: صفحة Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"35":{"q":"ما اختبار المعرفة الذي يجب على مقدم الطلب في ولاية يوتا اجتيازه أولًا ليُصدر له تصريح المتعلم التجاري؟","options":["اختبار المعرفة العامة المكوَّن من 50 سؤالًا","اختبار المكابح الهوائية المكوَّن من 25 سؤالًا","اختبار المركبات التركيبية المكوَّن من 20 سؤالًا","اختبار المواد الخطرة المكوَّن من 30 سؤالًا"],"explanation":"يؤدي اجتياز اختبار المعرفة العامة المكوَّن من 50 سؤالًا (بدرجة 80%) إلى إصدار تصريح CLP، الذي يكون صالحًا لمدة 180 يومًا. المصدر: صفحة Utah DLD CDL Written Knowledge Test (dld.utah.gov/cdl-written-test)."},"36":{"q":"يجب إكمال تدريب السائق المبتدئ (ELDT) المطلوب لمقدمي طلبات الفئة A أو الفئة B لأول مرة في ولاية يوتا من خلال مزوّد يكون:","options":["معتمدًا من المنطقة التعليمية المحلية","مدرجًا في سجل مزوّدي التدريب التابع لـ FMCSA","معتمدًا من لجنة الضرائب في ولاية يوتا","معتمدًا من وزارة التعليم الأمريكية"],"explanation":"يجب إكمال ELDT من خلال مزوّد مدرج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA قبل اختبار المهارات. وينطبق ELDT على مقدمي طلبات الفئة A/B لأول مرة، والترقية من الفئة B إلى A، ومصادقات H وP وS لأول مرة. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)؛ 49 CFR Part 380."},"37":{"q":"بالنسبة لأي مما يلي لا تتطلب ولاية يوتا تدريب السائق المبتدئ (ELDT)؟","options":["مقدم طلب رخصة CDL من الفئة A لأول مرة","مقدم طلب مصادقة المواد الخطرة (H) لأول مرة","إضافة مصادقة الصهريج (N)","مقدم طلب مصادقة حافلة المدرسة (S) لأول مرة"],"explanation":"ينطبق ELDT الفيدرالي على رخص CDL من الفئة A/B لأول مرة، والترقية من الفئة B إلى A، ومصادقات H وP وS لأول مرة. أما مصادقتا N (الصهريج) وT (المزدوجة/الثلاثية) فليستا خاضعتين لـ ELDT. المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)؛ 49 CFR Part 380."},"38":{"q":"عند التقدم بطلب للحصول على رخصة Utah CDL، ما مجموعة المستندات التي يجب على مقدم الطلب تقديمها لقسم رخص السائقين؟","options":["إثبات الهوية والوجود القانوني، ورقم الضمان الاجتماعي الكامل، ومستندان يثبتان الإقامة في ولاية يوتا","جواز سفر فقط","شهادة الثانوية العامة وفاتورة خدمات واحدة","تسجيل المركبة وإثبات التأمين فقط"],"explanation":"تتطلب Utah DLD إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي الكامل لمقدم الطلب، ومستندين يثبتان الإقامة في ولاية يوتا (إضافة إلى شهادة طبية سارية حيثما تُطلب). المصدر: صفحة Utah DLD CDL Information (dld.utah.gov/cdl-info)."},"39":{"q":"مقدم طلب رخصة Utah CDL يقود داخل ولاية يوتا فقط وينقل بضائع غير معفاة، ويحمل بطاقة طبية سارية من DOT، تحت أي فئة ينبغي أن يصادق ذاتيًا؟","options":["غير معفى بين الولايات","معفى بين الولايات","غير معفى داخل الولاية","معفى داخل الولاية"],"explanation":"تستخدم ولاية يوتا أربع فئات للمصادقة الذاتية. السائق الذي يعمل داخل ولاية يوتا فقط في تجارة غير معفاة يصادق على أنه غير معفى داخل الولاية. تنطبق فئات بين الولايات على القيادة عبر حدود الولايات؛ وتنطبق الفئات المعفاة على عمليات محددة معفاة فيدراليًا. المصدر: صفحة Utah DLD CDL Self-Certification (dld.utah.gov/cdl-self-certification)."},"40":{"q":"في ولاية يوتا، ما هو تركيز الكحول في الدم/النفَس (BAC) الذي يُحظر عنده أو فوقه على الشخص تشغيل مركبة آلية تجارية (CMV)؟","options":["0.04","0.08","0.02","0.05"],"explanation":"يجعل Utah Code 53-3-414(1)(a)(ii) من قيادة مركبة آلية تجارية بتركيز كحول قدره 0.04 غرام أو أكثر جريمة كبرى. وينطبق حد 0.08 فقط على القيادة غير التجارية. المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"41":{"q":"أُدين سائق رخصة Utah CDL بأول جريمة كبرى (مثل قيادة مركبة آلية تجارية بتركيز كحول قدره 0.04 أو أكثر) ولم يكن ينقل مواد خطرة تحمل لافتات تحذيرية. ما الحد الأدنى لمدة إلغاء أهلية CDL؟","options":["سنة واحدة","60 يومًا","3 سنوات","6 أشهر"],"explanation":"بموجب Utah Code 53-3-414(1)(a)، تؤدي أول جريمة كبرى إلى إلغاء الأهلية لمدة لا تقل عن سنة واحدة. المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"42":{"q":"إذا ارتكب سائق رخصة Utah CDL أول جريمة كبرى (مثل القيادة تحت تأثير الكحول) أثناء نقل مادة خطرة يجب أن تحمل لافتات تحذيرية، فإلى أي مدة يزداد الحد الأدنى لإلغاء الأهلية؟","options":["3 سنوات","سنة واحدة","سنتان","مدى الحياة"],"explanation":"يرفع Utah Code 53-3-414(2) الحد الأدنى لإلغاء الأهلية عن أول جريمة كبرى إلى ما لا يقل عن ثلاث سنوات عندما تقع الجريمة أثناء نقل مواد خطرة تحمل لافتات تحذيرية. المصدر: Utah Code 53-3-414."},"43":{"q":"ماذا يحدث لحامل رخصة Utah CDL الذي يُدان بثاني جريمة كبرى ناشئة عن حادثة منفصلة؟","options":["إلغاء الأهلية مدى الحياة من قيادة مركبة آلية تجارية","إلغاء الأهلية لمدة 3 سنوات","إلغاء الأهلية لمدة سنة واحدة","إلغاء الأهلية لمدة 120 يومًا"],"explanation":"ينص Utah Code 53-3-414(3)(a) على أن جريمتين كبريين أو أكثر من حوادث منفصلة تؤديان إلى إلغاء الأهلية مدى الحياة من قيادة مركبة آلية تجارية. المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"44":{"q":"بموجب قواعد الموافقة الضمنية في ولاية يوتا، ما هي عاقبة سائق CDL الذي يرفض الخضوع لاختبار كيميائي لتركيز الكحول أو المخدرات؟","options":["يُعامَل كجريمة كبرى، تُلغي أهلية CDL لمدة سنة واحدة على الأقل","تحذير فقط عند الرفض الأول","إلغاء الأهلية لمدة 60 يومًا","غرامة قدرها 500 دولار دون إلغاء الأهلية"],"explanation":"يدرج Utah Code 53-3-414(1)(a)(vi) رفض الخضوع لاختبار كيميائي كجريمة كبرى، يحمل الحد الأدنى نفسه لإلغاء الأهلية وهو سنة واحدة (3 سنوات إذا كانت مواد خطرة تحمل لافتات تحذيرية). المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"45":{"q":"كم عدد مخالفات المرور الخطيرة خلال فترة ثلاث سنوات التي تستوجب إلغاء أهلية CDL لمدة 60 يومًا في ولاية يوتا؟","options":["2","3","1","4"],"explanation":"يتطلب Utah Code 53-3-414(6)(a)(i) إلغاء الأهلية لمدة لا تقل عن 60 يومًا عن مخالفتين خطيرتين للمرور تقعان خلال ثلاث سنوات. المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"46":{"q":"في ولاية يوتا، يُلغى تأهيل سائق CDL المُدان بثلاث مخالفات مرور خطيرة أو أكثر خلال فترة ثلاث سنوات لمدة لا تقل عن كم؟","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"يفرض Utah Code 53-3-414(6)(a)(ii) إلغاء الأهلية لمدة لا تقل عن 120 يومًا عن ثلاث مخالفات مرور خطيرة أو أكثر خلال ثلاث سنوات. المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"47":{"q":"أي مما يلي يُصنَّف كمخالفة مرور خطيرة لسائق Utah CDL؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد المقرر","تجاوز السرعة بمقدار 5 mph فوق الحد المقرر","مخالفة وقوف","القيادة بسرعة 3 mph دون الحد"],"explanation":"وفقًا لـ Utah CDL Manual وقائمة رموز المخالفات (ACD) في ولاية يوتا، يُعد تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد مخالفة مرور خطيرة. أما تجاوز السرعة الأقل والوقوف فليسا خطيرين. المصدر: Utah CDL Manual؛ 49 CFR 383.51 المطبَّق في ولاية يوتا."},"48":{"q":"أي فعل يُحتسب كمخالفة مرور خطيرة قد تسهم في إلغاء أهلية Utah CDL؟","options":["إرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة آلية تجارية","استخدام هاتف بدون استخدام اليدين أثناء قيادة مركبة آلية تجارية","الأكل أثناء قيادة مركبة آلية تجارية","الاستماع إلى الراديو أثناء قيادة مركبة آلية تجارية"],"explanation":"تتبع ولاية يوتا القائمة الفيدرالية للمخالفات الخطيرة (49 CFR 383.51): إرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء تشغيل مركبة آلية تجارية هو مخالفة مرور خطيرة. أما الاستخدام بدون استخدام اليدين فليس كذلك. المصدر: Utah CDL Manual؛ 49 CFR 383.51."},"49":{"q":"أُدين سائق رخصة Utah CDL بأول مخالفة لأمر إيقاف عن الخدمة (OOS) أثناء قيادة مركبة آلية تجارية (دون مواد خطرة، وليست حافلة كبيرة). ما الحد الأدنى لإلغاء الأهلية بموجب قانون ولاية يوتا؟","options":["180 يومًا","90 يومًا","60 يومًا","سنة واحدة"],"explanation":"يحدد Utah Code 53-3-414(7)(a)(i) الحد الأدنى لإلغاء الأهلية عن أول مخالفة لأمر الإيقاف عن الخدمة بـ 180 يومًا، وهو ما يتجاوز الحد الأدنى الفيدرالي البالغ 90 يومًا. المصدر: Utah Code 53-3-414."},"50":{"q":"إلى جانب إلغاء الأهلية، ما الحد الأدنى للغرامة المدنية التي يفرضها قانون ولاية يوتا على سائق CDL المُدان بأول مخالفة لأمر الإيقاف عن الخدمة؟","options":["$2,500","$1,000","$5,000","$500"],"explanation":"يتطلب Utah Code 53-3-414(7)(b) غرامة مدنية لا تقل عن $2,500 عن أول مخالفة لأمر الإيقاف عن الخدمة. المصدر: Utah Code 53-3-414."},"51":{"q":"بموجب قانون ولاية يوتا، الحد الأدنى للغرامة المدنية عن ثاني مخالفة لأمر الإيقاف عن الخدمة لسائق CDL أو ما يليها لا يقل عن:","options":["$5,000","$2,500","$3,500","$10,000"],"explanation":"يحدد Utah Code 53-3-414(7)(c) الغرامة المدنية بما لا يقل عن $5,000 عن ثاني مخالفة لأمر الإيقاف عن الخدمة أو ما يليها. المصدر: Utah Code 53-3-414."},"52":{"q":"أُدين سائق رخصة Utah CDL بثاني مخالفة لأمر الإيقاف عن الخدمة، في حادثة منفصلة، خلال فترة 10 سنوات. ما الحد الأدنى لإلغاء الأهلية؟","options":["سنتان","سنة واحدة","180 يومًا","3 سنوات"],"explanation":"يتطلب Utah Code 53-3-414(7)(a)(ii) إلغاء الأهلية لمدة لا تقل عن سنتين عن ثاني مخالفة لأمر الإيقاف عن الخدمة في حوادث منفصلة خلال أي فترة 10 سنوات. المصدر: Utah Code 53-3-414."},"53":{"q":"بموجب قانون ولاية يوتا، تؤدي ثالث مخالفة لأمر الإيقاف عن الخدمة أو ما يليها في حوادث منفصلة خلال فترة 10 سنوات إلى إلغاء الأهلية لمدة:","options":["3 إلى 5 سنوات","1 إلى 2 سنة","180 يومًا إلى سنة واحدة","10 سنوات"],"explanation":"يتطلب Utah Code 53-3-414(7)(a)(iii) إلغاء الأهلية لمدة لا تقل عن ثلاث سنوات ولا تزيد عن خمس سنوات عن ثلاث مخالفات أو أكثر لأمر الإيقاف عن الخدمة خلال أي فترة 10 سنوات. المصدر: Utah Code 53-3-414."},"54":{"q":"أُدين سائق رخصة Utah CDL بأول مخالفة عبور مزلقان سكة حديد-طريق أثناء قيادة مركبة آلية تجارية. ما الحد الأدنى لإلغاء الأهلية؟","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"يفرض Utah Code 53-3-414(9)(a) إلغاء الأهلية لمدة لا تقل عن 60 يومًا عن أول مخالفة عبور مزلقان سكة حديد-طريق. المصدر: Utah Code 53-3-414؛ Utah CDL Manual."},"55":{"q":"عن ثاني مخالفة عبور مزلقان سكة حديد-طريق خلال فترة ثلاث سنوات (حوادث منفصلة)، يُلغى تأهيل سائق Utah CDL لمدة لا تقل عن:","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"يتطلب Utah Code 53-3-414(9)(b) إلغاء الأهلية لمدة لا تقل عن 120 يومًا عن ثاني مخالفة عبور مزلقان خلال أي فترة ثلاث سنوات. المصدر: Utah Code 53-3-414."},"56":{"q":"يُلغى تأهيل سائق رخصة Utah CDL المُدان بثالث مخالفة عبور مزلقان سكة حديد-طريق أو ما يليها خلال فترة ثلاث سنوات (حوادث منفصلة) لمدة لا تقل عن:","options":["سنة واحدة","120 يومًا","60 يومًا","3 سنوات"],"explanation":"يتطلب Utah Code 53-3-414(9)(c) إلغاء الأهلية لمدة لا تقل عن سنة واحدة عن ثلاث مخالفات عبور مزلقان أو أكثر خلال أي فترة ثلاث سنوات. المصدر: Utah Code 53-3-414."},"57":{"q":"إذا أظهر فحص سائق مركبة آلية تجارية ملزَم بحمل رخصة CDL وجود أي كمية قابلة للكشف من الكحول دون 0.04، ما الإجراء الذي يُتخذ؟","options":["يُوضَع خارج الخدمة لمدة 24 ساعة","إلغاء فوري لأهلية CDL لمدة سنة واحدة","إلغاء أهلية CDL لمدة 60 يومًا","لا إجراء لأنه أقل من 0.04"],"explanation":"تتبع ولاية يوتا القاعدة الفيدرالية (49 CFR 392.5): يجب وضع سائق مركبة آلية تجارية لديه أي كحول قابل للكشف دون 0.04 خارج الخدمة لمدة 24 ساعة. أما قراءة 0.04 أو أعلى فهي جريمة كبرى. المصدر: Utah CDL Manual؛ 49 CFR 392.5."},"58":{"q":"في ولاية يوتا، ما الحد الأدنى لإلغاء أهلية CDL عن استخدام مركبة آلية تجارية في ارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها؟","options":["مدى الحياة، دون إمكانية لإعادة التأهيل","سنة واحدة","3 سنوات","10 سنوات"],"explanation":"يفرض Utah Code 53-3-414(5) و414(3)(b) إلغاء الأهلية مدى الحياة دون أي أهلية لإعادة التأهيل عند استخدام مركبة آلية تجارية في جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها. المصدر: Utah Code 53-3-414."},"59":{"q":"يتلقى حامل رخصة Utah CDL إلغاء أهلية مدى الحياة يكون مؤهلًا لإعادة التأهيل. ما الحد الأدنى لمدة إلغاء الأهلية التي يجب قضاؤها قبل التقدم بطلب لإعادة تأهيل CDL؟","options":["10 سنوات","5 سنوات","3 سنوات","15 سنة"],"explanation":"يسمح Utah Code 53-3-414(4)(a) للسائق بالتقدم بطلب لإعادة التأهيل فقط بعد قضاء حد أدنى لإلغاء الأهلية قدره 10 سنوات وإكمال برنامج إعادة تأهيل معتمد يستوفي 49 CFR 383.51. المصدر: Utah Code 53-3-414."},"60":{"q":"بموجب قانون \"أفسح المجال\" (Move Over) في ولاية يوتا، عندما يقترب سائق تجاري من شاحنة قطر متوقفة أو مركبة صيانة طرق سريعة تُظهر أضواءً كهرمانية وامضة على طريق سريع متعدد المسارات، ماذا يجب على السائق أن يفعل؟","options":["تخفيف السرعة، وإذا كان ذلك عملياً وآمناً، الانتقال إلى مسار غير مجاور للمركبة المتوقفة","الحفاظ على السرعة مع إطلاق البوق لتحذير العمال","التوقف توقفاً تاماً حتى تغادر المركبة المتوقفة الكتف","لا شيء، لأن القانون ينطبق فقط على الشرطة وسيارات الإسعاف"],"explanation":"يتطلب قانون يوتا 41-6a-904 (قانون \"أفسح المجال\") من السائق الذي يقترب من مركبة طوارئ مرخّصة متوقفة، أو شاحنة قطر/سحب، أو مركبة صيانة طرق ذات أضواء وامضة، أن يخفف السرعة، وإذا كان يسير في مسار مجاور وكان ذلك عملياً مع المراعاة الواجبة للسلامة، أن ينتقل إلى مسار غير مجاور للمركبة المتوقفة. المصدر: قانون يوتا 41-6a-904."},"61":{"q":"قانون \"أفسح المجال\" في يوتا (41-6a-904) يحدد إلى أي سرعة رقمية يجب على السائق أن يبطئ عند تجاوز مركبة طوارئ أو صيانة متوقفة؟","options":["لا يُحدَّد أي رقم ثابت؛ يتطلب القانون من السائق \"تخفيف السرعة\"","بالضبط 20 mph أقل من الحد المعلن","25 mph ثابتة بغض النظر عن الحد المعلن","بالضبط 10 mph في جميع الحالات"],"explanation":"لا يحدد قانون يوتا 41-6a-904 رقماً ثابتاً بوحدة mph. بل يتطلب من السائق تخفيف السرعة، وإتاحة أكبر مساحة ممكنة عملياً، وتغيير المسار بعيداً عن المركبة المتوقفة عندما يكون ذلك عملياً. المصدر: قانون يوتا 41-6a-904."},"62":{"q":"على طريق سريع في يوتا به أكثر من مسار في الاتجاه نفسه، تُتجاوَز مركبة تجارية تسير في المسار الأيسر للأغراض العامة من قبل مركبة أسرع خلفها. ماذا يتطلب قانون يوتا؟","options":["الانتقال بأمان إلى مسار على اليمين وعدم إعاقة التدفق الحر لحركة المرور في المسار الأيسر","البقاء في المسار لأن الشاحنة تسير بالفعل عند الحد الأقصى للسرعة المعلن","زيادة السرعة إلى ما لا يقل عن 5 mph فوق الحد لإخلاء المسار","الانتقال يساراً إلى كتف الجزيرة الوسطى للسماح للمركبة بالمرور"],"explanation":"ينص قانون يوتا 41-6a-704 على أن السائق في المسار الأيسر للأغراض العامة الذي تتجاوزه مركبة أخرى يجب أن يفسح المجال بالانتقال بأمان إلى مسار على اليمين، ولا يجوز له إعاقة حركة أو التدفق الحر لحركة المرور في المسار الأيسر؛ والمخالفة تُعَدّ مخالفة بسيطة (infraction). المصدر: قانون يوتا 41-6a-704."},"63":{"q":"ما هو الحد الأقصى المعلن للسرعة الذي قد يواجهه السائق التجاري قانونياً على طريق سريع بين الولايات (interstate) ريفي في يوتا؟","options":["80 mph حيث يكون معلناً","65 mph كحد أقصى على مستوى الولاية لجميع الشاحنات","70 mph كحد أقصى لأي مركبة","85 mph حيث يكون معلناً"],"explanation":"تعلن يوتا 80 mph على مقاطع محددة من الطرق السريعة بين الولايات الريفية (75 mph هي القيمة الافتراضية الشائعة)، وهي الأعلى في الولاية. المصدر: قانون يوتا 41-6a-601/604 والحدود المعلنة من قبل وزارة النقل في يوتا (Utah DOT)."},"64":{"q":"كيف تتعامل يوتا مع حدود سرعة الشاحنات مقارنةً بحدود سيارات الركاب على الطرق السريعة بين الولايات؟","options":["تتبع الشاحنات الحد المعلن نفسه؛ لا تضع يوتا حداً منفصلاً أدنى لسرعة الشاحنات على مستوى الولاية","الشاحنات محددة بسرعة 55 mph على مستوى الولاية بغض النظر عن الحد المعلن","يجب على الشاحنات دائماً السير 15 mph أقل من حد سرعة السيارات المعلن","الشاحنات محددة بسرعة 60 mph على جميع الطرق السريعة بين الولايات"],"explanation":"على عكس الولايات ذات الحدود المنقسمة مثل كاليفورنيا، لا تفرض يوتا حداً منفصلاً أدنى لسرعة الشاحنات على مستوى الولاية؛ فالمركبات التجارية تلتزم بالحد المعلن نفسه (حتى 80 mph). تنطبق فقط تخفيضات سرعة الشاحنات المعلنة محلياً على بعض المنحدرات. المصدر: قانون يوتا الباب 41 الفصل 6a الجزء 6 ووزارة النقل في يوتا (Utah DOT)."},"65":{"q":"عند معبر سكة حديد على مستوى الطريق في يوتا، يجب على سائق حافلة تقل ركاباً أو مركبة تحمل لافتات مواد خطرة (HazMat) أن يوقف المركبة ضمن أي مسافة من أقرب قضيب سكة؟","options":["ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب سكة","ضمن 25 feet ولكن ليس أقل من 5 feet من أقرب قضيب سكة","ضمن 100 feet ولكن ليس أقل من 50 feet من أقرب قضيب سكة","ضمن 75 feet ولكن ليس أقل من 25 feet من أقرب قضيب سكة"],"explanation":"يجب على الحافلات التي تقل ركاباً والمركبات التي تحمل لافتات HazMat أن تتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب سكة، ثم تنظر وتستمع قبل العبور. المصدر: دليل CDL في يوتا (DLD) و 49 CFR 392.10 كما هو مطبق في يوتا."},"66":{"q":"أي من هذه المركبات التجارية في يوتا مطلوب منها التوقف عند كل معبر سكة حديد (حيث لا تكون معفاة)؟","options":["حافلة تقل ركاباً ومركبة تعرض لافتات HazMat","أي جرّار-مقطورة ينقل بضائع عامة","فقط المركبات التي يزيد وزنها على 26,001 pounds","فقط التركيبات ثلاثية المقطورات"],"explanation":"تتبع يوتا القاعدة الفيدرالية: فقط الحافلات التي تقل ركاباً والمركبات التي تحمل لافتات HazMat يجب أن تتوقف عند معابر السكك الحديدية؛ ومعظم المركبات التجارية الأخرى غير مطالبة بالتوقف. المصدر: دليل CDL في يوتا (DLD)؛ 49 CFR 392.10."},"67":{"q":"عند التوقف لمعبر سكة حديد في مركبة تحمل لافتات HazMat في يوتا، قبل أن يكون أي جزء من المركبة على القضبان، ما الذي يجب على السائق ألا يفعله من بين ما يلي؟","options":["تغيير التروس أثناء عبور أي جزء من المركبة للقضبان","النظر والاستماع في كلا الاتجاهين بحثاً عن قطار قادم","تشغيل الأضواء الوامضة الرباعية عند الاقتراب","اختيار نقطة عبور يمكن للمركبة فيها إخلاء القضبان دون توقف"],"explanation":"يجب على سائق المركبة التجارية ألا يغيّر التروس أبداً أثناء وجود أي جزء من المركبة على القضبان، لأن نقلة تروس فاشلة قد تعطّل المركبة على المعبر. المصدر: دليل CDL في يوتا (DLD)، قسم معابر السكك الحديدية."},"68":{"q":"على طريق غير مقسوم ذي مسارين باتجاهين في يوتا، تتوقف حافلة مدرسية وتعرض أضواءً حمراء وامضة متناوبة. ماذا يجب على السائق المقترب من الاتجاه المعاكس أن يفعل؟","options":["التوقف قبل الوصول إلى الحافلة والبقاء متوقفاً حتى تتوقف الأضواء الحمراء عن الوميض","التباطؤ إلى 20 mph والتجاوز بحذر من اليسار","المتابعة بشكل طبيعي لأن حركة المرور القادمة ليست مطالبة بالتوقف أبداً","التوقف فقط إذا كان الأطفال ظاهرين على الطريق"],"explanation":"يتطلب قانون يوتا 41-6a-1302 من حركة المرور في كلا الاتجاهين التوقف لحافلة مدرسية تعرض أضواءً حمراء وامضة، وعدم المتابعة حتى تتوقف الأضواء الحمراء. المصدر: قانون يوتا 41-6a-1302."},"69":{"q":"تتوقف حافلة مدرسية وتومض بأضواء حمراء على الجانب البعيد من جزيرة وسطى مرتفعة ومزروعة تقسم الطريق السريع. سائق مركبة تجارية يتحرك في الاتجاه المعاكس على الجانب الآخر من تلك الجزيرة الوسطى، ماذا يُطلب منه بموجب قانون يوتا؟","options":["المتابعة، لأن استثناء الطريق السريع المقسوم بجزيرة وسطى ينطبق على حركة المرور في الاتجاه المعاكس","التوقف، لأن جميع حركة المرور يجب أن تتوقف دائماً للأضواء الحمراء الوامضة","التوقف فقط إذا كانت الحافلة ضمن 100 feet","التباطؤ إلى 15 mph دون الحاجة إلى التوقف"],"explanation":"لأن الطريق السريع مقسوم بجزء فاصل محدد بوضوح (الجزيرة الوسطى المرتفعة)، يسمح قانون يوتا 41-6a-1302 لحركة المرور في الاتجاه المعاكس بالمتابعة دون توقف. المصدر: قانون يوتا 41-6a-1302."},"70":{"q":"ما لون أضواء الحافلة المدرسية الوامضة الذي يشير إلى أن الحافلة تستعد للتوقف وأن على السائقين التباطؤ والاستعداد للتوقف في يوتا؟","options":["أضواء كهرمانية (صفراء) وامضة متناوبة","أضواء حمراء وامضة متناوبة","أضواء زرقاء ثابتة","أضواء خضراء وامضة متناوبة"],"explanation":"في يوتا، تحذّر الأضواء الكهرمانية (الصفراء) الوامضة من أن الحافلة على وشك التوقف؛ أما الأضواء الحمراء الوامضة مع ذراع التوقف الممتد فتُلزم حركة المرور بالتوقف. المصدر: قانون يوتا 41-6a-1302؛ دليل CDL في يوتا، قسم الحافلات المدرسية."},"71":{"q":"عندما تتوقف مركبة تجارية على كتف طريق سريع مقسوم أو أحادي الاتجاه في يوتا، أين يجب على السائق أن يضع مثلثات التحذير الطارئة الثلاثة؟","options":["حوالي 10 و100 و200 feet خلف المركبة باتجاه حركة المرور القادمة","حوالي 10 و50 و150 feet خلف المركبة باتجاه حركة المرور القادمة","حوالي 25 و75 و125 feet خلف المركبة باتجاه حركة المرور القادمة","حوالي 50 و100 و250 feet خلف المركبة باتجاه حركة المرور القادمة"],"explanation":"على طريق سريع مقسوم أو أحادي الاتجاه، تُوضع المثلثات على بُعد حوالي 10 ft و100 ft و200 ft باتجاه حركة المرور القادمة. المصدر: دليل CDL في يوتا (DLD)؛ 49 CFR 392.22."},"72":{"q":"بعد توقف مركبة تجارية على طريق في يوتا، خلال كم دقيقة يجب على السائق أن يكون قد وضع أجهزة التحذير الطارئة (المثلثات)؟","options":["خلال 10 دقائق","خلال دقيقتين (2)","خلال 5 دقائق","خلال 30 دقيقة"],"explanation":"يجب وضع أجهزة التحذير خلال 10 دقائق من التوقف. المصدر: دليل CDL في يوتا (DLD)؛ 49 CFR 392.22."},"73":{"q":"على طريق مستقيم ومستوٍ وغير مقسوم باتجاهين في يوتا، أين تُوضع مثلثات التحذير الثلاثة لمركبة تجارية متوقفة؟","options":["10 feet إلى الخلف، و100 feet إلى الخلف، و100 feet إلى أمام المركبة","10 feet و200 feet و300 feet، جميعها إلى الخلف","25 feet إلى الخلف، و50 feet إلى الخلف، و75 feet إلى الأمام","100 feet إلى الخلف، و100 feet إلى الأمام، وواحد عند المصد"],"explanation":"على طريق باتجاهين، ضع مثلثاً على بُعد حوالي 10 ft إلى الخلف، ومثلثاً على بُعد حوالي 100 ft إلى الخلف، ومثلثاً على بُعد حوالي 100 ft إلى الأمام (باتجاه حركة المرور في كلا الاتجاهين). المصدر: دليل CDL في يوتا (DLD)؛ 49 CFR 392.22."},"74":{"q":"ما هو الحد الأقصى لعرض المركبة الذي يمكن أن يسير على الطرق السريعة في يوتا دون تصريح حمولة كبيرة الحجم؟","options":["8 feet 6 inches","8 feet 0 inches","10 feet 0 inches","9 feet 6 inches"],"explanation":"الحد الأقصى القانوني للعرض في يوتا دون تصريح هو 8 feet 6 inches (102 inches)؛ وأي شيء أعرض يتطلب تصريح حمولة كبيرة الحجم من UDOT. المصدر: تصاريح الحجم/الوزن في وزارة النقل بيوتا؛ القانون الإداري في يوتا R909-2."},"75":{"q":"ما هو الحد الأقصى لارتفاع المركبة المسموح به على الطرق السريعة في يوتا قبل أن يُطلب تصريح حمولة كبيرة الحجم؟","options":["14 feet 0 inches","13 feet 6 inches","13 feet 0 inches","15 feet 0 inches"],"explanation":"تسمح يوتا بارتفاع يصل إلى 14 feet دون تصريح، مقاساً من سطح الطريق إلى أعلى الحمولة، وهو أعلى من حد 13'6\" الشائع في كثير من الولايات. المصدر: تصاريح الحجم/الوزن في وزارة النقل بيوتا؛ القانون الإداري في يوتا R909-2."},"76":{"q":"مركبة مركّبة في يوتا يبلغ وزنها الإجمالي 86,000 pounds وعرضها 9 feet. ما المطلوب قبل أن يُسمح لها بالعمل على الطرق السريعة في يوتا؟","options":["تصريح نقل خاص لحمولة كبيرة الحجم/زائدة الوزن من UDOT","لا شيء، لأنها أقل من الحد الأقصى الفيدرالي بين الولايات","فقط لافتة حمولة عريضة، دون تصريح","فقط تصديق HazMat على رخصة قيادة السائق"],"explanation":"الحمولات التي تتجاوز 80,000 lb إجمالياً أو أعرض من 8'6\" تتجاوز الحدود القانونية في يوتا وتتطلب تصريح حمولة كبيرة الحجم/زائدة الوزن من UDOT (لرحلة واحدة، أو نصف سنوي، أو سنوي). المصدر: تصاريح الحجم/الوزن في وزارة النقل بيوتا؛ القانون الإداري في يوتا R909-2."},"77":{"q":"على المنحدرات الجبلية الشديدة في يوتا مثل I-80 عبر وادي بارليز (Parleys Canyon)، ما الميزة المتوفرة تحديداً لإيقاف شاحنة ثقيلة تعطلت فراملها؟","options":["منحدر هروب للشاحنات الهاربة (runaway truck escape ramp)","ميزان وزن أثناء الحركة إلزامي","مسار قابل للعكس للمركبات عالية الإشغال (HOV)","كشك رسوم مرور للشاحنات فقط"],"explanation":"تحتوي المنحدرات في يوتا مثل I-80 في وادي بارليز على منحدر هروب للشاحنات الهاربة، بالإضافة إلى مناطق فحص فرامل معلنة عند الاقتراب من الهبوط، لذا ينبغي على السائقين الهبوط بترس منخفض واستخدام تقنية فرملة سليمة. المصدر: وزارة النقل في يوتا (Utah DOT)؛ دليل CDL في يوتا (قيادة الجبال)."},"78":{"q":"قبل منحدر طويل في جبال يوتا، ما هي الممارسة الأكثر أماناً للسائق التجاري للتحكم في السرعة؟","options":["اختيار ترس منخفض والاعتماد على الفرملة المحركية/المساعدة قبل بدء الهبوط","البقاء في ترس عالٍ والضغط المستمر على فرامل الخدمة حتى القاع","النقل إلى الوضع المحايد للانزلاق وتوفير الوقود في المنحدر","زيادة سرعة إضافية في القمة لتجاوز المرتفع التالي"],"explanation":"إرشادات القيادة الجبلية في يوتا هي اختيار ترس منخفض واستخدام الفرملة المحركية/المساعدة قبل الهبوط حتى لا تفرط فرامل الخدمة في السخونة؛ ومناطق فحص الفرامل على منحدرات مثل وادي بارليز تدعم ذلك. المصدر: دليل CDL في يوتا (DLD)، قيادة الجبال والفرملة في المنحدرات."},"79":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في يوتا؟","options":["قسم رخص القيادة في يوتا (Utah DLD)","إدارة المركبات الآلية في يوتا (DMV)","وزارة النقل في يوتا (UDOT)","الإدارة الفيدرالية لسلامة شركات النقل بالشاحنات (FMCSA)"],"explanation":"في يوتا، تُصدر رخص CDL من قبل قسم رخص القيادة في يوتا (DLD)، وهو جزء من وزارة السلامة العامة. وتتولى DMV تسجيل المركبات، وتتولى UDOT الطرق وتصاريح الحمولات كبيرة الحجم/زائدة الوزن، وFMCSA هي المنظِّم الفيدرالي. المصدر: صفحة معلومات CDL لقسم DLD في يوتا (dld.utah.gov/cdl-info)."},"80":{"q":"كم عدد الأسئلة في اختبار المعرفة العامة الكتابي لرخصة CDL في يوتا؟","options":["50 سؤالاً","30 سؤالاً","40 سؤالاً","100 سؤال"],"explanation":"يتكون اختبار المعرفة العامة الكتابي في يوتا من 50 سؤالاً من نوع الاختيار من متعدد، جميعها مبنية على دليل CDL. المصدر: صفحة اختبار CDL الكتابي للمعرفة لقسم DLD في يوتا (dld.utah.gov/cdl-written-test) ودليل CDL لعام 2025."},"81":{"q":"ما هي الدرجة الدنيا التي يجب أن تحققها لاجتياز اختبار معرفة CDL في يوتا؟","options":["80%","70%","75%","90%"],"explanation":"تتطلب يوتا 80% لاجتياز كل اختبار معرفة CDL (40 من 50 في اختبار المعرفة العامة). وهذا يطابق المعيار الفيدرالي في 49 CFR 383.135. المصدر: صفحة اختبار CDL الكتابي للمعرفة لقسم DLD في يوتا (dld.utah.gov/cdl-written-test)."},"82":{"q":"بأي لغة تُجرى اختبارات معرفة CDL في يوتا؟","options":["الإنجليزية فقط؛ ومواد الترجمة محظورة","الإنجليزية أو الإسبانية، حسب اختيار المتقدم","أي لغة بوجود مترجم معتمد","الإنجليزية، مع السماح بقواميس الترجمة"],"explanation":"تُجري يوتا جميع اختبارات معرفة CDL بالإنجليزية فقط، واستخدام مواد الترجمة محظور تماماً. الاختبارات أيضاً مغلقة الكتاب. المصدر: صفحة اختبار CDL الكتابي للمعرفة لقسم DLD في يوتا (dld.utah.gov/cdl-written-test)."},"83":{"q":"قبل إجراء أي اختبارات معرفة CDL كتابية في يوتا، ما الذي يجب أن يمتلكه المتقدم بالفعل؟","options":["شهادة فاحص طبي معتمدة سارية من DOT","اختبار مهارات الطريق مكتملاً","سنة واحدة من خبرة CDL من خارج الولاية","فحص الخلفية الخاص بالمواد الخطرة"],"explanation":"تتطلب يوتا من المتقدمين امتلاك شهادة فاحص طبي سارية (MEC) قبل إجراء اختبارات المعرفة الكتابية. يأتي اختبار المهارات لاحقاً، وينطبق فحص خلفية المواد الخطرة على ذلك التصديق فقط. المصدر: صفحة معلومات CDL لقسم DLD في يوتا (dld.utah.gov/cdl-info)."},"84":{"q":"ما هي المدة القصوى لصلاحية شهادة الفاحص الطبي من DOT لحامل رخصة CDL في يوتا؟","options":["حتى 24 شهراً","حتى 12 شهراً","حتى 36 شهراً","حتى 6 أشهر"],"explanation":"يكون الفحص الطبي من DOT (شهادة الفاحص الطبي) سارياً لمدة تصل إلى 24 شهراً في يوتا، مع أن الفاحص قد يصدرها لفترة أقصر عند متابعة حالة طبية. المصدر: صفحة معلومات CDL لقسم DLD في يوتا (dld.utah.gov/cdl-info)."},"85":{"q":"من المخوّل بإجراء الفحص الطبي من DOT لمتقدم رخصة CDL في يوتا؟","options":["فاحص طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","أي طبيب مرخّص يختاره المتقدم","موظف في DLD بمكتب الاختبار","فقط طبيب موظف لدى UDOT"],"explanation":"يجب أن يُجرى الفحص الطبي من DOT بواسطة فاحص طبي معتمد مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. ولا يكون أي طبيب مؤهلاً لذلك. المصدر: صفحة معلومات CDL لقسم DLD في يوتا والسجل الوطني لـ FMCSA."},"86":{"q":"من بين كم فئة للتصديق الذاتي يجب على متقدم رخصة CDL في يوتا أن يختار؟","options":["أربع فئات، باختيار فئة واحدة بالضبط","فئتان، باختيار فئة واحدة بالضبط","ثلاث فئات، باختيار فئة واحدة بالضبط","خمس فئات، باختيار فئة واحدة بالضبط"],"explanation":"تستخدم يوتا أربع فئات للتصديق الذاتي، ويجوز للسائق التصديق على فئة واحدة فقط. وهي: غير المعفاة بين الولايات، والمعفاة بين الولايات، وغير المعفاة داخل الولاية، والمعفاة داخل الولاية. المصدر: صفحة التصديق الذاتي لـ CDL لقسم DLD في يوتا (dld.utah.gov/cdl-self-certification)."},"87":{"q":"السائق في يوتا الذي يعمل فقط داخل يوتا ويجب أن يستوفي متطلبات تأهيل الولاية، تحت أي فئة يقوم بالتصديق الذاتي؟","options":["غير المعفاة داخل الولاية (Non-Excepted Intrastate)","غير المعفاة بين الولايات (Non-Excepted Interstate)","المعفاة بين الولايات (Excepted Interstate)","المعفاة الفيدرالية (Exempt Federal)"],"explanation":"تغطي فئة \"غير المعفاة داخل الولاية\" السائقين الذين يعملون فقط داخل يوتا ويجب أن يستوفوا معايير التأهيل الطبي للولاية (UCA 53-3-303.5)؛ وتحمل قيداً خاصاً بيوتا فقط. أما الفئات بين الولايات فتنطبق على التجارة على مستوى البلاد. المصدر: صفحة التصديق الذاتي لـ CDL لقسم DLD في يوتا (dld.utah.gov/cdl-self-certification)."},"88":{"q":"في أي من هذه الأوقات يجب على سائق CDL في يوتا أن يقدّم تصديقاً ذاتياً (وشهادة طبية سارية) إلى DLD؟","options":["عند إصدار أي رخصة CDL، وعند تغيّر حالة القيادة، وعند كل تجديد","مرة واحدة فقط، أول مرة تُصدر فيها رخصة CDL","فقط عند تغيير أصحاب العمل","فقط عند إضافة تصديق جديد"],"explanation":"كي تظل عملية التصديق الطبي مكتملة، يجب تقديم نموذج التصديق الذاتي إلى DLD عند إصدار أي رخصة CDL، وإذا تغيرت حالة القيادة، وعند كل تجديد لرخصة CDL. المصدر: صفحة معلومات CDL لقسم DLD في يوتا (dld.utah.gov/cdl-info)."},"89":{"q":"ما التدريب الذي يجب أن يكمله المتقدمون لأول مرة لرخصة CDL من الفئة A أو الفئة B في يوتا قبل الحصول على الرخصة؟","options":["تدريب السائقين المبتدئين (ELDT) من مزود مسجّل","تدريب مهني حكومي مدته 160 ساعة","دورة قيادة دفاعية معتمدة من UDOT","ستة أشهر من التدريب المشرف عليه من قبل صاحب العمل"],"explanation":"تتطلب القواعد الفيدرالية وقواعد يوتا من المتقدمين لأول مرة للفئة A/B (والمتقدمين لأول مرة لتصديق الحافلات المدرسية أو الركاب أو المواد الخطرة) إكمال تدريب السائقين المبتدئين (ELDT) من مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA قبل الحصول على رخصة CDL. المصدر: صفحة معلومات CDL لقسم DLD في يوتا (dld.utah.gov/cdl-info)."},"90":{"q":"يتكون ELDT من جزأين. ما الذي يجب أن يحصل عليه المتقدم قبل إمكانية إجراء جزء القيادة خلف المقود؟","options":["تصريح متعلّم تجاري (CLP)","درجة ناجحة في اختبار المهارات","تصديق المواد الخطرة (HazMat)","رخصة CDL كاملة دون قيود"],"explanation":"يحتوي ELDT على جزء نظري وجزء قيادة خلف المقود. يمكن إكمال الجزء النظري قبل التقديم، لكن يجب الحصول على تصريح متعلّم تجاري (CLP) قبل إجراء أي تدريب قيادة خلف المقود. المصدر: صفحة معلومات CDL لقسم DLD في يوتا (dld.utah.gov/cdl-info)."},"91":{"q":"بعد اجتياز اختبار المعرفة الكتابي في يوتا، ما مدة صلاحية تصريح المتعلّم التجاري (CLP)؟","options":["180 يوماً","90 يوماً","سنة واحدة","60 يوماً"],"explanation":"بمجرد اجتياز اختبار المعرفة العامة، تصدر يوتا تصريح متعلّم تجاري (CLP) ساري المفعول لمدة 180 يوماً (حوالي 6 أشهر). المصدر: صفحة اختبار CDL الكتابي للمعرفة لقسم DLD في يوتا (dld.utah.gov/cdl-written-test) ودليل CDL لعام 2025."},"92":{"q":"كم يجب أن يحتفظ المتقدم في يوتا بتصريح CLP قبل أن يُسمح له بإجراء اختبار مهارات CDL؟","options":["ما لا يقل عن 14 يوماً","ما لا يقل عن 30 يوماً","ما لا يقل عن 7 أيام","ما لا يقل عن 60 يوماً"],"explanation":"تتطلب يوتا من المتقدم الاحتفاظ بتصريح CLP لمدة لا تقل عن 14 يوماً (وإكمال ELDT) قبل إجراء اختبار المهارات، بما يطابق القاعدة الفيدرالية لـ CLP. المصدر: صفحة اختبار مهارات قيادة CDL لقسم DLD في يوتا (dld.utah.gov/cdl-driving-test)."},"93":{"q":"يتكون اختبار مهارات CDL في يوتا من أي ثلاثة أجزاء، بالترتيب؟","options":["فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية، والقيادة على الطريق","اختبار كتابي، ومهارات التحكم الأساسية، والقيادة على الطريق","فحص قبل الرحلة، واختبار الفرامل الهوائية، والقيادة على الطريق","مهارات التحكم الأساسية، والقيادة على الطريق، واختبار كتابي نهائي"],"explanation":"يتكون اختبار مهارات CDL في يوتا من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار مهارات التحكم الأساسية، واختبار القيادة على الطريق. الاختبارات الكتابية منفصلة عن اختبار المهارات. المصدر: صفحة اختبار مهارات قيادة CDL لقسم DLD في يوتا (dld.utah.gov/cdl-driving-test)."},"94":{"q":"ماذا يقيّم جزء الفحص قبل الرحلة من اختبار مهارات يوتا بشكل أساسي؟","options":["معرفتك بما إذا كانت المركبة آمنة للقيادة","قدرتك على رجوع المركبة إلى رصيف تحميل","زمن رد فعلك في حركة المرور الكثيفة","معرفتك الكتابية بقوانين المرور"],"explanation":"يختبر الفحص قبل الرحلة معرفة المتقدم بما إذا كانت المركبة آمنة للقيادة، ويغطي عناصر مثل المحرك والجرّار والمقطورة والأضواء والمقاييس ومعدات السلامة والفرامل الهوائية إن وُجدت. المصدر: صفحة اختبار مهارات قيادة CDL لقسم DLD في يوتا (dld.utah.gov/cdl-driving-test)."},"95":{"q":"لاجتياز جزء مهارات التحكم الأساسية من اختبار مهارات CDL في يوتا، كم نقطة خطأ يجوز أن تتراكم لديك؟","options":["ثماني نقاط خطأ أو أقل","اثنتا عشرة نقطة خطأ أو أقل","ثلاثون نقطة خطأ أو أقل","صفر نقطة خطأ"],"explanation":"يتطلب اختبار مهارات التحكم الأساسية في يوتا (التوقف للأمام، والرجوع في خط مستقيم، والتتبع الأمامي المنحرف، والرجوع المنحرف) ثماني نقاط خطأ أو أقل للنجاح. ويسمح اختبار الطريق بما يصل إلى 30. المصدر: صفحة اختبار مهارات قيادة CDL لقسم DLD في يوتا (dld.utah.gov/cdl-driving-test)."},"96":{"q":"لاجتياز جزء القيادة على الطريق من اختبار مهارات CDL في يوتا، كم نقطة خطأ يجوز أن تتراكم لديك؟","options":["ثلاثون نقطة خطأ أو أقل","ثماني نقاط خطأ أو أقل","خمس عشرة نقطة خطأ أو أقل","خمسون نقطة خطأ أو أقل"],"explanation":"يتطلب اختبار القيادة على الطريق في يوتا، الذي يتحقق مما إذا كانت لديك المهارات الدنيا للقيادة في معظم حالات المرور، 30 نقطة خطأ أو أقل للنجاح. أما اختبار مهارات التحكم الأساسية فيسمح بثماني نقاط فقط. المصدر: صفحة اختبار مهارات قيادة CDL لقسم DLD في يوتا (dld.utah.gov/cdl-driving-test)."},"97":{"q":"ما الذي تتطلب يوتا من المتقدم توفيره لإجراء اختبار مهارات (قيادة) CDL؟","options":["مركبتك الخاصة المسجلة والجاهزة للطريق من الفئة المناسبة","مركبة يوفرها قسم رخص القيادة","مركبة مستعارة من مجمع مركبات UDOT","فقط تصريح CLP ساري، لأن الولاية توفر المركبة"],"explanation":"تتطلب يوتا من المتقدم إحضار مركبته الخاصة المسجلة والجاهزة للطريق التي تمثل فئة رخصة CDL المطلوبة. ولا يوفّر DLD مركبات اختبار. المصدر: صفحة اختبار مهارات قيادة CDL لقسم DLD في يوتا (dld.utah.gov/cdl-driving-test)."},"98":{"q":"كم مرة يجب على حامل رخصة CDL في يوتا تجديد الرخصة وفق دورة التجديد المعيارية؟","options":["كل خمس سنوات","كل أربع سنوات","كل ثماني سنوات","كل سنتين"],"explanation":"تتبع رخص CDL في يوتا دورة تجديد مدتها خمس سنوات، ويتطلب كل تجديد طلباً محدثاً بالإضافة إلى تصديق ذاتي ووثائق طبية سارية. المصدر: معلومات تجديد CDL لقسم DLD في يوتا (dld.utah.gov) وقانون يوتا الموحد لرخصة القيادة التجارية، UCA 53-3-400 وما يليه."}}};
